window.QUESTIONS = [
// ============================================================
// CHAPTER 1: Fundamentals of Testing (Q1–Q180)
// ============================================================
{id:1,chapter:"Fundamentals of Testing",topic:"Why Testing is Necessary",difficulty:"easy",question:"Which of the following BEST describes why software testing is necessary?",options:["A. Testing guarantees that all defects are found","B. Testing reduces the risk of software failures in operation","C. Testing proves that the software is completely correct","D. Testing eliminates the need for debugging"],answer:1,explanation:"Testing reduces the risk of failures but cannot guarantee zero defects."},
{id:2,chapter:"Fundamentals of Testing",topic:"Why Testing is Necessary",difficulty:"easy",question:"A defect in software is BEST described as:",options:["A. A deviation from expected behavior observed at runtime","B. An imperfection or flaw in a work product","C. The inability of a system to perform a required function","D. A mistake made by a developer while coding"],answer:1,explanation:"A defect (fault) is an imperfection or flaw in a work product."},
{id:3,chapter:"Fundamentals of Testing",topic:"Why Testing is Necessary",difficulty:"easy",question:"What is a failure in software testing?",options:["A. A flaw introduced during development","B. An incorrect step or process in the code","C. An event in which a component does not perform a required function within specified limits","D. A human mistake that causes a defect"],answer:2,explanation:"A failure is the event of a component not performing its required function."},
{id:4,chapter:"Fundamentals of Testing",topic:"Why Testing is Necessary",difficulty:"medium",question:"Which of the following is an example of an error (mistake)?",options:["A. The software crashes when the user submits an empty form","B. A developer misunderstands a requirement and codes the wrong logic","C. A tester finds that login fails with correct credentials","D. The system produces incorrect output for a valid input"],answer:1,explanation:"An error is a human action (like misunderstanding a requirement) that leads to a defect."},
{id:5,chapter:"Fundamentals of Testing",topic:"Why Testing is Necessary",difficulty:"medium",question:"Which statement about the root cause of defects is CORRECT?",options:["A. All defects are caused by programmers making mistakes","B. Root causes are the fundamental reasons why defects are introduced","C. Root causes can only be identified after a failure occurs","D. Defect root cause analysis is only performed in safety-critical systems"],answer:1,explanation:"Root causes are the earliest actions or conditions that contributed to creating a defect."},
{id:6,chapter:"Fundamentals of Testing",topic:"Why Testing is Necessary",difficulty:"easy",question:"Which of the following is NOT typically considered a reason why testing is necessary?",options:["A. To evaluate work products and identify defects","B. To provide information to stakeholders for decision-making","C. To replace the need for good development practices","D. To build confidence in the quality of the software"],answer:2,explanation:"Testing is necessary alongside good development practices, not as a replacement."},
{id:7,chapter:"Fundamentals of Testing",topic:"Testing Objectives",difficulty:"easy",question:"Which of the following is a valid objective of testing?",options:["A. Proving that the software has no defects","B. Finding defects before they cause failures in production","C. Ensuring developers write better code in the future","D. Replacing the need for requirements documentation"],answer:1,explanation:"Finding defects before they cause failures in production is a core testing objective."},
{id:8,chapter:"Fundamentals of Testing",topic:"Testing Objectives",difficulty:"medium",question:"Which testing objective is associated with providing information to stakeholders about software quality?",options:["A. Defect prevention","B. Building confidence","C. Decision support","D. Compliance testing"],answer:2,explanation:"Testing provides information that supports decision-making by stakeholders."},
{id:9,chapter:"Fundamentals of Testing",topic:"Testing Objectives",difficulty:"medium",question:"During which phase is defect prevention MOST cost-effective as a testing objective?",options:["A. During system testing","B. During acceptance testing","C. During early development phases","D. During production"],answer:2,explanation:"Defect prevention is most cost-effective when applied early in the development lifecycle."},
{id:10,chapter:"Fundamentals of Testing",topic:"Testing Objectives",difficulty:"hard",question:"A test manager uses test results to advise the project board whether to release the software. This BEST illustrates which testing objective?",options:["A. Defect detection","B. Validating that requirements are met","C. Providing information for decision-making","D. Building stakeholder confidence"],answer:2,explanation:"Providing information for decision-making (go/no-go decisions) is a key testing objective."},
{id:11,chapter:"Fundamentals of Testing",topic:"Testing Principles",difficulty:"easy",question:"Which testing principle states that testing shows the presence of defects but cannot prove their absence?",options:["A. Exhaustive testing is impossible","B. Testing is context-dependent","C. Testing shows presence of defects, not their absence","D. Defects cluster together"],answer:2,explanation:"This principle reminds us that testing can find defects but cannot prove a system is defect-free."},
{id:12,chapter:"Fundamentals of Testing",topic:"Testing Principles",difficulty:"easy",question:"The principle 'exhaustive testing is impossible' means:",options:["A. Testers should test as many inputs as possible","B. It is impractical to test all combinations of inputs and preconditions","C. Testing should always be automated","D. All tests must be completed before release"],answer:1,explanation:"Testing all possible combinations of inputs and conditions is not feasible."},
{id:13,chapter:"Fundamentals of Testing",topic:"Testing Principles",difficulty:"medium",question:"Which testing principle explains why it is important to start testing activities early in the SDLC?",options:["A. Defects cluster together","B. Early testing saves time and money","C. Exhaustive testing is impossible","D. The pesticide paradox"],answer:1,explanation:"Early testing (shift-left) finds defects sooner when they are cheaper to fix."},
{id:14,chapter:"Fundamentals of Testing",topic:"Testing Principles",difficulty:"medium",question:"The 'pesticide paradox' in testing means:",options:["A. Testing becomes more effective over time if the same tests are repeated","B. Repeated execution of the same tests will eventually find fewer new defects","C. Test environments should be kept free from external influences","D. More test cases always lead to better quality"],answer:1,explanation:"If the same tests are run repeatedly, they stop finding new defects — tests must evolve."},
{id:15,chapter:"Fundamentals of Testing",topic:"Testing Principles",difficulty:"medium",question:"The principle 'defects cluster together' suggests that:",options:["A. All modules have the same defect density","B. A small number of modules typically contain the majority of defects","C. Defects always appear in pairs","D. Defects in one test level cannot affect other levels"],answer:1,explanation:"Defect clustering means most defects are found in a few modules (Pareto principle)."},
{id:16,chapter:"Fundamentals of Testing",topic:"Testing Principles",difficulty:"hard",question:"A team continually applies the same set of automated regression tests without reviewing or updating them. Which testing principle are they violating?",options:["A. Early testing saves time and money","B. Testing is context-dependent","C. Absence-of-errors fallacy","D. Pesticide paradox"],answer:3,explanation:"Repeating the same tests without updating them falls into the pesticide paradox — tests lose effectiveness."},
{id:17,chapter:"Fundamentals of Testing",topic:"Testing Principles",difficulty:"hard",question:"A software meets all specified requirements but users still find it unusable. Which testing principle does this illustrate?",options:["A. Exhaustive testing is impossible","B. Defects cluster together","C. Absence-of-errors fallacy","D. Testing is context-dependent"],answer:2,explanation:"The absence-of-errors fallacy: a system can pass all tests yet still not meet user needs."},
{id:18,chapter:"Fundamentals of Testing",topic:"Testing Principles",difficulty:"easy",question:"Which principle states that testing approaches must be adapted to the context of the project?",options:["A. Testing is context-dependent","B. Early testing saves time and money","C. Defects cluster together","D. Pesticide paradox"],answer:0,explanation:"Testing approaches must be adapted based on context — safety-critical vs. e-commerce differ greatly."},
{id:19,chapter:"Fundamentals of Testing",topic:"Test Activities",difficulty:"easy",question:"Which of the following is a test activity in the test process?",options:["A. Designing the software architecture","B. Test analysis and design","C. Writing functional requirements","D. Deploying the application to production"],answer:1,explanation:"Test analysis and design is a core test process activity."},
{id:20,chapter:"Fundamentals of Testing",topic:"Test Activities",difficulty:"medium",question:"During which test activity are test conditions identified?",options:["A. Test planning","B. Test analysis","C. Test implementation","D. Test closure"],answer:1,explanation:"Test conditions (what to test) are identified during test analysis."},
{id:21,chapter:"Fundamentals of Testing",topic:"Test Activities",difficulty:"medium",question:"Which activity involves creating test scripts and organizing test suites?",options:["A. Test analysis","B. Test design","C. Test implementation","D. Test execution"],answer:2,explanation:"Test implementation involves scripting, organizing, and preparing tests for execution."},
{id:22,chapter:"Fundamentals of Testing",topic:"Test Activities",difficulty:"medium",question:"Comparing actual results with expected results takes place during which test activity?",options:["A. Test design","B. Test analysis","C. Test execution","D. Test completion"],answer:2,explanation:"During test execution, testers compare actual vs. expected results and log outcomes."},
{id:23,chapter:"Fundamentals of Testing",topic:"Test Activities",difficulty:"hard",question:"Which test activity includes summarizing test results, archiving testware, and conducting retrospectives?",options:["A. Test monitoring and control","B. Test implementation","C. Test execution","D. Test completion"],answer:3,explanation:"Test completion activities include summarizing results, archiving testware, and retrospectives."},
{id:24,chapter:"Fundamentals of Testing",topic:"Test Activities",difficulty:"medium",question:"Identifying exit criteria and defining the test approach are part of which test activity?",options:["A. Test analysis","B. Test planning","C. Test design","D. Test execution"],answer:1,explanation:"Test planning defines the approach, entry/exit criteria, and scope."},
{id:25,chapter:"Fundamentals of Testing",topic:"Testware",difficulty:"easy",question:"Which of the following is an example of testware?",options:["A. Source code of the application under test","B. Test cases and test scripts","C. User requirements document","D. Project charter"],answer:1,explanation:"Testware includes test cases, test scripts, test data, and other artifacts created during testing."},
{id:26,chapter:"Fundamentals of Testing",topic:"Testware",difficulty:"medium",question:"Test data, test environment specifications, and test scripts are collectively referred to as:",options:["A. Test basis","B. Testware","C. Test oracle","D. Test harness"],answer:1,explanation:"Testware is the collective term for all artifacts produced during the test process."},
{id:27,chapter:"Fundamentals of Testing",topic:"Testware",difficulty:"medium",question:"A test oracle is BEST described as:",options:["A. An automated tool that generates test cases","B. A source that provides expected results for comparison during testing","C. A test environment that mirrors production","D. A senior tester who approves test plans"],answer:1,explanation:"A test oracle provides the expected outputs against which actual outputs are compared."},
{id:28,chapter:"Fundamentals of Testing",topic:"Testware",difficulty:"hard",question:"Which of the following is NOT typically considered testware?",options:["A. Defect reports","B. Test execution logs","C. The production deployment script","D. Test data"],answer:2,explanation:"Production deployment scripts are not testware; testware is produced during and for testing activities."},
{id:29,chapter:"Fundamentals of Testing",topic:"Test Roles",difficulty:"easy",question:"Which role is primarily responsible for defining the overall test strategy and ensuring testing resources are available?",options:["A. Tester","B. Test Manager","C. Developer","D. Business Analyst"],answer:1,explanation:"The Test Manager is responsible for test strategy, planning, and resource management."},
{id:30,chapter:"Fundamentals of Testing",topic:"Test Roles",difficulty:"medium",question:"Which of the following is a responsibility of a tester (as opposed to a test manager)?",options:["A. Defining the test strategy","B. Allocating testing resources","C. Designing and executing test cases","D. Managing stakeholder expectations"],answer:2,explanation:"Testers design, implement, and execute tests, and report results."},
{id:31,chapter:"Fundamentals of Testing",topic:"Test Roles",difficulty:"medium",question:"In an Agile team where there is no dedicated test manager role, which role typically takes on test planning responsibilities?",options:["A. Scrum Master","B. The whole team, often led by a senior tester","C. Product Owner exclusively","D. Release Manager"],answer:1,explanation:"In Agile contexts, the whole team shares testing responsibilities; a senior tester often leads planning."},
{id:32,chapter:"Fundamentals of Testing",topic:"Essential Skills",difficulty:"easy",question:"Which of the following is an essential skill for a tester?",options:["A. Ability to write production code exclusively","B. Critical thinking and attention to detail","C. Deep expertise in project management only","D. System administration skills"],answer:1,explanation:"Critical thinking and attention to detail are core tester skills for finding defects."},
{id:33,chapter:"Fundamentals of Testing",topic:"Essential Skills",difficulty:"medium",question:"Why is domain knowledge important for testers?",options:["A. It replaces the need for formal test techniques","B. It helps testers identify realistic test conditions and understand the system under test","C. It ensures testers can write production code","D. It reduces the cost of automation"],answer:1,explanation:"Domain knowledge helps testers create relevant test conditions and understand business context."},
{id:34,chapter:"Fundamentals of Testing",topic:"Essential Skills",difficulty:"hard",question:"A tester who identifies a potential defect but avoids reporting it to avoid conflict with the developer is exhibiting a lack of which essential quality?",options:["A. Technical knowledge","B. Analytical thinking","C. Communication and interpersonal skills","D. Domain knowledge"],answer:2,explanation:"Good communication and interpersonal skills are essential — testers must report findings diplomatically."},
{id:35,chapter:"Fundamentals of Testing",topic:"Why Testing is Necessary",difficulty:"hard",question:"Which of the following BEST illustrates the economic impact of defects discovered late in the development lifecycle?",options:["A. Defects found late have the same fix cost as those found early","B. The cost to fix a defect generally increases significantly the later it is discovered","C. Only defects in critical modules have economic impact","D. Automated testing eliminates the economic impact of late defects"],answer:1,explanation:"The cost of fixing defects grows substantially the later they are found — a core argument for early testing."},
{id:36,chapter:"Fundamentals of Testing",topic:"Testing Principles",difficulty:"extreme",question:"A project team argues that since their automated test suite passes, the system is ready for release. Which TWO testing principles does this statement violate?",options:["A. Testing shows presence of defects, not absence; and exhaustive testing is impossible","B. Early testing saves time and money; and pesticide paradox","C. Absence-of-errors fallacy; and testing is context-dependent","D. Defects cluster together; and early testing saves time and money"],answer:0,explanation:"Passing tests don't prove absence of defects, and exhaustive testing is impossible — both principles are violated."},
{id:37,chapter:"Fundamentals of Testing",topic:"Testing Objectives",difficulty:"hard",question:"Which of the following is LEAST likely to be a testing objective?",options:["A. Preventing defects from being introduced","B. Verifying all stated requirements are met","C. Ensuring developers follow coding standards","D. Building confidence in the system's quality"],answer:2,explanation:"Ensuring coding standards compliance is a code review/static analysis objective, not a primary testing objective."},
{id:38,chapter:"Fundamentals of Testing",topic:"Test Activities",difficulty:"hard",question:"A tester identifies that a major functionality area has not been covered by existing tests. This is BEST associated with which test activity?",options:["A. Test execution","B. Test monitoring and control","C. Test analysis","D. Test completion"],answer:2,explanation:"Identifying test coverage gaps is part of test analysis — determining what needs to be tested."},
{id:39,chapter:"Fundamentals of Testing",topic:"Why Testing is Necessary",difficulty:"extreme",question:"A system correctly implements all specified requirements but still causes harm to users. This scenario BEST illustrates which concept?",options:["A. Validation failure — the right product was not built","B. Verification failure — the product was not built right","C. A test oracle problem","D. Pesticide paradox"],answer:0,explanation:"Validation checks 'did we build the right product?' — meeting specs but failing user needs is a validation failure."},
{id:40,chapter:"Fundamentals of Testing",topic:"Testing Principles",difficulty:"extreme",question:"In a safety-critical avionics system, the team applies extensive formal testing. In a startup's web app, they apply lightweight exploratory testing. This BEST demonstrates which principle?",options:["A. Defects cluster together","B. Exhaustive testing is impossible","C. Testing is context-dependent","D. Pesticide paradox"],answer:2,explanation:"Testing approaches must be adapted to the context — safety-critical systems need much more rigor than typical web apps."},
{id:41,chapter:"Fundamentals of Testing",topic:"Testing Principles",difficulty:"medium",question:"Which of the following BEST describes the 'early testing saves time and money' principle?",options:["A. Testers should be hired at project inception","B. Defects found and fixed early cost less than those found later","C. Early test automation reduces overall project costs","D. Test planning should begin before coding starts to save time"],answer:1,explanation:"Finding and fixing defects early in the lifecycle is significantly cheaper than finding them late."},
{id:42,chapter:"Fundamentals of Testing",topic:"Testware",difficulty:"hard",question:"A test basis is BEST described as:",options:["A. The set of test cases used to verify requirements","B. The body of knowledge used to identify test conditions and design test cases","C. The baseline version of the software under test","D. A reference model for the test process"],answer:1,explanation:"The test basis is any artifact (requirements, design, code) from which test conditions can be derived."},
{id:43,chapter:"Fundamentals of Testing",topic:"Test Roles",difficulty:"hard",question:"Which of the following activities would a test manager perform but a tester would NOT typically perform?",options:["A. Writing test cases","B. Reporting defects","C. Negotiating testing scope with the project manager","D. Executing exploratory testing sessions"],answer:2,explanation:"Negotiating scope, resources, and timelines is a test management activity, not a typical tester task."},
{id:44,chapter:"Fundamentals of Testing",topic:"Testing Objectives",difficulty:"extreme",question:"A company releases software without testing to meet a deadline. Six months later, a critical defect causes a major outage costing $500,000. This BEST demonstrates which concept?",options:["A. The pesticide paradox in action","B. The economic cost of inadequate testing","C. An absence-of-errors fallacy","D. Defect clustering in production modules"],answer:1,explanation:"Skipping testing to meet deadlines often leads to far greater costs from production failures."},
{id:45,chapter:"Fundamentals of Testing",topic:"Why Testing is Necessary",difficulty:"medium",question:"Software testing can contribute to quality improvement by:",options:["A. Detecting defects and reporting them so they can be fixed","B. Writing defect-free code from the start","C. Replacing the need for code reviews","D. Automating all development tasks"],answer:0,explanation:"Testing improves quality by detecting defects that can then be fixed before causing failures."},
{id:46,chapter:"Fundamentals of Testing",topic:"Test Activities",difficulty:"extreme",question:"A tester is reviewing requirements for testability and flagging ambiguities before development starts. Which test activity is being performed?",options:["A. Test design","B. Test implementation","C. Test analysis","D. Test closure"],answer:2,explanation:"Reviewing requirements for testability and identifying ambiguities is a test analysis activity."},
{id:47,chapter:"Fundamentals of Testing",topic:"Essential Skills",difficulty:"medium",question:"Which of the following BEST describes 'systematic approach' as a tester skill?",options:["A. Using only formal test techniques","B. Following a structured, methodical process for testing activities","C. Always automating repetitive tests","D. Documenting every test step in detail"],answer:1,explanation:"A systematic approach means following structured, methodical processes rather than ad hoc testing."},
{id:48,chapter:"Fundamentals of Testing",topic:"Essential Skills",difficulty:"hard",question:"A tester consistently finds defects that other team members missed. This BEST demonstrates which tester quality?",options:["A. Automation skills","B. Curiosity and attention to detail","C. Project management skills","D. Strong programming ability"],answer:1,explanation:"Curiosity and attention to detail are key qualities that help testers find defects others miss."},
{id:49,chapter:"Fundamentals of Testing",topic:"Testing Objectives",difficulty:"medium",question:"Verifying that a system meets its specified requirements is an example of which testing objective?",options:["A. Validation","B. Verification","C. Defect prevention","D. Decision support"],answer:1,explanation:"Verification checks that the product meets its specified requirements."},
{id:50,chapter:"Fundamentals of Testing",topic:"Testing Objectives",difficulty:"medium",question:"Confirming that a system meets the actual needs of users is an example of which testing objective?",options:["A. Verification","B. Defect prevention","C. Validation","D. Static testing"],answer:2,explanation:"Validation checks that the right product was built — that it meets actual user needs."},
{id:51,chapter:"Fundamentals of Testing",topic:"Why Testing is Necessary",difficulty:"medium",question:"Which factor is MOST likely to increase the likelihood of a failure in production?",options:["A. Using experienced developers","B. Defects remaining in the software that were not detected during testing","C. Having a well-documented test plan","D. Performing regression testing after changes"],answer:1,explanation:"Undetected defects in production software are the primary source of failures."},
{id:52,chapter:"Fundamentals of Testing",topic:"Testing Principles",difficulty:"hard",question:"A team using regression testing notices their test suite is not finding new defects in recently changed code. Which principle BEST explains this situation?",options:["A. Defects cluster together","B. Testing shows presence of defects","C. Pesticide paradox","D. Context-dependent testing"],answer:2,explanation:"The pesticide paradox: unchanged tests become less effective over time as defects evolve."},
{id:53,chapter:"Fundamentals of Testing",topic:"Testware",difficulty:"medium",question:"Which of the following BEST describes a test condition?",options:["A. A specific set of inputs and expected outputs","B. An aspect of the test object that can be verified by one or more test cases","C. A constraint on the test environment","D. A pass/fail criterion for a test"],answer:1,explanation:"A test condition is an aspect of the software that can be verified by test cases."},
{id:54,chapter:"Fundamentals of Testing",topic:"Testware",difficulty:"hard",question:"Which of the following is an example of a test basis document?",options:["A. A defect report","B. A test execution log","C. A software architecture specification","D. A test completion report"],answer:2,explanation:"Architecture specs, requirements, and design documents are test basis artifacts from which tests are derived."},
{id:55,chapter:"Fundamentals of Testing",topic:"Test Activities",difficulty:"extreme",question:"During test monitoring and control, a test manager observes that 30% of test cases remain unexecuted with only 2 days left. Which action is MOST appropriate?",options:["A. Extend the project deadline immediately","B. Stop all testing and declare the current build ready","C. Assess risks, reprioritize remaining tests, and report to stakeholders","D. Automate all remaining tests overnight"],answer:2,explanation:"Test monitoring and control involves assessing the situation, reprioritizing, and communicating status to stakeholders."},
{id:56,chapter:"Fundamentals of Testing",topic:"Test Roles",difficulty:"medium",question:"Who is PRIMARILY responsible for the quality of the software product?",options:["A. The test manager","B. The development team","C. The entire project team and stakeholders","D. The quality assurance department"],answer:2,explanation:"Quality is a shared responsibility across the entire project team and organization."},
{id:57,chapter:"Fundamentals of Testing",topic:"Why Testing is Necessary",difficulty:"hard",question:"Which of the following statements about testing and debugging is CORRECT?",options:["A. Testing and debugging are the same activity","B. Testing finds failures; debugging finds, analyzes, and fixes defects","C. Debugging eliminates the need for testing","D. Testing always precedes debugging in the development lifecycle"],answer:1,explanation:"Testing identifies failures; debugging is the process of finding the defect and fixing it."},
{id:58,chapter:"Fundamentals of Testing",topic:"Testing Objectives",difficulty:"hard",question:"During a compliance audit, the auditor asks for evidence that the software meets regulatory requirements. Which testing objective is MOST relevant?",options:["A. Defect prevention","B. Building confidence","C. Validation","D. Meeting contractual or regulatory requirements"],answer:3,explanation:"One key testing objective is demonstrating compliance with contractual, legal, or regulatory requirements."},
{id:59,chapter:"Fundamentals of Testing",topic:"Essential Skills",difficulty:"extreme",question:"A tester working on a banking application needs to understand transaction processing, clearing cycles, and regulatory constraints to write effective tests. This illustrates the importance of:",options:["A. Test automation skills","B. Domain knowledge","C. Programming skills","D. Project management skills"],answer:1,explanation:"Domain knowledge helps testers design realistic, effective tests that reflect actual business scenarios."},
{id:60,chapter:"Fundamentals of Testing",topic:"Testing Principles",difficulty:"extreme",question:"Which combination of testing principles would BEST guide a team performing risk-based testing on a large enterprise application?",options:["A. Exhaustive testing is impossible + defects cluster together","B. Pesticide paradox + absence-of-errors fallacy","C. Early testing + context-dependent testing","D. Testing shows presence of defects + early testing saves time"],answer:0,explanation:"Risk-based testing acknowledges exhaustive testing is impossible and prioritizes areas with defect clustering."},
{id:61,chapter:"Fundamentals of Testing",topic:"Test Activities",difficulty:"medium",question:"Which test activity produces test cases, test procedures, and test scripts?",options:["A. Test planning","B. Test analysis","C. Test design","D. Test implementation"],answer:3,explanation:"Test implementation creates executable test scripts and procedures from the test cases."},
{id:62,chapter:"Fundamentals of Testing",topic:"Test Activities",difficulty:"hard",question:"A tester documents a defect found during execution and reports it to the development team. This activity takes place during:",options:["A. Test design","B. Test implementation","C. Test execution","D. Test closure"],answer:2,explanation:"Logging defects and reporting them to developers happens during test execution."},
{id:63,chapter:"Fundamentals of Testing",topic:"Testing Objectives",difficulty:"easy",question:"Which of the following is an example of building confidence through testing?",options:["A. Finding and reporting a critical defect","B. Demonstrating that the software works correctly under normal conditions","C. Reducing the project timeline","D. Increasing test coverage to 100%"],answer:1,explanation:"Building confidence means demonstrating that the software works as expected under normal operating conditions."},
{id:64,chapter:"Fundamentals of Testing",topic:"Test Roles",difficulty:"easy",question:"Which role is responsible for reporting test results to stakeholders?",options:["A. Developer","B. Business Analyst","C. Test Manager / Tester","D. Release Manager"],answer:2,explanation:"Test managers and testers are responsible for communicating test results and quality status to stakeholders."},
{id:65,chapter:"Fundamentals of Testing",topic:"Why Testing is Necessary",difficulty:"extreme",question:"A project uses continuous integration with automated unit tests passing at 95% coverage. The team decides no further system testing is needed. Which of the following BEST explains the risk in this decision?",options:["A. Unit tests cover all integration scenarios","B. High unit test coverage does not guarantee system-level behavior is correct","C. 95% coverage means the remaining 5% is acceptable","D. Automated tests never miss defects"],answer:1,explanation:"Unit tests verify individual components; system-level behaviors, integrations, and emergent defects still require system testing."},
{id:66,chapter:"Fundamentals of Testing",topic:"Testware",difficulty:"extreme",question:"Which of the following testware artifacts would be MOST useful in a future project testing a similar system?",options:["A. Defect reports from the current project","B. Test cases, test data, and test scripts","C. The test execution log","D. The test completion report"],answer:1,explanation:"Test cases, test data, and scripts can be reused or adapted for similar systems in future projects."},
{id:67,chapter:"Fundamentals of Testing",topic:"Testing Objectives",difficulty:"extreme",question:"A team wants to ensure their new payment module is safe to deploy alongside existing modules without breaking existing functionality. Which testing objective is PRIMARY here?",options:["A. Validation","B. Compliance verification","C. Regression assurance / defect detection","D. Exploratory coverage"],answer:2,explanation:"Regression testing ensures new changes don't break existing functionality — a primary objective here."},
{id:68,chapter:"Fundamentals of Testing",topic:"Test Activities",difficulty:"medium",question:"Entry and exit criteria are MOST closely associated with which test activity?",options:["A. Test design","B. Test planning","C. Test execution","D. Test analysis"],answer:1,explanation:"Entry and exit criteria are defined during test planning."},
{id:69,chapter:"Fundamentals of Testing",topic:"Essential Skills",difficulty:"easy",question:"Why is communication skill important for testers?",options:["A. To write more automated tests","B. To effectively report defects and collaborate with developers and stakeholders","C. To manage test data","D. To perform code reviews"],answer:1,explanation:"Testers must communicate clearly — both in defect reports and when collaborating with developers and stakeholders."},
{id:70,chapter:"Fundamentals of Testing",topic:"Why Testing is Necessary",difficulty:"medium",question:"Which of the following statements about software quality is CORRECT?",options:["A. Quality can only be measured by the number of defects found","B. Quality is the degree to which a system satisfies stated and implied needs","C. Quality is solely the responsibility of the QA department","D. A system that passes all tests is a high-quality system"],answer:1,explanation:"Quality is defined as the degree to which a product or service meets stated and implied needs of stakeholders."},
{id:71,chapter:"Fundamentals of Testing",topic:"Testing Principles",difficulty:"medium",question:"Which of the following is an implication of the principle 'testing shows presence of defects'?",options:["A. If all tests pass, the software is defect-free","B. Passing all tests means the software is ready for release without further review","C. Passing all tests reduces the probability of remaining defects but cannot guarantee none exist","D. Testing is unnecessary once unit tests all pass"],answer:2,explanation:"Passing all tests reduces risk but cannot prove the system is completely defect-free."},
{id:72,chapter:"Fundamentals of Testing",topic:"Test Activities",difficulty:"hard",question:"Which of the following BEST describes the difference between test design and test implementation?",options:["A. Test design creates test conditions; test implementation creates the test basis","B. Test design defines what to test; test implementation creates how to execute the tests","C. Test design and test implementation are the same activity","D. Test implementation defines exit criteria; test design executes tests"],answer:1,explanation:"Test design identifies what to test and how; test implementation creates the actual test scripts for execution."},
{id:73,chapter:"Fundamentals of Testing",topic:"Testware",difficulty:"medium",question:"Which of the following would be part of the testware produced during test planning?",options:["A. Test scripts","B. Test data","C. Test plan document","D. Defect reports"],answer:2,explanation:"The test plan document is a key testware artifact produced during test planning."},
{id:74,chapter:"Fundamentals of Testing",topic:"Test Roles",difficulty:"extreme",question:"In a DevOps team, there are no dedicated testers. Developers write and run all tests. Which statement about this arrangement is MOST accurate?",options:["A. This is always a poor practice since testing requires specialized skills","B. This can work effectively if developers have testing knowledge and a quality mindset","C. Testing by developers means no independent testing perspective is needed","D. This arrangement eliminates the need for test planning"],answer:1,explanation:"In DevOps, whole-team quality is accepted, but testing skills and mindset are still required from those performing testing."},
{id:75,chapter:"Fundamentals of Testing",topic:"Why Testing is Necessary",difficulty:"hard",question:"Which of the following BEST illustrates the difference between a defect and a failure?",options:["A. A defect occurs at runtime; a failure is introduced during coding","B. A defect is a flaw in the work product; a failure is the observable incorrect behavior when the defect is executed","C. A failure always leads to a defect being created","D. Defects and failures are the same concept"],answer:1,explanation:"A defect is the underlying flaw; a failure is the observable incorrect behavior when the defect manifests during execution."},
{id:76,chapter:"Fundamentals of Testing",topic:"Testing Principles",difficulty:"medium",question:"Which of the following is NOT one of the seven testing principles in ISTQB Foundation Level?",options:["A. Testing is context-dependent","B. Early testing saves time and money","C. Test automation eliminates defects","D. Exhaustive testing is impossible"],answer:2,explanation:"Test automation eliminating defects is not one of the seven ISTQB testing principles."},
{id:77,chapter:"Fundamentals of Testing",topic:"Test Activities",difficulty:"easy",question:"Which of the following is part of test completion activities?",options:["A. Writing test cases","B. Finalizing the test report and archiving testware","C. Identifying test conditions","D. Executing test cases"],answer:1,explanation:"Test completion includes writing the final report, archiving testware, and conducting retrospectives."},
{id:78,chapter:"Fundamentals of Testing",topic:"Testing Objectives",difficulty:"hard",question:"Testing can contribute to defect prevention by:",options:["A. Detecting defects before they escape to production","B. Providing feedback to improve development and testing processes","C. Ensuring all code paths are executed at least once","D. Running regression tests after each change"],answer:1,explanation:"Feedback from testing helps teams improve processes, thereby preventing defects from being introduced."},
{id:79,chapter:"Fundamentals of Testing",topic:"Essential Skills",difficulty:"medium",question:"A tester is asked to test a feature they believe is poorly designed. They should:",options:["A. Refuse to test it and escalate to management","B. Test it objectively and report findings including design concerns","C. Design the feature themselves before testing","D. Skip testing until the design is fixed"],answer:1,explanation:"Testers should test objectively and report all findings, including design issues, diplomatically."},
{id:80,chapter:"Fundamentals of Testing",topic:"Why Testing is Necessary",difficulty:"easy",question:"Which of the following BEST describes verification in testing?",options:["A. Checking that the system meets the actual needs of the end users","B. Checking that the system conforms to its specifications and requirements","C. Confirming that the test environment is set up correctly","D. Ensuring test cases are correctly written"],answer:1,explanation:"Verification is the process of confirming that the work product meets specified requirements."},
{id:81,chapter:"Fundamentals of Testing",topic:"Testware",difficulty:"easy",question:"Which of the following is a characteristic of a good test case?",options:["A. It is vague so it can be applied to many situations","B. It has clear expected results and is repeatable","C. It tests as many features as possible in a single step","D. It is written after execution has started"],answer:1,explanation:"Good test cases have clear expected results and can be repeated reliably."},
{id:82,chapter:"Fundamentals of Testing",topic:"Test Roles",difficulty:"medium",question:"A tester who raises a concern about a feature's design during a review meeting is performing:",options:["A. Defect prevention through early feedback","B. Static testing of the code","C. Dynamic testing of the feature","D. Acceptance testing"],answer:0,explanation:"Providing feedback on design issues early prevents defects from being built in — a defect prevention activity."},
{id:83,chapter:"Fundamentals of Testing",topic:"Testing Principles",difficulty:"hard",question:"Which testing principle argues against spending equal testing effort across all modules?",options:["A. Exhaustive testing is impossible","B. Defects cluster together","C. Testing is context-dependent","D. Early testing saves time and money"],answer:1,explanation:"Because defects cluster in certain modules, effort should be focused there rather than spread equally."},
{id:84,chapter:"Fundamentals of Testing",topic:"Why Testing is Necessary",difficulty:"medium",question:"Which of the following scenarios represents a failure caused by an environmental factor rather than a code defect?",options:["A. A calculation module returns a wrong result due to a logic error","B. An application crashes because a database server is out of memory","C. A user interface displays the wrong currency symbol","D. A validation rule accepts invalid data"],answer:1,explanation:"Environmental factors like server resources can cause failures that are not due to code defects."},
{id:85,chapter:"Fundamentals of Testing",topic:"Test Activities",difficulty:"medium",question:"Test monitoring is BEST described as:",options:["A. Executing test cases against the software","B. Checking ongoing test activities against the test plan and reporting status","C. Reviewing the test basis for testability","D. Archiving test results at project end"],answer:1,explanation:"Test monitoring tracks ongoing testing against the plan and reports status to stakeholders."},
{id:86,chapter:"Fundamentals of Testing",topic:"Testing Objectives",difficulty:"easy",question:"Which of the following BEST describes a quality characteristic that testing might verify?",options:["A. The experience level of the development team","B. Performance, reliability, and security of the software","C. The number of test cases written","D. The size of the project team"],answer:1,explanation:"Testing verifies quality characteristics like performance, reliability, usability, and security."},
{id:87,chapter:"Fundamentals of Testing",topic:"Test Activities",difficulty:"hard",question:"Which test activity involves establishing traceability between test cases and requirements?",options:["A. Test planning","B. Test analysis","C. Test design","D. Test implementation"],answer:1,explanation:"Establishing traceability between requirements and test conditions/cases is part of test analysis."},
{id:88,chapter:"Fundamentals of Testing",topic:"Essential Skills",difficulty:"hard",question:"A tester with strong analytical skills would MOST likely excel at which activity?",options:["A. Writing automated test scripts","B. Analyzing complex requirements and identifying test conditions","C. Setting up test environments","D. Managing test schedules"],answer:1,explanation:"Analytical skills are most valuable for breaking down complex requirements and deriving test conditions."},
{id:89,chapter:"Fundamentals of Testing",topic:"Why Testing is Necessary",difficulty:"hard",question:"Which of the following statements about errors, defects, and failures is CORRECT?",options:["A. Every defect will eventually lead to a failure","B. Not every defect will cause a failure — some may never be executed","C. Errors always lead to defects which always lead to failures","D. Failures are always caused by errors made by testers"],answer:1,explanation:"A defect may never cause a failure if the code path containing it is never executed."},
{id:90,chapter:"Fundamentals of Testing",topic:"Testing Principles",difficulty:"easy",question:"How many testing principles are defined in the ISTQB Foundation Level syllabus?",options:["A. Five","B. Six","C. Seven","D. Eight"],answer:2,explanation:"ISTQB Foundation Level defines seven testing principles."},
{id:91,chapter:"Fundamentals of Testing",topic:"Test Activities",difficulty:"easy",question:"Which test activity immediately follows test planning?",options:["A. Test closure","B. Test analysis","C. Test execution","D. Test implementation"],answer:1,explanation:"After test planning, the team proceeds to test analysis to identify what needs to be tested."},
{id:92,chapter:"Fundamentals of Testing",topic:"Testware",difficulty:"hard",question:"Which of the following BEST describes the relationship between test basis and test conditions?",options:["A. Test conditions are derived from the test basis","B. The test basis is derived from test conditions","C. They are independent and unrelated artifacts","D. Test conditions replace the test basis once testing begins"],answer:0,explanation:"Test conditions are identified by analyzing the test basis (requirements, design docs, etc.)."},
{id:93,chapter:"Fundamentals of Testing",topic:"Test Roles",difficulty:"hard",question:"In a large organization, which activity would a test architect perform that a test manager would NOT typically handle?",options:["A. Managing the test team","B. Designing the overall test approach and test architecture","C. Reporting test status to stakeholders","D. Approving the test plan"],answer:1,explanation:"A test architect designs the technical test approach, frameworks, and architecture."},
{id:94,chapter:"Fundamentals of Testing",topic:"Why Testing is Necessary",difficulty:"extreme",question:"A software product passes all functional tests but users report it is too slow to use in production. This MOST likely indicates:",options:["A. The functional tests were poorly designed","B. Non-functional testing (performance) was not adequately performed","C. The test oracle was incorrect","D. A pesticide paradox occurred during regression testing"],answer:1,explanation:"Performance is a non-functional quality characteristic — inadequate performance testing led to production issues."},
{id:95,chapter:"Fundamentals of Testing",topic:"Testing Objectives",difficulty:"extreme",question:"A team performs testing specifically to provide evidence that the software complies with GDPR regulations. This BEST represents which testing objective?",options:["A. Building confidence","B. Defect detection","C. Meeting regulatory requirements","D. Validation"],answer:2,explanation:"Testing for regulatory compliance (GDPR, ISO, etc.) is a distinct testing objective."},
{id:96,chapter:"Fundamentals of Testing",topic:"Test Activities",difficulty:"medium",question:"Which of the following is an example of a test closure activity?",options:["A. Identifying test conditions from requirements","B. Logging defects found during execution","C. Conducting a lessons-learned retrospective","D. Setting up the test environment"],answer:2,explanation:"Retrospectives and lessons-learned sessions are classic test closure activities."},
{id:97,chapter:"Fundamentals of Testing",topic:"Essential Skills",difficulty:"extreme",question:"A tester is reviewing a high-level design document and notices a design decision that will make the system difficult to test. They should MOST appropriately:",options:["A. Wait until system testing to report the issue","B. Raise the concern immediately so the design can be reconsidered","C. Design workaround tests to handle the untestable feature","D. Only report it if a failure occurs during execution"],answer:1,explanation:"Raising testability concerns early prevents costly rework — this is proactive defect prevention."},
{id:98,chapter:"Fundamentals of Testing",topic:"Testing Principles",difficulty:"medium",question:"The principle 'absence-of-errors fallacy' implies that:",options:["A. A system with no defects reported is always ready for release","B. Finding and fixing defects is worthless if the system does not meet user needs","C. Error-free code can always be delivered with enough testing","D. Test automation eliminates the possibility of errors"],answer:1,explanation:"Even a defect-free system can fail to satisfy users if it doesn't meet their actual needs."},
{id:99,chapter:"Fundamentals of Testing",topic:"Test Roles",difficulty:"easy",question:"Who is PRIMARILY responsible for creating and executing test cases?",options:["A. Test Manager","B. Tester","C. Developer","D. Business Analyst"],answer:1,explanation:"Creating and executing test cases is primarily the responsibility of testers."},
{id:100,chapter:"Fundamentals of Testing",topic:"Why Testing is Necessary",difficulty:"medium",question:"Which of the following BEST explains why complete testing is impossible?",options:["A. Testing tools are not advanced enough","B. The number of possible inputs, paths, and conditions is effectively infinite for any real system","C. Testers do not have enough time to learn the system","D. Requirements are always incomplete"],answer:1,explanation:"The infinite combination of inputs, conditions, and execution paths makes exhaustive testing impossible."},
// ============================================================
// CHAPTER 2: Testing Throughout the SDLC (Q101–Q250)
// ============================================================
{id:101,chapter:"Testing Throughout the SDLC",topic:"Testing in SDLC",difficulty:"easy",question:"Which of the following BEST describes the V-model in software development?",options:["A. A model where testing only occurs after all development is complete","B. A model where each development phase has a corresponding test level","C. A model that focuses exclusively on automated testing","D. A model used only for safety-critical systems"],answer:1,explanation:"The V-model pairs each development phase with a corresponding test level (unit, integration, system, acceptance)."},
{id:102,chapter:"Testing Throughout the SDLC",topic:"Testing in SDLC",difficulty:"easy",question:"In the V-model, which development phase corresponds to acceptance testing?",options:["A. Architecture design","B. Detailed design","C. Requirements","D. Coding"],answer:2,explanation:"Acceptance testing corresponds to the requirements phase — verifying the system meets business requirements."},
{id:103,chapter:"Testing Throughout the SDLC",topic:"Testing in SDLC",difficulty:"medium",question:"Which of the following BEST describes how testing fits into an Agile development model?",options:["A. Testing is a separate phase at the end of each sprint","B. Testing is integrated throughout each sprint alongside development","C. Testing only occurs during the final sprint","D. Testing replaces the need for retrospectives in Agile"],answer:1,explanation:"In Agile, testing is integrated into each iteration/sprint — not deferred to the end."},
{id:104,chapter:"Testing Throughout the SDLC",topic:"Testing in SDLC",difficulty:"medium",question:"What does 'shift-left' testing mean?",options:["A. Moving test execution to earlier phases of development","B. Reducing the number of testers on a project","C. Replacing manual testing with automation","D. Moving testing activities to offshore teams"],answer:0,explanation:"Shift-left means starting testing activities earlier in the development lifecycle to find defects sooner."},
{id:105,chapter:"Testing Throughout the SDLC",topic:"Testing in SDLC",difficulty:"medium",question:"In a sequential (waterfall) SDLC, testing is MOST often:",options:["A. Performed throughout all phases","B. Performed only in a distinct phase after development","C. Replaced by static analysis","D. Focused entirely on acceptance testing"],answer:1,explanation:"In traditional waterfall, testing is typically a distinct phase following development."},
{id:106,chapter:"Testing Throughout the SDLC",topic:"Testing in SDLC",difficulty:"hard",question:"Which of the following is a characteristic of good testing in ANY SDLC model?",options:["A. Every test level has a distinct phase separate from development","B. Testing activities begin as early as possible in the lifecycle","C. Unit testing is always performed by dedicated testers","D. Acceptance testing is always the final activity"],answer:1,explanation:"Regardless of the SDLC model, starting testing activities as early as possible is a good practice."},
{id:107,chapter:"Testing Throughout the SDLC",topic:"Testing in SDLC",difficulty:"hard",question:"In a DevOps model, which of the following BEST describes the role of automated testing?",options:["A. Automated testing replaces all manual testing","B. Automated testing enables fast feedback loops in CI/CD pipelines","C. Automated testing is only relevant for unit testing","D. Automated testing is optional in DevOps"],answer:1,explanation:"Automated testing in DevOps provides rapid feedback through CI/CD pipelines, enabling fast delivery."},
{id:108,chapter:"Testing Throughout the SDLC",topic:"Test Levels",difficulty:"easy",question:"Which test level focuses on verifying the interactions between integrated components?",options:["A. Unit testing","B. Integration testing","C. System testing","D. Acceptance testing"],answer:1,explanation:"Integration testing verifies that components work correctly when combined/integrated."},
{id:109,chapter:"Testing Throughout the SDLC",topic:"Test Levels",difficulty:"easy",question:"Which test level is PRIMARILY performed by developers using white-box techniques?",options:["A. System testing","B. Acceptance testing","C. Component/Unit testing","D. Integration testing"],answer:2,explanation:"Component (unit) testing is primarily performed by developers, often using white-box techniques."},
{id:110,chapter:"Testing Throughout the SDLC",topic:"Test Levels",difficulty:"easy",question:"Which test level focuses on validating the complete, integrated system against business requirements?",options:["A. Unit testing","B. Integration testing","C. System testing","D. Regression testing"],answer:2,explanation:"System testing validates the complete, integrated system against specified requirements."},
{id:111,chapter:"Testing Throughout the SDLC",topic:"Test Levels",difficulty:"easy",question:"Which test level is performed to determine whether the system is acceptable for delivery to customers?",options:["A. System testing","B. Regression testing","C. Integration testing","D. Acceptance testing"],answer:3,explanation:"Acceptance testing determines whether the system is acceptable for delivery/deployment."},
{id:112,chapter:"Testing Throughout the SDLC",topic:"Test Levels",difficulty:"medium",question:"API testing is MOST closely associated with which test level?",options:["A. Component testing","B. Component integration testing","C. System testing","D. Acceptance testing"],answer:1,explanation:"API testing verifies the interactions between components through their interfaces — component integration testing."},
{id:113,chapter:"Testing Throughout the SDLC",topic:"Test Levels",difficulty:"medium",question:"User Acceptance Testing (UAT) is BEST described as:",options:["A. Testing performed by the test team to verify system requirements","B. Testing performed by intended users to validate the system against their needs","C. Automated testing of user interface components","D. Testing performed to verify usability requirements"],answer:1,explanation:"UAT is performed by end users to validate the system meets their actual business needs."},
{id:114,chapter:"Testing Throughout the SDLC",topic:"Test Levels",difficulty:"medium",question:"Which of the following is an example of system integration testing?",options:["A. Testing a single database stored procedure","B. Testing all features of a web application","C. Testing the interaction between a payment system and a bank's API","D. Testing a new feature in a user story"],answer:2,explanation:"System integration testing verifies interactions between the system and external systems/components."},
{id:115,chapter:"Testing Throughout the SDLC",topic:"Test Levels",difficulty:"hard",question:"Which test level would MOST likely detect defects in database triggers that are only activated when multiple services interact?",options:["A. Unit testing","B. Component integration testing","C. System testing","D. Acceptance testing"],answer:1,explanation:"Database triggers activated by multi-service interactions are best detected at component integration testing."},
{id:116,chapter:"Testing Throughout the SDLC",topic:"Test Levels",difficulty:"hard",question:"Alpha testing is BEST described as:",options:["A. Testing performed by developers before code review","B. Testing performed by potential customers at the developer's site","C. Testing performed by the internal test team before release","D. Automated regression testing after each build"],answer:1,explanation:"Alpha testing is done by potential customers/users at the developer's site before public release."},
{id:117,chapter:"Testing Throughout the SDLC",topic:"Test Levels",difficulty:"hard",question:"Beta testing is BEST described as:",options:["A. Internal testing by the development team","B. Testing by potential customers in their own environment before general release","C. Automated performance testing","D. Regression testing after a major release"],answer:1,explanation:"Beta testing is performed by potential customers in their own environment before general availability."},
{id:118,chapter:"Testing Throughout the SDLC",topic:"Test Levels",difficulty:"medium",question:"Which of the following BEST describes the test basis for unit testing?",options:["A. User stories and acceptance criteria","B. Source code, unit design, data model","C. System requirements specification","D. Business process documentation"],answer:1,explanation:"Unit testing is based on source code, unit design specifications, and data models."},
{id:119,chapter:"Testing Throughout the SDLC",topic:"Test Levels",difficulty:"medium",question:"Which of the following BEST describes the test basis for acceptance testing?",options:["A. Source code and unit design","B. Component design specifications","C. Business requirements, regulations, user needs","D. Architecture design"],answer:2,explanation:"Acceptance testing is based on business requirements, regulations, user stories, and end-user needs."},
{id:120,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"easy",question:"Functional testing focuses on:",options:["A. How the system performs under load","B. What the system does — its functions and features","C. How the system is structured internally","D. How easy the system is to use"],answer:1,explanation:"Functional testing evaluates what the system does — its functions, features, and behaviors."},
{id:121,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"easy",question:"Non-functional testing focuses on:",options:["A. Whether the system produces the correct outputs for given inputs","B. How well the system performs its functions (performance, reliability, usability)","C. The internal structure of the system's code","D. Whether each requirement has a corresponding test"],answer:1,explanation:"Non-functional testing evaluates quality characteristics like performance, reliability, and usability."},
{id:122,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"easy",question:"Regression testing is MOST important after:",options:["A. The initial system release","B. Any change made to the system","C. Acceptance testing is completed","D. Performance testing fails"],answer:1,explanation:"Regression testing verifies that changes have not broken existing functionality."},
{id:123,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"medium",question:"Which type of testing is MOST likely to use techniques like statement coverage and branch coverage?",options:["A. Functional testing","B. Non-functional testing","C. White-box testing","D. Acceptance testing"],answer:2,explanation:"White-box testing uses structural coverage criteria like statement and branch coverage."},
{id:124,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"medium",question:"Load testing, stress testing, and soak testing are examples of which type of testing?",options:["A. Functional testing","B. Security testing","C. Performance testing","D. Usability testing"],answer:2,explanation:"Load, stress, and soak tests are all performance testing subtypes."},
{id:125,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"medium",question:"Which type of testing verifies that the system has not regressed after a defect fix?",options:["A. Retesting","B. Regression testing","C. Sanity testing","D. Smoke testing"],answer:0,explanation:"Retesting (confirmation testing) verifies that a specific defect has been fixed. Regression tests check for broader regressions."},
{id:126,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"hard",question:"What is the MAIN difference between retesting and regression testing?",options:["A. Retesting is automated; regression testing is manual","B. Retesting confirms a specific defect is fixed; regression testing checks for new defects caused by changes","C. Retesting is done by developers; regression testing by testers","D. Retesting covers the whole system; regression testing covers only the changed module"],answer:1,explanation:"Retesting confirms a specific fix; regression testing ensures the fix hasn't broken other functionality."},
{id:127,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"medium",question:"Security testing is MOST focused on:",options:["A. Verifying the system meets performance benchmarks","B. Ensuring the system is protected against unauthorized access and threats","C. Validating that all functional requirements are implemented","D. Testing the usability of security-related features"],answer:1,explanation:"Security testing evaluates protection against unauthorized access, data breaches, and vulnerabilities."},
{id:128,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"hard",question:"Which type of testing is performed to evaluate whether a new system is compatible with its operational environment?",options:["A. Functional testing","B. Portability testing","C. Interoperability testing","D. Compatibility testing"],answer:3,explanation:"Compatibility testing verifies the system works correctly in its target operational environment."},
{id:129,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"hard",question:"A team tests a web application's response time under 10,000 concurrent users. This is MOST closely described as:",options:["A. Load testing","B. Stress testing","C. Volume testing","D. Soak testing"],answer:0,explanation:"Load testing measures behavior under expected or specified load levels."},
{id:130,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"hard",question:"A team tests what happens when a system is pushed beyond its maximum capacity. This is MOST closely described as:",options:["A. Load testing","B. Volume testing","C. Stress testing","D. Soak testing"],answer:2,explanation:"Stress testing pushes the system beyond its limits to understand failure behavior."},
{id:131,chapter:"Testing Throughout the SDLC",topic:"Maintenance Testing",difficulty:"easy",question:"Maintenance testing is triggered by:",options:["A. New project initiation","B. Changes to an operational system or its environment","C. User acceptance testing failure","D. The completion of system testing"],answer:1,explanation:"Maintenance testing is triggered by modifications, migrations, or retirements of operational systems."},
{id:132,chapter:"Testing Throughout the SDLC",topic:"Maintenance Testing",difficulty:"medium",question:"Which of the following is an example of a trigger for maintenance testing?",options:["A. A new software project starting","B. A hotfix applied to a production system","C. Completing a sprint in Agile","D. Hiring a new test team member"],answer:1,explanation:"Applying a hotfix to production triggers maintenance testing to verify the fix and check for regressions."},
{id:133,chapter:"Testing Throughout the SDLC",topic:"Maintenance Testing",difficulty:"medium",question:"What is impact analysis in the context of maintenance testing?",options:["A. Analyzing the business impact of a project","B. Assessing the scope and risk of changes to determine what testing is needed","C. Analyzing test coverage metrics","D. Evaluating the performance impact of new features"],answer:1,explanation:"Impact analysis determines what is affected by a change, guiding the extent of regression testing needed."},
{id:134,chapter:"Testing Throughout the SDLC",topic:"Maintenance Testing",difficulty:"hard",question:"A legacy system is being migrated to a new platform. Which type of maintenance testing is MOST relevant?",options:["A. Corrective maintenance testing","B. Adaptive maintenance testing","C. Perfective maintenance testing","D. Preventive maintenance testing"],answer:1,explanation:"Adaptive maintenance testing verifies changes made to adapt software to a new environment/platform."},
{id:135,chapter:"Testing Throughout the SDLC",topic:"Maintenance Testing",difficulty:"hard",question:"A vendor adds new functionality to improve system performance without any known bugs. Testing performed for this is MOST closely:",options:["A. Corrective maintenance testing","B. Adaptive maintenance testing","C. Perfective maintenance testing","D. Preventive maintenance testing"],answer:2,explanation:"Perfective maintenance testing covers changes made to improve or enhance the system."},
{id:136,chapter:"Testing Throughout the SDLC",topic:"Testing in SDLC",difficulty:"hard",question:"In a Kanban environment, how is testing MOST likely to be organized?",options:["A. Testing is performed in a separate phase after all development is complete","B. Testing is a continuous activity performed as items move through the workflow","C. Testing occurs only at scheduled sprint review meetings","D. Testing is replaced by automated deployment pipelines"],answer:1,explanation:"In Kanban, work items flow continuously and testing occurs as each item progresses through the workflow."},
{id:137,chapter:"Testing Throughout the SDLC",topic:"Test Levels",difficulty:"extreme",question:"A microservices application has 20 independent services. Defects in message contracts between services would MOST likely be found at which test level?",options:["A. Unit testing of individual services","B. Component integration testing","C. System testing","D. Acceptance testing"],answer:1,explanation:"Message contract defects between services are integration-level issues, found at component integration testing."},
{id:138,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"extreme",question:"A medical device software must demonstrate it complies with IEC 62304. Testing performed specifically for this purpose BEST represents:",options:["A. Functional testing","B. Compliance/regulatory testing","C. Acceptance testing","D. Non-functional testing"],answer:1,explanation:"Compliance testing verifies the system meets specific regulatory or standard requirements (like IEC 62304)."},
{id:139,chapter:"Testing Throughout the SDLC",topic:"Testing in SDLC",difficulty:"medium",question:"Which of the following BEST describes Behavior-Driven Development (BDD)?",options:["A. Developers write tests before code using only technical specifications","B. Acceptance criteria are written in a natural language format collaboratively before development","C. Behavior tests are automated after development is complete","D. Testing behavior replaces all other forms of testing"],answer:1,explanation:"BDD involves writing acceptance criteria collaboratively in natural language (Given-When-Then) before development."},
{id:140,chapter:"Testing Throughout the SDLC",topic:"Testing in SDLC",difficulty:"medium",question:"Test-Driven Development (TDD) is BEST described as:",options:["A. Writing test cases after development to verify functionality","B. Writing automated tests before writing the production code","C. Using only exploratory testing during development","D. Automating all manual regression tests"],answer:1,explanation:"TDD involves writing failing tests first, then writing minimal code to make them pass."},
{id:141,chapter:"Testing Throughout the SDLC",topic:"Test Levels",difficulty:"medium",question:"Which test level is MOST concerned with verifying end-to-end business processes?",options:["A. Unit testing","B. Integration testing","C. System testing","D. Component testing"],answer:2,explanation:"System testing validates the complete system against business requirements, including end-to-end processes."},
{id:142,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"medium",question:"Usability testing is a type of:",options:["A. Functional testing","B. Non-functional testing","C. White-box testing","D. Regression testing"],answer:1,explanation:"Usability is a non-functional quality characteristic; usability testing is a type of non-functional testing."},
{id:143,chapter:"Testing Throughout the SDLC",topic:"Test Levels",difficulty:"hard",question:"Which of the following BEST distinguishes system testing from acceptance testing?",options:["A. System testing uses black-box techniques; acceptance testing uses white-box","B. System testing is performed by the test team; acceptance testing by users/customers","C. System testing tests individual components; acceptance testing tests the whole system","D. System testing is automated; acceptance testing is always manual"],answer:1,explanation:"System testing is typically performed by the test team, while acceptance testing is performed by users/customers/business."},
{id:144,chapter:"Testing Throughout the SDLC",topic:"Testing in SDLC",difficulty:"extreme",question:"In a CI/CD pipeline, a build fails when automated unit tests detect a regression. This is an example of:",options:["A. Test-Driven Development","B. Shift-right testing","C. A quality gate enforced through continuous testing","D. Static analysis replacing dynamic testing"],answer:2,explanation:"Automated test gates in CI/CD pipelines are quality gates that prevent defective builds from progressing."},
{id:145,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"easy",question:"Black-box testing derives tests from:",options:["A. The internal code structure","B. The specification or requirements without knowledge of internal implementation","C. Code coverage metrics","D. Developer unit tests"],answer:1,explanation:"Black-box testing uses specifications and requirements, not internal implementation knowledge."},
{id:146,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"easy",question:"White-box testing derives tests from:",options:["A. User stories and acceptance criteria","B. Business requirements","C. Internal code structure and logic","D. Performance benchmarks"],answer:2,explanation:"White-box testing uses knowledge of the internal code structure (statements, branches, paths)."},
{id:147,chapter:"Testing Throughout the SDLC",topic:"Test Levels",difficulty:"medium",question:"Operational acceptance testing (OAT) is MOST focused on:",options:["A. Verifying functional requirements are met","B. Testing backup/recovery, maintenance, and operational procedures","C. Performance and load testing","D. User interface usability"],answer:1,explanation:"OAT focuses on operational aspects: backup, disaster recovery, maintenance procedures, and supportability."},
{id:148,chapter:"Testing Throughout the SDLC",topic:"Test Levels",difficulty:"hard",question:"Contract acceptance testing is performed to verify:",options:["A. The system meets legal regulations","B. The system fulfills the conditions specified in a contract","C. The user interface meets design specifications","D. Performance meets SLA requirements"],answer:1,explanation:"Contract acceptance testing verifies the system meets the agreed contractual requirements."},
{id:149,chapter:"Testing Throughout the SDLC",topic:"Maintenance Testing",difficulty:"extreme",question:"A production system is being retired. Which maintenance testing activity is MOST important?",options:["A. Regression testing of all existing features","B. Testing data migration to ensure data integrity in the new system","C. Performance testing of the retiring system","D. Unit testing of all modules"],answer:1,explanation:"When retiring a system, data migration testing ensures data is correctly preserved/transferred."},
{id:150,chapter:"Testing Throughout the SDLC",topic:"Testing in SDLC",difficulty:"extreme",question:"Which of the following BEST describes the 'whole team' approach to quality in Agile?",options:["A. All team members write test cases","B. Quality is everyone's responsibility, with testers, developers, and business collaborating on quality","C. Developers perform all testing tasks","D. Dedicated testers handle all quality activities independently"],answer:1,explanation:"The whole-team approach means quality is a shared responsibility — testers, developers, and business all contribute."},
{id:151,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"hard",question:"Which of the following is MOST likely an objective of non-functional testing?",options:["A. Verifying that a login function accepts valid credentials","B. Measuring the system's response time under peak load","C. Confirming that a calculation produces the correct result","D. Checking that all menu items display correctly"],answer:1,explanation:"Measuring response time under load is a performance (non-functional) testing objective."},
{id:152,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"medium",question:"Change-related testing includes which of the following?",options:["A. Usability testing and performance testing","B. Confirmation testing and regression testing","C. Alpha testing and beta testing","D. Compliance testing and security testing"],answer:1,explanation:"Change-related testing covers both confirmation testing (fix verified) and regression testing (nothing broken)."},
{id:153,chapter:"Testing Throughout the SDLC",topic:"Testing in SDLC",difficulty:"hard",question:"In Acceptance Test-Driven Development (ATDD), acceptance tests are:",options:["A. Written after development as final validation","B. Written collaboratively before development and drive the implementation","C. Automated performance tests","D. Written by testers in isolation"],answer:1,explanation:"In ATDD, acceptance tests are written collaboratively before development and serve as executable specifications."},
{id:154,chapter:"Testing Throughout the SDLC",topic:"Test Levels",difficulty:"medium",question:"Which test level is BEST for finding defects in interfaces between subsystems?",options:["A. Unit testing","B. System integration testing","C. User acceptance testing","D. Regression testing"],answer:1,explanation:"System integration testing focuses on verifying interfaces between subsystems."},
{id:155,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"extreme",question:"A financial application is tested to ensure it can recover all in-flight transactions after a crash. This MOST closely represents:",options:["A. Functional testing","B. Reliability testing","C. Security testing","D. Compatibility testing"],answer:1,explanation:"Recovery capability is a reliability quality characteristic — this is reliability/resilience testing."},
{id:156,chapter:"Testing Throughout the SDLC",topic:"Testing in SDLC",difficulty:"medium",question:"In the V-model, system design corresponds to which test level?",options:["A. Unit testing","B. Integration testing","C. System testing","D. Acceptance testing"],answer:2,explanation:"System design documents form the test basis for system testing in the V-model."},
{id:157,chapter:"Testing Throughout the SDLC",topic:"Test Levels",difficulty:"easy",question:"Which test level MOST typically uses stubs and drivers?",options:["A. Acceptance testing","B. System testing","C. Unit testing and integration testing","D. Performance testing"],answer:2,explanation:"Stubs (for called components) and drivers (for calling components) are used in unit and integration testing."},
{id:158,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"hard",question:"Exploratory testing is MOST aligned with which testing type?",options:["A. Scripted functional testing","B. Experience-based testing","C. White-box testing","D. Performance testing"],answer:1,explanation:"Exploratory testing is an experience-based technique where design and execution happen simultaneously."},
{id:159,chapter:"Testing Throughout the SDLC",topic:"Maintenance Testing",difficulty:"medium",question:"Why is impact analysis important before performing maintenance testing?",options:["A. It determines which modules are most expensive to maintain","B. It identifies what testing is needed by assessing the risk and scope of changes","C. It replaces the need for regression testing","D. It ensures all defects found in maintenance are classified"],answer:1,explanation:"Impact analysis identifies which parts of the system are affected by changes, guiding regression scope."},
{id:160,chapter:"Testing Throughout the SDLC",topic:"Test Levels",difficulty:"hard",question:"Which of the following BEST describes the test basis for integration testing?",options:["A. Source code and unit tests","B. Software design documents, interface specifications, and architecture documents","C. Business requirements and user stories","D. Operational user manuals"],answer:1,explanation:"Integration testing uses design documents, interface specs, and architecture as its test basis."},
{id:161,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"medium",question:"A test team runs a subset of regression tests after a minor bug fix to quickly assess if the fix has introduced new failures. This is BEST described as:",options:["A. Full regression testing","B. Sanity/smoke testing","C. Exploratory testing","D. System testing"],answer:1,explanation:"A quick subset of tests run after a change to check for critical regressions is a sanity or smoke test."},
{id:162,chapter:"Testing Throughout the SDLC",topic:"Testing in SDLC",difficulty:"medium",question:"Continuous testing in a CI/CD pipeline MOST commonly includes:",options:["A. Full system testing on every commit","B. Automated unit, integration, and regression tests triggered by each build","C. Manual exploratory testing after each deployment","D. Performance testing on every build"],answer:1,explanation:"Continuous testing typically includes automated unit, integration, and regression tests triggered by CI/CD builds."},
{id:163,chapter:"Testing Throughout the SDLC",topic:"Test Levels",difficulty:"extreme",question:"A team is testing a web application that calls a third-party geolocation API. During testing, the third-party API is unavailable. The BEST approach is to:",options:["A. Cancel the test session and wait for the API to be available","B. Use a test double (stub/mock) to simulate the third-party API","C. Skip testing the geolocation features entirely","D. Test in production when the API is available"],answer:1,explanation:"Test doubles (stubs/mocks) simulate unavailable components, allowing testing to continue independently."},
{id:164,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"hard",question:"Penetration testing is a form of:",options:["A. Performance testing","B. Security testing","C. Functional testing","D. Compliance testing"],answer:1,explanation:"Penetration testing (pen testing) is a security testing technique that simulates attacks."},
{id:165,chapter:"Testing Throughout the SDLC",topic:"Maintenance Testing",difficulty:"hard",question:"Which of the following BEST describes perfective maintenance?",options:["A. Fixing a defect reported by users","B. Adapting software to a new operating system","C. Improving software performance or maintainability","D. Retiring an old software system"],answer:2,explanation:"Perfective maintenance improves or enhances the system beyond fixing bugs or adapting to environments."},
{id:166,chapter:"Testing Throughout the SDLC",topic:"Testing in SDLC",difficulty:"hard",question:"In Agile, what is the PRIMARY purpose of the Definition of Done (DoD) for a user story?",options:["A. To define what features will be in the next sprint","B. To specify the acceptance criteria that must be met before a story is considered complete","C. To define the test automation framework to be used","D. To assign testing responsibilities to team members"],answer:1,explanation:"The Definition of Done ensures acceptance criteria are met — including testing — before a story is marked done."},
{id:167,chapter:"Testing Throughout the SDLC",topic:"Test Levels",difficulty:"medium",question:"Regulatory acceptance testing would MOST commonly be performed for:",options:["A. A social media application","B. A medical device software system","C. An internal HR tool","D. A gaming application"],answer:1,explanation:"Medical device software requires regulatory acceptance testing (e.g., FDA, IEC 62304) before release."},
{id:168,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"extreme",question:"A team tests a web application in Internet Explorer, Chrome, Firefox, and Safari. This is BEST described as:",options:["A. Portability testing","B. Compatibility testing","C. Regression testing","D. Functional testing"],answer:1,explanation:"Testing across multiple browsers is compatibility testing."},
{id:169,chapter:"Testing Throughout the SDLC",topic:"Testing in SDLC",difficulty:"extreme",question:"Which of the following BEST describes 'shift-right' testing?",options:["A. Moving testing to earlier in the development cycle","B. Performing testing in production or post-deployment environments","C. Using right-to-left testing methodologies","D. Focusing all testing on the right side of the V-model"],answer:1,explanation:"Shift-right testing performs testing activities in production (A/B testing, canary releases, monitoring)."},
{id:170,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"easy",question:"Confirmatio testing (retesting) is performed to:",options:["A. Check for new defects introduced by a change","B. Verify that a previously reported defect has been successfully fixed","C. Confirm the test environment is correctly set up","D. Validate user acceptance criteria"],answer:1,explanation:"Confirmation testing verifies that a specific defect that was previously found and fixed has been corrected."},
{id:171,chapter:"Testing Throughout the SDLC",topic:"Testing in SDLC",difficulty:"medium",question:"In which SDLC model is testing MOST tightly integrated with development?",options:["A. Waterfall","B. V-model","C. Agile/iterative","D. Big Bang"],answer:2,explanation:"Agile/iterative models most tightly integrate testing and development within each iteration."},
{id:172,chapter:"Testing Throughout the SDLC",topic:"Test Levels",difficulty:"hard",question:"Which of the following is a typical test object at the system testing level?",options:["A. A single function or method","B. A database stored procedure","C. The complete, integrated application","D. An API endpoint in isolation"],answer:2,explanation:"System testing tests the complete, integrated system as a whole."},
{id:173,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"medium",question:"Which of the following is NOT a type of non-functional testing?",options:["A. Performance testing","B. Security testing","C. Boundary value analysis","D. Usability testing"],answer:2,explanation:"Boundary value analysis is a black-box functional test design technique, not a type of non-functional testing."},
{id:174,chapter:"Testing Throughout the SDLC",topic:"Maintenance Testing",difficulty:"medium",question:"Which of the following BEST describes corrective maintenance testing?",options:["A. Testing changes made to improve performance","B. Testing fixes applied to address reported defects or failures","C. Testing adaptations to new environments","D. Testing preventive enhancements"],answer:1,explanation:"Corrective maintenance testing covers tests for defect fixes applied to the system."},
{id:175,chapter:"Testing Throughout the SDLC",topic:"Testing in SDLC",difficulty:"hard",question:"Which of the following is a key benefit of testing early in an iterative SDLC?",options:["A. All defects are found before development begins","B. Faster delivery is guaranteed","C. Defects can be identified and fixed within the same iteration, reducing cost","D. No regression testing is needed"],answer:2,explanation:"Early testing in iterations catches defects quickly within the same sprint, reducing rework cost."},
{id:176,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"hard",question:"A team tests how a system behaves under sustained load over 8 hours to check for memory leaks. This is MOST closely:",options:["A. Stress testing","B. Load testing","C. Soak/endurance testing","D. Volume testing"],answer:2,explanation:"Soak (endurance) testing runs the system under sustained load over time to detect issues like memory leaks."},
{id:177,chapter:"Testing Throughout the SDLC",topic:"Test Levels",difficulty:"medium",question:"In the context of the V-model, detailed design corresponds to which test level?",options:["A. Acceptance testing","B. System testing","C. Integration testing","D. Unit/Component testing"],answer:3,explanation:"Detailed component design corresponds to unit/component testing in the V-model."},
{id:178,chapter:"Testing Throughout the SDLC",topic:"Testing in SDLC",difficulty:"easy",question:"Which of the following BEST describes the purpose of test environment setup?",options:["A. To write test cases","B. To prepare the infrastructure, tools, and data needed for test execution","C. To define entry and exit criteria","D. To archive test results"],answer:1,explanation:"Test environment setup prepares all the infrastructure, tools, test data, and configurations needed to run tests."},
{id:179,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"extreme",question:"A team performs chaos engineering by randomly terminating services in production to test resilience. This BEST represents:",options:["A. Stress testing","B. Reliability/resilience testing using shift-right techniques","C. Destructive testing in the test environment","D. Security vulnerability scanning"],answer:1,explanation:"Chaos engineering is a shift-right reliability testing practice that tests system resilience in production."},
{id:180,chapter:"Testing Throughout the SDLC",topic:"Maintenance Testing",difficulty:"extreme",question:"After a significant OS upgrade on the servers hosting a banking application, which type of testing should be prioritized FIRST?",options:["A. Acceptance testing with end users","B. Impact analysis followed by targeted regression testing","C. Full system testing from scratch","D. Unit testing of all modules"],answer:1,explanation:"After environmental changes, impact analysis identifies what could be affected, then targeted regression testing is performed."},
// ============================================================
// CHAPTER 3: Static Testing (Q181-Q280)
// ============================================================

{id:181,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"easy",question:"Which of the following BEST describes static testing?",options:["A. Testing that involves executing the software","B. Testing that does not involve executing the software","C. Testing performed automatically by tools","D. Testing performed in a static test environment"],answer:1,explanation:"Static testing examines work products without executing the software."},
{id:182,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"easy",question:"Which of the following is an example of a static testing activity?",options:["A. Running unit tests","B. Performing a code review","C. Executing system tests","D. Running performance benchmarks"],answer:1,explanation:"Code reviews are static testing activities â€” they examine work products without execution."},
{id:183,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"easy",question:"Which types of work products can be examined using static testing?",options:["A. Only executable source code","B. Requirements, design documents, code, test plans, test cases, and more","C. Only test cases and test plans","D. Only requirements documents"],answer:1,explanation:"Static testing can be applied to any work product: requirements, designs, code, test plans, etc."},
{id:184,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"medium",question:"Which of the following defects is MOST effectively found by static testing rather than dynamic testing?",options:["A. A race condition in concurrent code","B. An ambiguous requirement that leads to different interpretations","C. An incorrect calculation result","D. A performance bottleneck"],answer:1,explanation:"Ambiguous requirements are best found through static review before they cause defects in code."},
{id:185,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"medium",question:"Which of the following is a benefit of static testing?",options:["A. It verifies the system's behavior at runtime","B. Defects are found early before they propagate to later phases","C. It eliminates the need for dynamic testing","D. It only requires automated tools"],answer:1,explanation:"Finding defects early through static testing prevents them from propagating and becoming more expensive to fix."},
{id:186,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"medium",question:"Which of the following BEST describes the difference between static and dynamic testing?",options:["A. Static testing uses tools; dynamic testing is manual","B. Static testing examines work products; dynamic testing executes software","C. Static testing is done by developers; dynamic testing by testers","D. Static testing is informal; dynamic testing is formal"],answer:1,explanation:"Static testing = examining artifacts without execution; dynamic testing = running the software."},
{id:187,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"hard",question:"Which of the following defects can ONLY be found by static testing and NOT dynamic testing?",options:["A. A memory leak in a running process","B. Unreachable (dead) code that can never be executed","C. An incorrect output from a calculation","D. A timeout failure under load"],answer:1,explanation:"Dead code can never be executed and therefore cannot trigger a failure â€” only static analysis can find it."},
{id:188,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"hard",question:"Static analysis tools can detect which of the following?",options:["A. User acceptance failures","B. Coding standards violations and potential defects in code","C. Performance bottlenecks at runtime","D. User experience issues"],answer:1,explanation:"Static analysis tools detect coding standard violations, security vulnerabilities, and code defects."},
{id:189,chapter:"Static Testing",topic:"Feedback and Review Process",difficulty:"easy",question:"What is the PRIMARY purpose of a review in software testing?",options:["A. To execute test cases against the software","B. To evaluate a work product and identify issues, defects, or improvements","C. To automate the testing process","D. To prepare the test environment"],answer:1,explanation:"Reviews evaluate work products to identify defects, inconsistencies, and improvement opportunities."},
{id:190,chapter:"Static Testing",topic:"Feedback and Review Process",difficulty:"medium",question:"Which of the following is a benefit of early feedback through reviews?",options:["A. Eliminates the need for system testing","B. Reduces rework by finding misunderstandings before they become code defects","C. Guarantees defect-free software","D. Replaces all other forms of testing"],answer:1,explanation:"Early reviews catch misunderstandings and defects before they are coded, reducing expensive rework."},
{id:191,chapter:"Static Testing",topic:"Review Types",difficulty:"easy",question:"Which type of review is the MOST informal?",options:["A. Inspection","B. Walkthrough","C. Informal review","D. Technical review"],answer:2,explanation:"An informal review has no defined process and is the least structured type of review."},
{id:192,chapter:"Static Testing",topic:"Review Types",difficulty:"easy",question:"Which type of review is the MOST formal and follows a defined process with metrics collection?",options:["A. Informal review","B. Walkthrough","C. Technical review","D. Inspection"],answer:3,explanation:"An inspection is the most formal review type with defined roles, entry/exit criteria, and metrics."},
{id:193,chapter:"Static Testing",topic:"Review Types",difficulty:"medium",question:"In a walkthrough, who TYPICALLY leads the review session?",options:["A. The review leader/moderator","B. The author of the work product","C. A dedicated inspector","D. An external auditor"],answer:1,explanation:"In a walkthrough, the author leads the session and presents their work to reviewers."},
{id:194,chapter:"Static Testing",topic:"Review Types",difficulty:"medium",question:"Which type of review is MOST appropriate for training new team members in processes and standards?",options:["A. Inspection","B. Walkthrough","C. Technical review","D. Informal review"],answer:1,explanation:"Walkthroughs are useful for training, spreading knowledge, and team discussion."},
{id:195,chapter:"Static Testing",topic:"Review Types",difficulty:"medium",question:"A technical review involves:",options:["A. The author presenting work to their peers for feedback","B. Technically qualified reviewers evaluating suitability of technical content","C. An external auditor reviewing code","D. Automated tools reviewing code quality"],answer:1,explanation:"Technical reviews involve qualified technical peers evaluating content for correctness and suitability."},
{id:196,chapter:"Static Testing",topic:"Review Types",difficulty:"hard",question:"Which of the following BEST distinguishes an inspection from a technical review?",options:["A. Inspections use checklists; technical reviews do not","B. Inspections are more formal with defined roles, entry/exit criteria, and mandatory metrics","C. Technical reviews are only for code; inspections cover all work products","D. Inspections are performed by external teams; technical reviews are internal"],answer:1,explanation:"Inspections are more formal â€” with defined roles (moderator, reader, scribe), entry criteria, and metrics collection."},
{id:197,chapter:"Static Testing",topic:"Review Types",difficulty:"hard",question:"Which of the following is a defined role in a formal inspection?",options:["A. Architect","B. Moderator","C. Scrum Master","D. Release manager"],answer:1,explanation:"A moderator (facilitator) is a defined role in formal inspections who leads the review process."},
{id:198,chapter:"Static Testing",topic:"Review Types",difficulty:"medium",question:"A peer review where developers examine each other's code is MOST closely described as:",options:["A. Formal inspection","B. Walkthrough","C. Informal review / peer review","D. Technical review"],answer:2,explanation:"Peer code review is typically an informal review process where developers review each other's code."},
{id:199,chapter:"Static Testing",topic:"Feedback and Review Process",difficulty:"hard",question:"During a review, a reviewer raises many issues not related to the work product being reviewed. The moderator should:",options:["A. Document all issues, even off-topic ones","B. Redirect the discussion and park off-topic issues for later","C. Terminate the review session","D. Allow all discussion since it may be relevant"],answer:1,explanation:"The moderator's job includes keeping the review focused and parking off-topic issues for later resolution."},
{id:200,chapter:"Static Testing",topic:"Feedback and Review Process",difficulty:"medium",question:"What should happen after a review meeting?",options:["A. The author immediately fixes all found issues","B. Issues are logged, decisions made, and the author addresses identified issues","C. The moderator sends the work product directly to the next phase","D. All found issues are escalated to the project manager"],answer:1,explanation:"After a review, issues are logged and the author works to fix them; follow-up confirms fixes."},

{id:201,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"medium",question:"Which of the following BEST describes static analysis?",options:["A. Manual review of documents by subject matter experts","B. Automated analysis of code or other artifacts without executing them","C. Running test scripts against static test data","D. Reviewing test results after execution"],answer:1,explanation:"Static analysis uses tools to automatically examine code/artifacts for defects without execution."},
{id:202,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"hard",question:"Which of the following can be detected by static analysis tools?",options:["A. Performance degradation under load","B. Security vulnerabilities such as SQL injection risks in code","C. Incorrect runtime behavior","D. User interface layout issues"],answer:1,explanation:"Static analysis can detect security vulnerabilities, code quality issues, and potential bugs without execution."},
{id:203,chapter:"Static Testing",topic:"Review Types",difficulty:"hard",question:"Which of the following is the CORRECT sequence of activities in a formal inspection?",options:["A. Planning -> Individual preparation -> Review meeting -> Rework -> Follow-up","B. Review meeting -> Planning -> Individual preparation -> Rework","C. Individual preparation -> Planning -> Review meeting -> Follow-up","D. Planning -> Review meeting -> Rework -> Individual preparation"],answer:0,explanation:"The formal inspection process: Planning -> Kick-off -> Individual preparation -> Review meeting -> Rework -> Follow-up."},
{id:204,chapter:"Static Testing",topic:"Feedback and Review Process",difficulty:"medium",question:"Which review role is responsible for ensuring the review process is followed?",options:["A. Author","B. Reviewer","C. Moderator","D. Scribe"],answer:2,explanation:"The moderator (facilitator) ensures the review process is followed and keeps it on track."},
{id:205,chapter:"Static Testing",topic:"Feedback and Review Process",difficulty:"medium",question:"Which review role is responsible for documenting issues and decisions during the review meeting?",options:["A. Moderator","B. Author","C. Scribe","D. Review leader"],answer:2,explanation:"The scribe records all issues, decisions, and action items during the review meeting."},
{id:206,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"extreme",question:"A large financial organization uses pair programming in their development process. This is an example of:",options:["A. Formal inspection","B. Continuous static testing through collaborative code review","C. Dynamic testing","D. Walkthrough"],answer:1,explanation:"Pair programming provides continuous informal code review â€” a form of ongoing static testing."},
{id:207,chapter:"Static Testing",topic:"Review Types",difficulty:"extreme",question:"Which review type is MOST appropriate when a safety-critical requirements specification needs rigorous evaluation with documented defect metrics?",options:["A. Walkthrough","B. Informal peer review","C. Inspection","D. Technical review"],answer:2,explanation:"Formal inspection with documented metrics is the most rigorous review, appropriate for safety-critical documents."},
{id:208,chapter:"Static Testing",topic:"Feedback and Review Process",difficulty:"hard",question:"Entry criteria for a review might include which of the following?",options:["A. The author has fixed all issues from the previous review","B. The work product is ready - no placeholders, syntax errors addressed","C. All reviewers have completed their other work","D. The review meeting room is booked"],answer:1,explanation:"A key entry criterion is that the work product is in a reviewable state - complete enough for review."},
{id:209,chapter:"Static Testing",topic:"Feedback and Review Process",difficulty:"hard",question:"Which of the following is an example of a review exit criterion?",options:["A. All reviewers have attended the kick-off meeting","B. All major defects have been addressed and verified","C. The author has been notified of the review","D. Reviewers have had 24 hours to prepare"],answer:1,explanation:"Exit criteria confirm the review objectives are met - typically that critical issues are resolved."},
{id:210,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"medium",question:"Reviewing test cases is an example of which type of static testing?",options:["A. Static analysis","B. Manual review","C. Dynamic testing","D. Regression testing"],answer:1,explanation:"Reviewing test cases (or any document) manually is a form of manual static testing."},
{id:211,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"medium",question:"Which of the following is NOT a typical work product examined in static testing?",options:["A. Requirements specification","B. Test cases","C. Runtime log files from production","D. Source code"],answer:2,explanation:"Runtime log files are produced during execution - they are a dynamic testing artifact, not a static testing input."},
{id:212,chapter:"Static Testing",topic:"Review Types",difficulty:"medium",question:"During a walkthrough, which of the following BEST describes the reviewers' role?",options:["A. To formally grade the work product","B. To ask questions, make suggestions, and identify potential issues","C. To formally approve the work product","D. To rewrite sections of the document"],answer:1,explanation:"In a walkthrough, reviewers ask questions, make suggestions, and discuss potential issues."},
{id:213,chapter:"Static Testing",topic:"Feedback and Review Process",difficulty:"extreme",question:"A team discovers that 80% of issues found during reviews were in requirements documents. This finding BEST supports which testing principle?",options:["A. Defects cluster together","B. Early testing saves time and money","C. Pesticide paradox","D. Testing is context-dependent"],answer:1,explanation:"Finding defects in requirements early (through reviews) is far cheaper than finding them in system testing or production."},
{id:214,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"hard",question:"Which of the following defect types is MOST likely found through code review rather than static analysis tools?",options:["A. Undeclared variables","B. Violations of naming conventions","C. Business logic that is technically correct but does not match the requirement","D. Memory access violations"],answer:2,explanation:"Logic defects that do not match requirements require human understanding of context - tools cannot detect them."},
{id:215,chapter:"Static Testing",topic:"Review Types",difficulty:"easy",question:"In which review type does the author present the work product to reviewers and reviewers provide feedback?",options:["A. Inspection","B. Walkthrough","C. Formal review","D. Technical review"],answer:1,explanation:"A walkthrough is characterized by the author presenting their work and reviewers providing feedback."},
{id:216,chapter:"Static Testing",topic:"Feedback and Review Process",difficulty:"medium",question:"Which of the following is a SUCCESS factor for effective reviews?",options:["A. Having reviewers rewrite portions of the work product","B. Having management evaluate the author's performance based on defects found","C. Establishing a no-blame, collaborative culture focused on finding defects","D. Limiting participation to senior team members only"],answer:2,explanation:"A constructive, blame-free culture focused on quality is essential for effective reviews."},
{id:217,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"hard",question:"Linters, code analyzers, and security scanning tools are examples of which static testing approach?",options:["A. Manual review","B. Inspection","C. Static analysis (automated)","D. Walkthrough"],answer:2,explanation:"Linters, analyzers, and security scanners are automated static analysis tools."},
{id:218,chapter:"Static Testing",topic:"Review Types",difficulty:"hard",question:"Which of the following BEST describes the 'author' role in a review?",options:["A. The author leads the review meeting","B. The author created the work product being reviewed and addresses identified issues","C. The author documents issues during the review","D. The author approves the final work product"],answer:1,explanation:"The author created the work product and is responsible for addressing issues identified during the review."},
{id:219,chapter:"Static Testing",topic:"Feedback and Review Process",difficulty:"extreme",question:"A test plan is reviewed and found to have missing test coverage for security requirements. This is BEST described as:",options:["A. A defect in the test plan","B. A failure in the test process","C. A dynamic testing issue","D. An error in the requirements"],answer:0,explanation:"Missing test coverage for documented requirements is a defect in the test plan, found through static review."},
{id:220,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"extreme",question:"Which of the following MOST accurately describes the relationship between static testing and defect prevention?",options:["A. Static testing prevents all defects in the final system","B. Static testing finds and removes defects early, and the review process provides feedback that helps prevent future defects","C. Static testing is only effective for defect detection, not prevention","D. Only static analysis tools contribute to defect prevention"],answer:1,explanation:"Reviews and static analysis find defects early AND the feedback improves processes, preventing future defects."},
{id:221,chapter:"Static Testing",topic:"Review Types",difficulty:"medium",question:"Which of the following is NOT a benefit of formal inspections?",options:["A. Defects found early before downstream propagation","B. Author learns from defects found, improving future work","C. Guarantees the work product is defect-free after the review","D. Metrics collected can improve future review processes"],answer:2,explanation:"No review technique can guarantee a defect-free work product - it can only reduce defect density."},
{id:222,chapter:"Static Testing",topic:"Feedback and Review Process",difficulty:"medium",question:"What is a 'review checklist' used for in the review process?",options:["A. Listing the reviewers' personal tasks","B. Providing a structured list of items to look for during the review","C. Recording defects found during execution","D. Tracking the author's progress in fixing issues"],answer:1,explanation:"A review checklist provides a structured set of items/questions reviewers should check for during the review."},
{id:223,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"medium",question:"Which of the following is a LIMITATION of static analysis tools?",options:["A. They cannot analyze source code","B. They generate false positives that require human investigation","C. They can only be used on small codebases","D. They require the system to be running"],answer:1,explanation:"Static analysis tools can generate false positives - findings that appear to be defects but are not."},
{id:224,chapter:"Static Testing",topic:"Review Types",difficulty:"hard",question:"Which type of review is MOST appropriate early in a project to verify that requirements are correct and complete?",options:["A. Code inspection","B. Requirements walkthrough or review","C. System test execution","D. User acceptance testing"],answer:1,explanation:"Requirements reviews/walkthroughs early in the project catch ambiguities and missing requirements cheaply."},
{id:225,chapter:"Static Testing",topic:"Feedback and Review Process",difficulty:"hard",question:"During an individual preparation phase of a review, reviewers should:",options:["A. Meet together to discuss the work product","B. Independently examine the work product and log potential issues","C. Fix issues they identify in the work product","D. Present their findings to the author"],answer:1,explanation:"Individual preparation involves each reviewer independently examining the work product and noting potential issues."},
{id:226,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"easy",question:"Which of the following is a TYPE of static analysis?",options:["A. Unit testing","B. Code coverage analysis","C. Cyclomatic complexity analysis","D. Performance profiling"],answer:2,explanation:"Cyclomatic complexity analysis is a static analysis technique that measures code complexity."},
{id:227,chapter:"Static Testing",topic:"Review Types",difficulty:"easy",question:"An 'ad hoc' review with no formal process or defined output is BEST described as:",options:["A. Inspection","B. Technical review","C. Informal review","D. Walkthrough"],answer:2,explanation:"An informal review has no defined process, roles, or required output."},
{id:228,chapter:"Static Testing",topic:"Feedback and Review Process",difficulty:"medium",question:"The 'kick-off' meeting in a formal review is used to:",options:["A. Make the final decision on release","B. Distribute the work product and ensure reviewers understand the objectives and their roles","C. Present the defects found during individual review","D. Approve the final version of the work product"],answer:1,explanation:"The kick-off ensures all participants understand the review objectives, their roles, and the work product context."},
{id:229,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"hard",question:"Which of the following is NOT typically detected by automated static analysis?",options:["A. Potential null pointer exceptions","B. Security injection vulnerabilities","C. Whether the feature meets business goals","D. Code duplication"],answer:2,explanation:"Whether code meets business goals requires human judgment - tools cannot detect business-level requirements alignment."},
{id:230,chapter:"Static Testing",topic:"Review Types",difficulty:"extreme",question:"A team uses pair programming and continuous code reviews in their CI pipeline with automated linting. What review coverage does this approach MOST closely achieve?",options:["A. Equivalent to a formal inspection","B. A combination of informal review and automated static analysis","C. Equivalent to a walkthrough with documented metrics","D. Formal technical review"],answer:1,explanation:"Pair programming provides informal review; automated linting provides static analysis - together they cover both."},
{id:231,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"medium",question:"Which of the following BEST describes a benefit of using automated static analysis in CI pipelines?",options:["A. It replaces the need for manual reviews","B. It provides immediate feedback to developers when they commit code","C. It verifies runtime behavior","D. It guarantees compliance with all coding standards"],answer:1,explanation:"Automated static analysis in CI gives developers immediate feedback on code quality issues as they commit."},
{id:232,chapter:"Static Testing",topic:"Feedback and Review Process",difficulty:"hard",question:"Which of the following is considered a review defect severity classification?",options:["A. Blocker, Critical, Major, Minor, Trivial","B. Error, Defect, Failure","C. Easy, Medium, Hard, Extreme","D. Functional, Non-functional, Structural"],answer:0,explanation:"Defects found in reviews are typically classified by severity (blocker, critical, major, minor, trivial)."},
{id:233,chapter:"Static Testing",topic:"Review Types",difficulty:"medium",question:"Which review type does NOT require the author to be present?",options:["A. Walkthrough","B. Inspection","C. Informal review","D. Technical review"],answer:1,explanation:"In inspections, the author may not be required to be present during the review meeting itself."},
{id:234,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"extreme",question:"A SAST tool reports 200 findings. The team investigates and finds 150 are false positives. What is the BEST approach going forward?",options:["A. Disable the SAST tool as it produces too many false positives","B. Tune the tool's configuration rules to reduce false positives and investigate remaining findings","C. Ignore all tool findings and rely on manual testing","D. Increase the tool's sensitivity to find more issues"],answer:1,explanation:"Tuning SAST tools to reduce false positives makes the findings actionable while maintaining security coverage."},
{id:235,chapter:"Static Testing",topic:"Feedback and Review Process",difficulty:"medium",question:"Why is it important to follow up after a review to verify that issues have been addressed?",options:["A. To ensure reviewers get credit for issues they found","B. To confirm the work product has been improved and meets exit criteria","C. To update the project schedule","D. To reassign issues to other team members"],answer:1,explanation:"Follow-up ensures that identified issues have been actually fixed and the work product meets review exit criteria."},
{id:236,chapter:"Static Testing",topic:"Review Types",difficulty:"medium",question:"Which review type is MOST likely to use a checklist based on past defect data?",options:["A. Informal review","B. Walkthrough","C. Inspection","D. Ad hoc review"],answer:2,explanation:"Inspections use structured checklists informed by historical defect data to guide thorough examination."},
{id:237,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"medium",question:"Which of the following is a category of defect that can be detected by reviewing requirements?",options:["A. Memory allocation errors","B. Ambiguities, inconsistencies, and missing requirements","C. Runtime exceptions","D. Performance bottlenecks"],answer:1,explanation:"Requirements reviews find ambiguities, inconsistencies, incompleteness, and conflicting requirements."},
{id:238,chapter:"Static Testing",topic:"Feedback and Review Process",difficulty:"easy",question:"Who is PRIMARILY responsible for fixing issues found during a review?",options:["A. The moderator","B. The scribe","C. The author","D. The reviewer"],answer:2,explanation:"The author is responsible for addressing and fixing issues identified during the review."},
{id:239,chapter:"Static Testing",topic:"Review Types",difficulty:"hard",question:"Peer review of test cases helps achieve which benefit?",options:["A. Faster test execution","B. Improved test case quality and identification of missing coverage","C. Automated test generation","D. Reduced testing timeline"],answer:1,explanation:"Reviewing test cases finds errors, improves coverage, and ensures they correctly represent requirements."},
{id:240,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"extreme",question:"A development team uses automated code review tools integrated into their pull request process. This MOST accurately represents which testing concept?",options:["A. Continuous dynamic testing","B. Shift-left static testing integrated into the development workflow","C. Automated acceptance testing","D. Test automation as a replacement for manual testing"],answer:1,explanation:"Automated static analysis in the PR process is shift-left testing - catching defects at the earliest possible point."},

{id:241,chapter:"Static Testing",topic:"Review Types",difficulty:"extreme",question:"A safety-critical medical device project requires all requirements documents to undergo formal inspection with complete traceability to found defects. This is MOST likely required by:",options:["A. Agile development methodology","B. Regulatory compliance requirements (e.g., FDA 21 CFR Part 11)","C. The project manager's personal preference","D. The ISTQB certification body"],answer:1,explanation:"Regulatory bodies often mandate formal review processes with documented evidence for safety-critical systems."},
{id:242,chapter:"Static Testing",topic:"Feedback and Review Process",difficulty:"hard",question:"Which of the following is a CHALLENGE specific to remote/virtual reviews?",options:["A. Finding enough reviewers","B. Technical difficulties and reduced informal communication compared to in-person reviews","C. Reviews take too long","D. Work products being too large to review"],answer:1,explanation:"Remote reviews face challenges like technical issues and reduced informal interaction."},
{id:243,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"easy",question:"Which of the following is a characteristic of static testing that distinguishes it from dynamic testing?",options:["A. Static testing can only be performed by specialized testers","B. Static testing finds defects directly rather than triggering failures","C. Static testing always uses automated tools","D. Static testing only applies to code"],answer:1,explanation:"Static testing finds defects (the root cause) directly; dynamic testing triggers failures from which defects are inferred."},
{id:244,chapter:"Static Testing",topic:"Review Types",difficulty:"medium",question:"In which type of review is the work product's author NOT expected to lead the session?",options:["A. Walkthrough","B. Informal review","C. Technical review or Inspection","D. Peer review"],answer:2,explanation:"In technical reviews and inspections, a trained moderator leads the session â€” not the author."},
{id:245,chapter:"Static Testing",topic:"Feedback and Review Process",difficulty:"hard",question:"During a review, a reviewer begins personally criticizing the author's abilities. The moderator should MOST appropriately:",options:["A. Allow it since it may motivate the author to improve","B. Redirect the discussion to the work product and address the behavior privately","C. End the review immediately","D. Ask the author to leave the meeting"],answer:1,explanation:"Moderators must maintain a constructive, blame-free environment â€” redirecting personal criticism is essential."},
{id:246,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"medium",question:"Which of the following is an objective of static testing?",options:["A. Executing test cases to find failures","B. Evaluating work products to find defects, risks, and improvements","C. Measuring system performance","D. Deploying software to staging environments"],answer:1,explanation:"Objectives of static testing include finding defects, assessing quality, and identifying risks in work products."},
{id:247,chapter:"Static Testing",topic:"Review Types",difficulty:"hard",question:"A review where a senior engineer examines the architecture design for technical correctness, without involving the author, is MOST closely described as:",options:["A. Informal review","B. Walkthrough","C. Technical review","D. Inspection"],answer:2,explanation:"A technical review involves qualified technical reviewers evaluating technical content for correctness."},
{id:248,chapter:"Static Testing",topic:"Feedback and Review Process",difficulty:"medium",question:"Collecting and analyzing review metrics can help improve the review process by:",options:["A. Identifying which authors produce the most defects for performance reviews","B. Understanding defect density, review efficiency, and areas needing improvement","C. Proving to management that reviews are worthwhile","D. Replacing the exit criteria with quantitative thresholds"],answer:1,explanation:"Review metrics help improve future reviews by identifying patterns in defect density and review effectiveness."},
{id:249,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"hard",question:"Which of the following is a characteristic that makes a work product MORE suitable for static testing?",options:["A. It is executed frequently in production","B. It will form the basis for subsequent work products or tests","C. It is simple and straightforward","D. It has already been tested dynamically"],answer:1,explanation:"Documents that form the basis for subsequent work benefit most from static testing since defects propagate downstream."},
{id:250,chapter:"Static Testing",topic:"Review Types",difficulty:"extreme",question:"A team conducts a review meeting for a 200-page requirements specification. After 4 hours, they have covered only 20 pages and found 50 defects. Which action should the moderator take?",options:["A. Continue the meeting until all pages are reviewed","B. Schedule additional review meetings and adjust the review scope to manageable chunks","C. Declare the requirements inadequate and restart requirements gathering","D. Fast-track the remaining 180 pages in the same session"],answer:1,explanation:"When review scope is too large or defect density too high, the moderator should split the review into manageable sessions."},

// ============================================================
// CHAPTER 4: Test Analysis and Design (Q251-Q450)
// ============================================================
{id:251,chapter:"Test Analysis and Design",topic:"Test Conditions",difficulty:"easy",question:"A test condition is BEST described as:",options:["A. A specific set of inputs and expected outputs for a test","B. An aspect of the test object that can be verified by one or more test cases","C. A constraint on the test environment","D. A pass/fail criterion for the entire test suite"],answer:1,explanation:"A test condition is an aspect or feature that needs to be tested â€” it can lead to one or more test cases."},
{id:252,chapter:"Test Analysis and Design",topic:"Test Conditions",difficulty:"medium",question:"Which of the following BEST describes the difference between a test condition and a test case?",options:["A. A test condition is a specific executable test; a test case is a general area to test","B. A test condition identifies what to test; a test case specifies how to test it","C. Test conditions are for dynamic testing; test cases are for static testing","D. They are the same thing"],answer:1,explanation:"Test conditions identify WHAT needs to be tested; test cases specify HOW (inputs, steps, expected results)."},
{id:253,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"easy",question:"Which of the following is a black-box test design technique?",options:["A. Statement coverage","B. Branch coverage","C. Equivalence partitioning","D. Condition coverage"],answer:2,explanation:"Equivalence partitioning is a black-box technique that derives tests from specifications without code knowledge."},
{id:254,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"easy",question:"What is the purpose of equivalence partitioning?",options:["A. To test all possible input values","B. To divide inputs into groups where each value in the group is expected to behave the same","C. To test only boundary values","D. To test all combinations of inputs"],answer:1,explanation:"EP divides inputs into partitions where all values behave the same way â€” one value from each partition is sufficient."},
{id:255,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"A field accepts ages from 1 to 120. Using equivalence partitioning, what are the valid and invalid partitions?",options:["A. Valid: 1-120, Invalid: <1 and >120","B. Valid: 1-60 and 61-120, Invalid: <1 and >120","C. Valid: 0-120, Invalid: >120","D. Valid: all positive numbers, Invalid: negative numbers"],answer:0,explanation:"EP creates: Valid partition (1-120), Invalid partition below (<1), Invalid partition above (>120)."},
{id:256,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"Boundary value analysis extends equivalence partitioning by:",options:["A. Testing all values in each partition","B. Testing the values at and just inside and outside boundaries","C. Creating decision tables for boundary conditions","D. Testing only the middle value of each partition"],answer:1,explanation:"BVA focuses on values at the edges of partitions where defects are most likely to occur."},
{id:257,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"For a valid age range of 18-65, which values would 2-value BVA produce?",options:["A. 17, 18, 65, 66","B. 18, 65","C. 17, 18, 64, 65","D. 0, 18, 65, 120"],answer:0,explanation:"2-value BVA tests the boundary and just outside: 17 (invalid), 18 (valid), 65 (valid), 66 (invalid)."},
{id:258,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"hard",question:"For a valid age range of 18-65, which values would 3-value BVA produce?",options:["A. 17, 18, 19, 64, 65, 66","B. 18, 65","C. 17, 18, 65, 66","D. 16, 17, 18, 65, 66, 67"],answer:0,explanation:"3-value BVA tests: boundary-1, boundary, boundary+1 at each edge: 17,18,19 (lower) and 64,65,66 (upper)."},
{id:259,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"A decision table is MOST useful when:",options:["A. There is a simple linear set of conditions","B. Complex combinations of conditions determine system behavior","C. Testing boundary values in numeric ranges","D. Testing state transitions in a system"],answer:1,explanation:"Decision tables are ideal for complex business logic with multiple conditions and resulting actions."},
{id:260,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"hard",question:"A system has 3 binary conditions. How many possible combinations does a full decision table have?",options:["A. 3","B. 6","C. 8","D. 9"],answer:2,explanation:"With 3 binary conditions, there are 2^3 = 8 possible combinations."},
{id:261,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"hard",question:"In a decision table, a 'don't care' entry means:",options:["A. The condition is not relevant and can be either true or false","B. The condition always evaluates to true","C. The condition is an invalid input","D. The condition is not yet defined"],answer:0,explanation:"A 'don't care' (N/A) entry means the condition's value does not affect the outcome for that rule."},
{id:262,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"easy",question:"State transition testing is MOST appropriate when:",options:["A. The system has complex business rules with many conditions","B. The system has defined states and transitions between them based on events","C. Testing numeric input ranges","D. Testing user interface layouts"],answer:1,explanation:"State transition testing models systems with states, events, and transitions between states."},
{id:263,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"In a state transition diagram, what is a 'transition'?",options:["A. A stable condition of the system","B. A movement from one state to another triggered by an event","C. A defect in the state machine","D. A test case for the state machine"],answer:1,explanation:"A transition is a change from one state to another, triggered by an event or condition."},
{id:264,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"hard",question:"All-states coverage in state transition testing requires:",options:["A. Every state is visited at least once","B. Every transition is traversed at least once","C. Every invalid transition is tested","D. All state combinations are tested"],answer:0,explanation:"All-states coverage requires that each valid state is visited by at least one test."},
{id:265,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"hard",question:"All-transitions coverage in state transition testing requires:",options:["A. Every state is visited at least once","B. Every valid transition is traversed at least once","C. Every invalid transition is tested","D. All possible paths through the state machine are covered"],answer:1,explanation:"All-transitions (0-switch) coverage requires each valid transition to be exercised at least once."},
{id:266,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"A use case describes:",options:["A. The internal code structure of a feature","B. An interaction between an actor and the system that achieves a goal","C. The test cases for a system feature","D. The database schema for an application"],answer:1,explanation:"A use case describes interactions between actors (users/systems) and the system to achieve a specific goal."},
{id:267,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"Use case testing is MOST useful for:",options:["A. Testing low-level code logic","B. Testing end-to-end business scenarios from a user perspective","C. Testing database performance","D. Measuring code coverage"],answer:1,explanation:"Use case testing validates end-to-end scenarios that represent real user interactions and business processes."},
{id:268,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"easy",question:"Which of the following is a white-box test design technique?",options:["A. Equivalence partitioning","B. Boundary value analysis","C. Statement coverage","D. Use case testing"],answer:2,explanation:"Statement coverage is a white-box technique based on the internal code structure."},
{id:269,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"medium",question:"Statement coverage measures:",options:["A. The percentage of branches tested","B. The percentage of executable statements executed by test cases","C. The percentage of conditions tested","D. The percentage of paths tested"],answer:1,explanation:"Statement coverage = (executed statements / total executable statements) x 100%."},
{id:270,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"medium",question:"Branch coverage measures:",options:["A. The percentage of statements executed","B. The percentage of decision outcomes (true/false) exercised","C. The percentage of paths through the code","D. The percentage of conditions in expressions tested"],answer:1,explanation:"Branch coverage requires each decision (if/else) to be tested for both true and false outcomes."},
{id:271,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"hard",question:"100% statement coverage guarantees:",options:["A. That all defects have been found","B. That all branches have been covered","C. That every executable statement has been executed at least once","D. That all paths have been tested"],answer:2,explanation:"100% statement coverage means every executable statement ran at least once â€” but does NOT mean all branches are covered."},
{id:272,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"hard",question:"Which is TRUE about the relationship between branch coverage and statement coverage?",options:["A. 100% statement coverage implies 100% branch coverage","B. 100% branch coverage implies 100% statement coverage","C. They are completely independent","D. Branch coverage is always lower than statement coverage"],answer:1,explanation:"100% branch coverage subsumes (implies) 100% statement coverage, but not vice versa."},
{id:273,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"extreme",question:"A function has 5 independent conditions in a single decision expression. How many tests does Modified Condition/Decision Coverage (MC/DC) require at minimum?",options:["A. 10","B. 32","C. 6","D. 5"],answer:2,explanation:"MC/DC requires N+1 tests for N independent conditions (5+1=6), much fewer than the 2^5=32 for full condition combination coverage."},
{id:274,chapter:"Test Analysis and Design",topic:"Experience-based Techniques",difficulty:"easy",question:"Which of the following is an experience-based test design technique?",options:["A. Equivalence partitioning","B. Statement coverage","C. Exploratory testing","D. Decision tables"],answer:2,explanation:"Exploratory testing is an experience-based technique where tests are designed and executed simultaneously."},
{id:275,chapter:"Test Analysis and Design",topic:"Experience-based Techniques",difficulty:"easy",question:"Error guessing is BEST described as:",options:["A. Guessing the probability of a defect","B. Using knowledge and experience to anticipate where defects are likely to be","C. Randomly selecting test inputs","D. Testing without a test plan"],answer:1,explanation:"Error guessing uses testers' experience to predict likely defects and design tests to find them."},
{id:276,chapter:"Test Analysis and Design",topic:"Experience-based Techniques",difficulty:"medium",question:"A fault attack is a systematic form of:",options:["A. Boundary value analysis","B. Error guessing","C. State transition testing","D. Decision table testing"],answer:1,explanation:"A fault attack is a structured approach to error guessing, using lists of common failures and defects."},
{id:277,chapter:"Test Analysis and Design",topic:"Experience-based Techniques",difficulty:"medium",question:"Exploratory testing is BEST described as:",options:["A. Testing without documentation","B. Simultaneous test design, execution, and learning to investigate the system","C. Random input testing","D. Testing that replaces scripted testing"],answer:1,explanation:"Exploratory testing simultaneously designs, executes, and learns â€” guided by the tester's skills and knowledge."},
{id:278,chapter:"Test Analysis and Design",topic:"Experience-based Techniques",difficulty:"hard",question:"A test charter in exploratory testing serves as:",options:["A. A formal test script with exact steps","B. A goal or mission that guides the exploration focus","C. A list of test conditions","D. A defect report template"],answer:1,explanation:"A test charter defines the mission/scope for an exploratory testing session â€” what to explore and why."},
{id:279,chapter:"Test Analysis and Design",topic:"Experience-based Techniques",difficulty:"medium",question:"Checklist-based testing is BEST described as:",options:["A. Testing that verifies each item on a requirements checklist","B. Testing guided by a list of conditions, risks, or items to check","C. Testing that uses automated checklists","D. Testing that follows a fixed script"],answer:1,explanation:"Checklist-based testing uses a pre-prepared list of items to guide test design and execution."},
{id:280,chapter:"Test Analysis and Design",topic:"Collaboration Approaches",difficulty:"easy",question:"What is the purpose of collaborative user story creation in testing?",options:["A. To assign user stories to developers","B. To ensure shared understanding of requirements through collaboration between developers, testers, and business","C. To create automated test scripts","D. To estimate story points"],answer:1,explanation:"Collaborative story creation ensures testers, developers, and business stakeholders share understanding of requirements."},

{id:281,chapter:"Test Analysis and Design",topic:"Collaboration Approaches",difficulty:"medium",question:"The Three Amigos concept in Agile refers to:",options:["A. Three testers who review test plans","B. Collaboration between a developer, tester, and business representative to define requirements and acceptance criteria","C. Three stages of acceptance testing","D. Three types of user stories"],answer:1,explanation:"The Three Amigos (business, dev, test) collaborate to ensure shared understanding before development begins."},
{id:282,chapter:"Test Analysis and Design",topic:"Collaboration Approaches",difficulty:"medium",question:"In ATDD, acceptance criteria are written using the format:",options:["A. When-Then-Given","B. Given-When-Then","C. If-Then-Else","D. Arrange-Act-Assert"],answer:1,explanation:"ATDD acceptance criteria use Given (preconditions) - When (action) - Then (expected outcome) format."},
{id:283,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"hard",question:"A discount system gives 10% off for purchases over $100, 20% off for loyalty members, and both discounts can apply. A decision table for this has how many rules (not counting the header)?",options:["A. 2","B. 4","C. 6","D. 8"],answer:1,explanation:"With 2 binary conditions (purchase >$100: Y/N, loyalty member: Y/N), there are 2^2 = 4 rules."},
{id:284,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"extreme",question:"A login system has a partition: valid users (registered), invalid username (not registered), and valid username with wrong password. Using equivalence partitioning, what is the MINIMUM number of tests to cover all partitions?",options:["A. 1","B. 2","C. 3","D. 4"],answer:2,explanation:"One test case per partition: valid login (registered + correct password), invalid username, wrong password = 3 tests."},
{id:285,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"hard",question:"A code module has a simple if-else statement. What is the minimum number of tests needed to achieve 100% branch coverage?",options:["A. 1","B. 2","C. 3","D. 4"],answer:1,explanation:"An if-else statement has 2 branches (true and false); at minimum, 2 tests are needed to cover both."},
{id:286,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"Which black-box technique is BEST for testing a credit card validation system that accepts numbers of specific lengths?",options:["A. State transition testing","B. Equivalence partitioning and boundary value analysis","C. Decision table testing","D. Use case testing"],answer:1,explanation:"EP and BVA are ideal for testing numeric ranges â€” valid lengths vs. invalid (too short/too long)."},
{id:287,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"hard",question:"In state transition testing, an invalid transition test checks:",options:["A. That all valid states are reached","B. That the system handles attempts to trigger undefined transitions correctly","C. That transitions occur in the correct sequence","D. That the initial state is correct"],answer:1,explanation:"Invalid transition tests verify the system appropriately handles undefined or illegal state transitions."},
{id:288,chapter:"Test Analysis and Design",topic:"Experience-based Techniques",difficulty:"hard",question:"Which of the following BEST describes a session-based exploratory testing approach?",options:["A. Testing without any time constraints","B. Time-boxed, chartered exploration with a defined mission and debriefing","C. Exploratory testing using only scripted test cases","D. Pair testing without a charter"],answer:1,explanation:"Session-based exploratory testing uses time-boxes, charters (missions), and debrief meetings."},
{id:289,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"Which technique is MOST suitable for testing an ATM's states: Ready, Card Inserted, PIN Verified, Transaction Processing, and Dispensing Cash?",options:["A. Equivalence partitioning","B. Boundary value analysis","C. State transition testing","D. Decision table testing"],answer:2,explanation:"ATMs have clear states and transitions â€” state transition testing is ideal."},
{id:290,chapter:"Test Analysis and Design",topic:"Test Conditions",difficulty:"hard",question:"Traceability between test cases and requirements serves which purpose?",options:["A. It reduces the number of test cases needed","B. It ensures requirements have test coverage and supports impact analysis","C. It automatically generates test cases from requirements","D. It eliminates the need for test planning"],answer:1,explanation:"Traceability ensures every requirement has tests and helps identify which tests are affected by requirement changes."},
{id:291,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"medium",question:"Path coverage testing requires:",options:["A. All statements to be executed","B. All branches to be traversed","C. All independent paths through the code to be exercised","D. All conditions to be true and false"],answer:2,explanation:"Path coverage requires every distinct independent path through the code to be executed."},
{id:292,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"A form accepts first name, last name, and email. Using equivalence partitioning for the email field, which is a valid partition?",options:["A. First name and last name combined","B. Valid email addresses (containing @ and domain)","C. All string inputs","D. Numeric inputs only"],answer:1,explanation:"For an email field, valid EP partition = valid format emails; invalid partitions = missing @, no domain, etc."},
{id:293,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"extreme",question:"A password field requires 8-16 characters. Using 3-value BVA, how many test values are needed?",options:["A. 2","B. 4","C. 6","D. 8"],answer:2,explanation:"3-value BVA at lower boundary: 7,8,9 and at upper boundary: 15,16,17 = 6 test values total."},
{id:294,chapter:"Test Analysis and Design",topic:"Experience-based Techniques",difficulty:"medium",question:"A tester with 10 years of banking system experience uses their knowledge to identify areas most likely to have defects. This BEST illustrates which technique?",options:["A. Boundary value analysis","B. Error guessing","C. Decision table testing","D. Branch coverage"],answer:1,explanation:"Using experience to predict likely defect locations is the error guessing technique."},
{id:295,chapter:"Test Analysis and Design",topic:"Collaboration Approaches",difficulty:"hard",question:"What is the MAIN benefit of using Given-When-Then format for acceptance criteria?",options:["A. It reduces the time needed for testing","B. It creates clear, testable criteria that everyone (business, dev, test) can understand","C. It automatically generates test scripts","D. It eliminates the need for test cases"],answer:1,explanation:"GWT format creates unambiguous, testable acceptance criteria that all stakeholders can understand and validate."},
{id:296,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"extreme",question:"A test achieves 100% branch coverage but only 80% condition coverage. What can be concluded?",options:["A. All defects have been found","B. All branches but not all individual condition outcomes have been tested","C. The test suite is inadequate since condition coverage should be 100%","D. Branch coverage and condition coverage are always equal"],answer:1,explanation:"Branch coverage checks decision outcomes (true/false); condition coverage checks each individual condition â€” they are different."},
{id:297,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"hard",question:"When applying equivalence partitioning to an ordered set (like a range), boundary value analysis should ALSO be applied because:",options:["A. EP and BVA are the same technique","B. Defects are more likely at the boundaries of partitions","C. BVA replaces EP for ordered sets","D. BVA tests the center of each partition"],answer:1,explanation:"Defects tend to cluster at partition boundaries, so BVA complements EP by testing those boundary values."},
{id:298,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"A bank charges different interest rates based on credit score: <600 (high risk), 600-750 (medium risk), >750 (low risk). How many equivalence partitions exist?",options:["A. 2","B. 3","C. 4","D. 6"],answer:1,explanation:"There are 3 partitions: high risk (<600), medium risk (600-750), and low risk (>750)."},
{id:299,chapter:"Test Analysis and Design",topic:"Experience-based Techniques",difficulty:"extreme",question:"A tester finishes scripted testing and spends the remaining time exploring areas they found suspicious during scripted testing. This BEST illustrates:",options:["A. A structured fault attack","B. Targeted exploratory testing guided by findings from scripted testing","C. Ad hoc testing without a plan","D. Regression testing"],answer:1,explanation:"Exploratory testing guided by prior test findings is a structured, effective use of remaining test time."},
{id:300,chapter:"Test Analysis and Design",topic:"Test Conditions",difficulty:"medium",question:"Test coverage is BEST described as:",options:["A. The number of test cases in the test suite","B. The degree to which test coverage items have been exercised by tests","C. The percentage of requirements that are tested","D. The amount of time spent on testing"],answer:1,explanation:"Test coverage is the degree to which defined coverage items (requirements, branches, states) have been exercised."},
{id:301,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"Which of the following BEST describes an equivalence class?",options:["A. A single test input value","B. A set of input values that are all expected to be processed the same way","C. A group of related test cases","D. A range of invalid inputs"],answer:1,explanation:"An equivalence class (partition) is a set of values expected to trigger the same system behavior."},
{id:302,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"hard",question:"A code path can only be reached under exceptional conditions that never occur in practice. Should this path be tested?",options:["A. No, testing unreachable paths wastes resources","B. Yes, it should always be tested for completeness","C. It depends on the risk â€” if the exceptional condition could have security implications, yes","D. Only if the customer requests it"],answer:2,explanation:"Risk-based decisions guide coverage â€” potentially security-relevant paths should be tested even if rare."},
{id:303,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"hard",question:"In a decision table, which column represents a specific combination of conditions and the resulting action?",options:["A. A stub","B. A rule","C. A condition","D. An action row"],answer:1,explanation:"Each column in a decision table (excluding condition/action stubs) represents a rule â€” a specific combination and its outcome."},
{id:304,chapter:"Test Analysis and Design",topic:"Collaboration Approaches",difficulty:"medium",question:"In which Agile event are acceptance criteria typically refined and agreed upon by the Three Amigos?",options:["A. Sprint retrospective","B. Sprint review","C. Backlog refinement or Three Amigos session","D. Daily stand-up"],answer:2,explanation:"Backlog refinement and Three Amigos sessions are where acceptance criteria are clarified before development."},
{id:305,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"extreme",question:"A traffic light controller has states: Red, Red-Amber, Green, Amber. From Green, the only valid transition is to Amber. A test tries to transition directly from Green to Red. This is:",options:["A. A valid transition test","B. An invalid transition test","C. A state coverage test","D. A boundary value test"],answer:1,explanation:"Testing an undefined/impossible transition (Green -> Red directly) is an invalid transition test."},
{id:306,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"medium",question:"Which white-box technique is MOST commonly required for safety-critical avionics software (DO-178C)?",options:["A. Statement coverage","B. Branch coverage","C. Modified Condition/Decision Coverage (MC/DC)","D. Path coverage"],answer:2,explanation:"DO-178C Level A software requires MC/DC â€” the most rigorous condition coverage criterion."},
{id:307,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"Use case testing focuses PRIMARILY on:",options:["A. Internal code logic","B. User interactions and end-to-end scenarios","C. Database table structures","D. API response codes"],answer:1,explanation:"Use case testing validates the user interactions and end-to-end scenarios described in use cases."},
{id:308,chapter:"Test Analysis and Design",topic:"Test Conditions",difficulty:"hard",question:"Which of the following BEST describes the purpose of test design?",options:["A. To write test automation scripts","B. To specify test conditions and test cases that will effectively cover the test object","C. To schedule test execution","D. To define entry and exit criteria"],answer:1,explanation:"Test design specifies what to test (conditions) and how to test it (test cases) to achieve coverage objectives."},
{id:309,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"easy",question:"Boundary value analysis is based on the principle that:",options:["A. All input values are equally likely to cause defects","B. Defects tend to occur at the boundaries between partitions","C. Only extreme values should be tested","D. Boundary values are always valid inputs"],answer:1,explanation:"BVA is based on the observation that defects are more likely at the edges (boundaries) of input ranges."},
{id:310,chapter:"Test Analysis and Design",topic:"Experience-based Techniques",difficulty:"hard",question:"Which of the following BEST describes the difference between error guessing and exploratory testing?",options:["A. Error guessing is structured; exploratory testing is unstructured","B. Error guessing targets specific predicted defects; exploratory testing simultaneously explores and learns","C. Error guessing uses checklists; exploratory testing uses test scripts","D. They are the same technique with different names"],answer:1,explanation:"Error guessing targets known failure types; exploratory testing is dynamic learning-driven investigation."},

{id:311,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"Which statement about equivalence partitioning is CORRECT?",options:["A. One test case per partition is sufficient to verify all values in that partition","B. All values in a partition must be tested","C. Invalid partitions never need to be tested","D. EP requires at least 3 tests per partition"],answer:0,explanation:"The premise of EP is that one representative value from a partition covers all values in that partition."},
{id:312,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"medium",question:"If a test suite achieves 100% branch coverage, what can be concluded?",options:["A. All defects have been found","B. Every decision in the code was tested for both true and false outcomes","C. Every statement was executed","D. Both B and C are correct"],answer:3,explanation:"100% branch coverage means every decision outcome AND every statement has been executed (branch subsumes statement)."},
{id:313,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"hard",question:"An input field accepts values between 1 and 100 inclusive. Using 2-value BVA, the test values are:",options:["A. 1, 100","B. 0, 1, 100, 101","C. 1, 50, 100","D. 0, 1, 2, 99, 100, 101"],answer:1,explanation:"2-value BVA tests the boundary value and the value just outside: 0 (invalid), 1 (valid), 100 (valid), 101 (invalid)."},
{id:314,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"A shopping cart gives free shipping for orders of $50 or more. The relevant boundary values using 2-value BVA are:",options:["A. $49, $50","B. $49.99, $50.00","C. $49, $50, $51","D. $0, $50, $100"],answer:0,explanation:"2-value BVA: $49 (just below boundary - no free shipping) and $50 (at boundary - free shipping)."},
{id:315,chapter:"Test Analysis and Design",topic:"Experience-based Techniques",difficulty:"medium",question:"Which of the following is a key advantage of exploratory testing?",options:["A. It produces reproducible, scripted tests","B. It finds unexpected defects that scripted tests might miss through creative investigation","C. It always achieves 100% requirement coverage","D. It replaces the need for formal test design"],answer:1,explanation:"Exploratory testing's strength is finding unanticipated defects through creative, unscripted investigation."},
{id:316,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"easy",question:"Which test technique divides input data into valid and invalid groups?",options:["A. Boundary value analysis","B. State transition testing","C. Equivalence partitioning","D. Decision table testing"],answer:2,explanation:"Equivalence partitioning divides inputs into valid and invalid partitions."},
{id:317,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"hard",question:"A system applies rules based on TWO independent conditions, each binary. Collapsing 'don't care' entries, the MINIMUM number of test cases in a decision table is:",options:["A. 2","B. 3","C. 4","D. 8"],answer:2,explanation:"Without simplification, 2 binary conditions = 4 rules; with 'don't cares' it may collapse, but minimum is context-dependent."},
{id:318,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"hard",question:"Condition coverage is STRONGER than branch coverage because:",options:["A. It requires every individual sub-condition to evaluate to both true and false","B. It requires all paths to be tested","C. It is always equivalent to MC/DC","D. It requires all statements to execute"],answer:0,explanation:"Condition coverage checks each individual condition in a compound expression, while branch coverage only checks the decision outcome."},
{id:319,chapter:"Test Analysis and Design",topic:"Test Conditions",difficulty:"medium",question:"What information is needed to define a test case?",options:["A. Only the test inputs","B. Test inputs, preconditions, expected results, and postconditions","C. Only the expected results","D. The test execution log"],answer:1,explanation:"A complete test case includes preconditions, test inputs/steps, expected results, and postconditions."},
{id:320,chapter:"Test Analysis and Design",topic:"Collaboration Approaches",difficulty:"hard",question:"What is the purpose of a 'Definition of Ready' in Agile testing?",options:["A. To define when a sprint is complete","B. To specify the criteria a user story must meet before it can be included in a sprint","C. To define acceptance criteria for release","D. To specify testing entry criteria"],answer:1,explanation:"Definition of Ready ensures user stories are sufficiently defined (including testable acceptance criteria) before sprint planning."},
{id:321,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"extreme",question:"A system has 4 conditions each with 3 possible values. A FULL combination decision table has how many rules?",options:["A. 12","B. 27","C. 64","D. 81"],answer:3,explanation:"With 4 conditions each having 3 values: 3^4 = 81 rules. This is why collapsed tables with don't-care entries are used."},
{id:322,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"extreme",question:"A function has a loop that executes 0 to N times. To test boundary cases of the loop, the MINIMUM test values for loop count are:",options:["A. N only","B. 0 and N","C. 0, 1, and N","D. 0, 1, 2, N-1, and N"],answer:2,explanation:"Loop boundary testing: 0 iterations (never executes), 1 iteration (minimal), and N (maximum) at minimum."},
{id:323,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"Testing the 'basic flow' in use case testing covers:",options:["A. All exception scenarios","B. The most common successful scenario from start to end","C. All alternate paths","D. Invalid inputs and error handling"],answer:1,explanation:"The basic flow (happy path) is the most common, successful path through the use case."},
{id:324,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"hard",question:"Testing 'alternative flows' in use case testing covers:",options:["A. Only the main success scenario","B. Variations and exceptions to the basic flow, including error handling","C. Only invalid inputs","D. Performance under load"],answer:1,explanation:"Alternative flows cover variations from the happy path, including exception handling and alternate routes."},
{id:325,chapter:"Test Analysis and Design",topic:"Experience-based Techniques",difficulty:"hard",question:"Which of the following BEST describes the benefit of using checklists in testing?",options:["A. They guarantee complete coverage","B. They provide a structured reminder of items to verify based on experience","C. They automate test execution","D. They replace test cases for exploratory testing"],answer:1,explanation:"Checklists provide a structured, experience-based guide ensuring important items are not overlooked."},
{id:326,chapter:"Test Analysis and Design",topic:"Test Conditions",difficulty:"hard",question:"When can test analysis be considered complete?",options:["A. When all test cases are written","B. When all test conditions have been identified and linked to the test basis","C. When the test plan is approved","D. When the first test is executed"],answer:1,explanation:"Test analysis is complete when all test conditions have been identified and traced to the test basis."},
{id:327,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"extreme",question:"A heating system has 3 states: Off, Heating, and Cooling. From Off, it can go to Heating or Cooling. From Heating, it can only go to Off. From Cooling, it can only go to Off. How many valid transitions exist?",options:["A. 3","B. 4","C. 6","D. 9"],answer:1,explanation:"Valid transitions: Off->Heating, Off->Cooling, Heating->Off, Cooling->Off = 4 valid transitions."},
{id:328,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"medium",question:"Which of the following is NOT a white-box test design technique?",options:["A. Statement coverage","B. Branch coverage","C. Path coverage","D. Boundary value analysis"],answer:3,explanation:"Boundary value analysis is a black-box technique based on specifications, not internal code structure."},
{id:329,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"Which technique is BEST for testing a vending machine's response to coin inputs?",options:["A. Equivalence partitioning","B. State transition testing","C. Decision table testing","D. Use case testing"],answer:1,explanation:"A vending machine has clear states (idle, selecting, dispensing) with transitions based on inputs â€” state transition testing fits."},
{id:330,chapter:"Test Analysis and Design",topic:"Test Conditions",difficulty:"extreme",question:"A tester derives 50 test conditions from a requirements document containing 25 requirements. Each condition is traced to exactly one requirement. What percentage of requirements have at least one test condition?",options:["A. 50%","B. Impossible to determine from the information given","C. 100%","D. 200%"],answer:1,explanation:"We know 50 conditions map to 25 requirements, but we don't know if all 25 requirements are covered â€” some may have 2+ conditions while others have none."},
{id:331,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"Which of the following BEST describes when you would choose decision table testing over equivalence partitioning?",options:["A. When testing a field with a simple valid/invalid range","B. When the system's behavior depends on specific combinations of multiple conditions","C. When testing sequential states of a system","D. When testing performance under load"],answer:1,explanation:"Decision tables excel when behavior is determined by combinations of multiple conditions â€” complex business rules."},
{id:332,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"hard",question:"A test achieves 75% statement coverage. Which statement is MOST accurate?",options:["A. 75% of requirements are tested","B. 25% of executable statements were never executed","C. 75% of branches were covered","D. The software is 75% defect-free"],answer:1,explanation:"75% statement coverage means 25% of executable statements were never reached during testing."},
{id:333,chapter:"Test Analysis and Design",topic:"Experience-based Techniques",difficulty:"medium",question:"During exploratory testing, a tester notices an unusual system response and decides to investigate it further. This demonstrates which key aspect of exploratory testing?",options:["A. Following a scripted test procedure","B. Learning and adapting the test approach based on what is discovered during testing","C. Achieving 100% code coverage","D. Reporting defects without investigating further"],answer:1,explanation:"Exploratory testing involves learning and adapting â€” investigating unexpected findings is a core characteristic."},
{id:334,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"hard",question:"A form requires a user to enter a date in the format MM/DD/YYYY. Which input would be in an INVALID equivalence partition?",options:["A. 01/15/2024","B. 12/31/1999","C. 13/01/2024","D. 07/04/2023"],answer:2,explanation:"13/01/2024 has an invalid month (13) â€” it belongs to the invalid equivalence partition."},
{id:335,chapter:"Test Analysis and Design",topic:"Collaboration Approaches",difficulty:"extreme",question:"A product owner, developer, and tester meet before a sprint to clarify a user story and define acceptance criteria. During this session, they discover the story is ambiguous. This is MOST beneficial because:",options:["A. It delays the sprint planning","B. The ambiguity is resolved before development starts, preventing defects from being coded","C. It gives the tester time to write test cases","D. It allows the product owner to reprioritize the backlog"],answer:1,explanation:"Finding ambiguities before development (shift-left) prevents defects from being built in â€” a key benefit of Three Amigos collaboration."},
{id:336,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"easy",question:"Which of the following statements about white-box testing is TRUE?",options:["A. White-box testing can be performed without access to the source code","B. White-box testing is based on knowledge of the internal structure of the software","C. White-box testing only applies to unit testing","D. White-box testing always achieves 100% coverage"],answer:1,explanation:"White-box testing requires knowledge of the internal code structure to design tests."},
{id:337,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"Which of the following is a TRUE statement about equivalence partitions?",options:["A. Partitions must always be of equal size","B. A value can belong to multiple partitions","C. Testing one value from a partition is generally as good as testing all values in it","D. Partitions only apply to numeric data"],answer:2,explanation:"The fundamental premise of EP: any value in a partition is equivalent for testing purposes â€” one test covers all."},
{id:338,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"extreme",question:"An insurance system applies different rules based on: age (under 25, 25-60, over 60) and driving history (clean, one minor, two or more). How many equivalence partitions exist for this combination?",options:["A. 5","B. 6","C. 9","D. 12"],answer:2,explanation:"3 age partitions x 3 driving history partitions = 9 combined partitions."},
{id:339,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"extreme",question:"A developer has written a function with 5 linearly independent paths. What is the minimum number of test cases needed to achieve path coverage?",options:["A. 1","B. 3","C. 5","D. 10"],answer:2,explanation:"Path coverage requires each independent path to be exercised â€” 5 independent paths need at least 5 test cases."},
{id:340,chapter:"Test Analysis and Design",topic:"Test Conditions",difficulty:"medium",question:"Which type of coverage metric is most commonly used to measure test completeness at the acceptance test level?",options:["A. Statement coverage","B. Branch coverage","C. Requirements coverage","D. Condition coverage"],answer:2,explanation:"At acceptance testing level, coverage is typically measured against requirements (requirements coverage)."},
{id:341,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"Which of the following is a typical test for the 'alternative/exception flow' in use case testing?",options:["A. Entering valid data and completing the transaction successfully","B. Entering invalid data and verifying the appropriate error message is shown","C. Measuring system response time","D. Verifying code logic"],answer:1,explanation:"Exception flows test what happens when things go wrong â€” invalid inputs, errors, and exceptional conditions."},
{id:342,chapter:"Test Analysis and Design",topic:"Experience-based Techniques",difficulty:"hard",question:"Why might a team combine exploratory testing with scripted testing rather than using only one approach?",options:["A. Scripted testing covers all scenarios, making exploratory testing redundant","B. Exploratory testing finds unexpected issues while scripted testing ensures systematic coverage","C. Exploratory testing is cheaper, so it should replace scripted testing","D. Scripted testing covers non-functional aspects; exploratory testing covers functional"],answer:1,explanation:"The two approaches are complementary â€” scripted for systematic coverage, exploratory for finding unanticipated defects."},
{id:343,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"In state transition testing, the 'all transitions' coverage criterion requires:",options:["A. All states are visited","B. All valid transitions are traversed once","C. All invalid transitions are tested","D. All possible sequences of transitions are tested"],answer:1,explanation:"All-transitions (0-switch) coverage requires each valid transition to be exercised at least once."},
{id:344,chapter:"Test Analysis and Design",topic:"Test Conditions",difficulty:"hard",question:"A test charter says: 'Explore the checkout process focusing on edge cases in shipping address validation.' This is an example of a test charter used in which technique?",options:["A. Scripted testing","B. Session-based exploratory testing","C. Decision table testing","D. User acceptance testing"],answer:1,explanation:"A test charter defining a focused exploration mission is used in session-based exploratory testing."},
{id:345,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"medium",question:"Which of the following BEST describes the purpose of code coverage analysis?",options:["A. To identify which test cases are most important","B. To measure which portions of the code have been exercised by tests","C. To detect security vulnerabilities in code","D. To measure system performance"],answer:1,explanation:"Code coverage measures which parts of the source code have been exercised by the existing test suite."},
{id:346,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"hard",question:"A pay calculation has rules: base pay for 40 hours, overtime (1.5x) for 41-60 hours, double time (2x) for over 60 hours. The decision table should have how many rules?",options:["A. 2","B. 3","C. 4","D. 6"],answer:1,explanation:"There are 3 conditions/categories (<=40h, 41-60h, >60h) = 3 rules in the decision table."},
{id:347,chapter:"Test Analysis and Design",topic:"Experience-based Techniques",difficulty:"extreme",question:"A tester is performing exploratory testing on a payment system. They find a defect in discount calculation. They immediately explore related areas like coupon stacking and refunds. This BEST illustrates:",options:["A. Lack of discipline in testing","B. Defect clustering applied through exploratory testing to find related defects","C. Random testing without a plan","D. Violation of test procedure"],answer:1,explanation:"Defects tend to cluster; exploring related areas after finding a defect is a smart exploratory strategy."},
{id:348,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"In equivalence partitioning, which of the following BEST describes an invalid partition?",options:["A. Values that the system should reject or handle as errors","B. Values that the system accepts but processes incorrectly","C. Values outside the range of the partition","D. Values that have never been tested before"],answer:0,explanation:"Invalid partitions contain values the system should reject, handle as errors, or are outside the acceptable range."},
{id:349,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"hard",question:"A function has an 'if condition A AND condition B then action X' statement. How many test cases are needed for branch coverage?",options:["A. 1","B. 2","C. 3","D. 4"],answer:1,explanation:"Branch coverage for this decision requires: one test where A AND B is true (action X), one where it is false = 2 tests."},
{id:350,chapter:"Test Analysis and Design",topic:"Test Conditions",difficulty:"easy",question:"Which of the following is an example of a test procedure?",options:["A. A test condition identifying what to test","B. A step-by-step specification of how to execute a test case","C. A list of test coverage items","D. A defect report"],answer:1,explanation:"A test procedure specifies the sequence of actions to execute a test case, step by step."},

{id:351,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"Which black-box technique is MOST useful when the input space is very large?",options:["A. Testing all possible inputs","B. Equivalence partitioning to reduce the input space to representative values","C. White-box testing to focus on code paths","D. Performance testing to handle large inputs"],answer:1,explanation:"EP reduces the large input space by identifying representative partitions â€” one value per partition suffices."},
{id:352,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"medium",question:"Which statement about 100% path coverage is TRUE?",options:["A. It is always achievable for any program","B. It subsumes both branch and statement coverage","C. It is equivalent to 100% branch coverage","D. It is the weakest coverage criterion"],answer:1,explanation:"Path coverage is the strongest structural criterion, subsuming both branch and statement coverage."},
{id:353,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"easy",question:"Which test technique is MOST appropriate for a system that changes behavior depending on past transactions?",options:["A. Equivalence partitioning","B. Boundary value analysis","C. State transition testing","D. Decision table testing"],answer:2,explanation:"Systems with history-dependent behavior have states and transitions â€” state transition testing is ideal."},
{id:354,chapter:"Test Analysis and Design",topic:"Experience-based Techniques",difficulty:"medium",question:"Which of the following is a SUCCESS factor for exploratory testing?",options:["A. Having a fully scripted test suite to follow","B. The tester having good domain knowledge and testing skills","C. Having automated tools execute all exploratory tests","D. Avoiding documentation of findings"],answer:1,explanation:"Effective exploratory testing requires strong domain knowledge, test skills, and the ability to adapt the approach."},
{id:355,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"hard",question:"In a decision table, if the number of conditions is reduced by collapsing 'don't care' entries, what happens to the number of test cases?",options:["A. Increases","B. Stays the same","C. Decreases","D. Doubles"],answer:2,explanation:"Collapsing 'don't care' entries reduces the number of distinct rules, decreasing required test cases."},
{id:356,chapter:"Test Analysis and Design",topic:"Test Conditions",difficulty:"medium",question:"Which of the following BEST describes the purpose of defining test objectives in test design?",options:["A. To determine what resources are needed for testing","B. To specify what qualities or behaviors need to be verified","C. To schedule testing activities","D. To identify who will execute the tests"],answer:1,explanation:"Test objectives define what needs to be verified/validated, guiding the test design process."},
{id:357,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"Testing the system's response to invalid inputs is testing from which partition?",options:["A. Valid partition","B. Boundary partition","C. Invalid partition","D. Error partition"],answer:2,explanation:"Invalid partitions contain inputs the system should handle as errors or reject."},
{id:358,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"extreme",question:"A developer achieves 100% MC/DC coverage. What ADDITIONAL coverage does this guarantee compared to branch coverage alone?",options:["A. All individual conditions in compound decisions affect the outcome independently","B. All paths through the code are tested","C. All statements are covered","D. All state transitions are tested"],answer:0,explanation:"MC/DC additionally guarantees each individual condition in compound decisions independently affects the decision outcome."},
{id:359,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"hard",question:"A web form has 4 optional checkboxes. The number of valid equivalence partitions for combinations of checked boxes is:",options:["A. 4","B. 8","C. 15","D. 16"],answer:3,explanation:"4 binary checkboxes = 2^4 = 16 combinations. Each unique combination is a potential distinct partition."},
{id:360,chapter:"Test Analysis and Design",topic:"Collaboration Approaches",difficulty:"hard",question:"Which of the following BEST describes 'specification by example' in the context of collaborative testing?",options:["A. Writing technical specifications before coding","B. Using concrete examples to clarify requirements and drive development (BDD/ATDD)","C. Specifying test data for automated tests","D. Providing examples in user documentation"],answer:1,explanation:"Specification by example uses concrete scenarios/examples to define requirements, enabling BDD and ATDD."},
{id:361,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"For a numeric field accepting integers 1-10, what is the representative test value for the valid partition in EP?",options:["A. Always 1","B. Always 10","C. Any value between 1 and 10 inclusive","D. The average of the range (5 or 6)"],answer:2,explanation:"Any value within the valid partition is a valid representative â€” typically the middle value is chosen but any works."},
{id:362,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"hard",question:"Cyclomatic complexity of a function equals 7. What does this suggest about testing this function?",options:["A. The function has 7 statements","B. The function has at least 7 independent paths requiring at least 7 tests for path coverage","C. The function has 7 branches","D. The function is 7% covered"],answer:1,explanation:"Cyclomatic complexity = number of independent paths = minimum tests needed for path coverage."},
{id:363,chapter:"Test Analysis and Design",topic:"Experience-based Techniques",difficulty:"easy",question:"Exploratory testing is MOST effective when:",options:["A. Requirements are well-defined and stable","B. The tester is experienced and has domain knowledge","C. Automated tools are available","D. The test environment is fully set up"],answer:1,explanation:"Exploratory testing effectiveness depends heavily on the tester's experience and domain knowledge."},
{id:364,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"A mobile app has 3 screens. Navigating between them follows defined paths. Which technique is BEST for testing navigation?",options:["A. Equivalence partitioning","B. Boundary value analysis","C. State transition testing","D. Decision table testing"],answer:2,explanation:"Screen-to-screen navigation with defined paths is a state machine â€” state transition testing applies."},
{id:365,chapter:"Test Analysis and Design",topic:"Test Conditions",difficulty:"hard",question:"A test analysis produces 30 test conditions for 10 requirements. On average, how many test conditions per requirement?",options:["A. 1","B. 2","C. 3","D. 10"],answer:2,explanation:"30 test conditions / 10 requirements = 3 test conditions per requirement on average."},
{id:366,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"extreme",question:"An order system applies discounts based on: quantity (bulk vs. not), customer type (regular/premium), and coupon (valid/invalid/none). A full decision table has how many rules?",options:["A. 6","B. 8","C. 12","D. 24"],answer:2,explanation:"2 x 2 x 3 = 12 combinations for quantity x customer type x coupon."},
{id:367,chapter:"Test Analysis and Design",topic:"Experience-based Techniques",difficulty:"hard",question:"A tester creates a list of common error types (off-by-one, null inputs, overflow) and systematically designs tests to expose these. This is BEST described as:",options:["A. Exploratory testing","B. Checklist-based testing","C. Fault attack (structured error guessing)","D. State transition testing"],answer:2,explanation:"Systematically using a categorized list of common defect types to design tests is a fault attack."},
{id:368,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"Which of the following is an example of a VALID equivalence partition for a 'gender' field accepting M or F?",options:["A. Null value","B. 'M'","C. 'Male'","D. '1'"],answer:1,explanation:"'M' is a valid input; 'Male', '1', and null are all in various invalid partitions."},
{id:369,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"medium",question:"A test achieves 90% statement coverage. What should a tester do about the uncovered 10%?",options:["A. Nothing â€” 90% is sufficient","B. Investigate why those statements are not covered and assess the risk","C. Delete the uncovered code","D. Automatically generate tests for the remaining 10%"],answer:1,explanation:"Uncovered code should be investigated â€” it may represent dead code, missing tests, or unreachable paths."},
{id:370,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"extreme",question:"A requirements specification says 'the system shall validate the date format.' A tester identifies 6 test conditions. A developer sees only 2 (valid/invalid). This difference illustrates:",options:["A. The developer is correct â€” only 2 partitions exist","B. The tester has identified sub-partitions within invalid inputs (wrong format, future date, Feb 30, etc.)","C. The tester is over-testing","D. Only the developer's view is required for development"],answer:1,explanation:"Invalid partitions can be further sub-divided (e.g., wrong format, impossible dates, past dates) for more thorough testing."},
{id:371,chapter:"Test Analysis and Design",topic:"Test Conditions",difficulty:"medium",question:"What is the relationship between test conditions and test cases?",options:["A. One test condition always results in exactly one test case","B. Multiple test cases can be designed to cover a single test condition","C. Test conditions are only used in exploratory testing","D. Test cases are defined before test conditions"],answer:1,explanation:"One test condition may require multiple test cases to adequately verify it (e.g., valid and invalid scenarios)."},
{id:372,chapter:"Test Analysis and Design",topic:"Collaboration Approaches",difficulty:"medium",question:"In BDD, scenarios written in Given-When-Then format serve as:",options:["A. Project management documentation","B. Executable specifications that serve as both requirements and acceptance tests","C. Database design documents","D. Performance benchmarks"],answer:1,explanation:"BDD scenarios are executable specifications â€” they define behavior AND can be automated as acceptance tests."},
{id:373,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"hard",question:"All-transition-pairs coverage (1-switch coverage) in state transition testing requires:",options:["A. Every individual transition to be traversed","B. Every sequence of two consecutive valid transitions to be tested","C. Every state to be visited","D. All possible paths through the state machine"],answer:1,explanation:"1-switch coverage requires every pair of consecutive transitions to be exercised â€” more thorough than single transitions."},
{id:374,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"medium",question:"Why is 100% code coverage NOT sufficient to ensure software quality?",options:["A. Code coverage tools are inaccurate","B. Coverage only measures which code was executed, not whether the results were verified as correct","C. Coverage tools slow down the software","D. Coverage cannot be measured accurately"],answer:1,explanation:"Executing code doesn't verify correctness â€” a test may cover a statement but not assert the right expected outcome."},
{id:375,chapter:"Test Analysis and Design",topic:"Experience-based Techniques",difficulty:"medium",question:"The main purpose of a test charter in exploratory testing is to:",options:["A. Document every step taken during testing","B. Define the scope and goals of an exploratory test session","C. Replace formal test cases","D. Provide entry criteria for testing"],answer:1,explanation:"A test charter sets the mission and boundaries for an exploratory session, providing focus without over-scripting."},
{id:376,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"easy",question:"State transition testing MOST closely models systems that behave like:",options:["A. A simple calculator function","B. A finite state machine with defined states, events, and transitions","C. A complex algorithm with loops","D. A batch processing system"],answer:1,explanation:"State transition testing is designed for systems that behave as finite state machines."},
{id:377,chapter:"Test Analysis and Design",topic:"Test Conditions",difficulty:"hard",question:"Which of the following is a component of a test case?",options:["A. Test execution log","B. Test completion report","C. Expected result","D. Test metrics"],answer:2,explanation:"A test case includes: test ID, preconditions, inputs/steps, expected results, and postconditions."},
{id:378,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"extreme",question:"In use case testing, the 'post-conditions' section describes:",options:["A. The conditions that must be true before the use case can begin","B. The state of the system after the use case has completed successfully","C. The actor who initiates the use case","D. The exception scenarios"],answer:1,explanation:"Post-conditions describe the system state after the use case completes â€” what should be true at the end."},
{id:379,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"hard",question:"A test suite with 70% branch coverage is being enhanced. The team should focus on:",options:["A. The already covered branches","B. The 30% of branches not yet covered","C. Adding more tests for the most critical already-covered branches","D. Measuring statement coverage instead"],answer:1,explanation:"To improve branch coverage, the team should add tests that exercise the 30% of branches not yet covered."},
{id:380,chapter:"Test Analysis and Design",topic:"Collaboration Approaches",difficulty:"extreme",question:"A team adopts 'living documentation' where BDD scenarios are automatically executed as regression tests and their results published. This BEST represents:",options:["A. A replacement for all manual testing","B. Executable specifications maintaining alignment between requirements, tests, and implementation","C. An informal review process","D. Static analysis of requirements"],answer:1,explanation:"Living documentation keeps requirements and tests synchronized â€” BDD scenarios execute and their results show if behavior is still correct."},

{id:381,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"Which of the following BEST describes the primary advantage of decision table testing?",options:["A. It is simpler than equivalence partitioning","B. It systematically covers all combinations of conditions and their effects","C. It tests the software's internal code paths","D. It reduces the number of test cases needed for boundary testing"],answer:1,explanation:"Decision tables ensure systematic coverage of all condition combinations and their corresponding actions."},
{id:382,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"easy",question:"Which metric measures how much of the source code has been executed by tests?",options:["A. Requirements coverage","B. Code coverage","C. Test coverage","D. Defect density"],answer:1,explanation:"Code coverage metrics measure which portions of source code were executed during testing."},
{id:383,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"hard",question:"A credit card number validation has rules: 16 digits, starts with specific digits by card type. A decision table would MOST effectively test:",options:["A. Individual character inputs","B. Combinations of card type, length, and starting digits","C. Performance of the validation function","D. The database storage of card numbers"],answer:1,explanation:"Decision tables test the combinations of conditions (card type, length, starting digits) that determine validity."},
{id:384,chapter:"Test Analysis and Design",topic:"Experience-based Techniques",difficulty:"extreme",question:"A senior tester uses knowledge of a past project's frequent defects in payment processing to create a targeted fault attack test suite. This BEST illustrates:",options:["A. Test automation","B. Applying historical defect data to improve error guessing effectiveness","C. Regression testing","D. Formal verification"],answer:1,explanation:"Using historical defect data to systematically target likely failures is a powerful form of structured error guessing/fault attack."},
{id:385,chapter:"Test Analysis and Design",topic:"Test Conditions",difficulty:"medium",question:"Risk-based test design prioritizes test conditions by:",options:["A. Alphabetical order","B. Likelihood of failure and impact of failure","C. The order they appear in requirements","D. Developer preference"],answer:1,explanation:"Risk-based testing prioritizes test conditions based on the risk (probability x impact) of potential failures."},
{id:386,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"In a vending machine state diagram: States are [Idle, HasMoney, ItemSelected, Dispensing]. Which state is the initial state?",options:["A. HasMoney","B. ItemSelected","C. Idle","D. Dispensing"],answer:2,explanation:"A vending machine starts in the Idle state before any interaction."},
{id:387,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"hard",question:"A function has no branches but has a loop. 100% statement coverage requires:",options:["A. The loop to never execute","B. The loop to execute exactly once","C. The loop to execute at least once (entering the loop)","D. The loop to execute maximum iterations"],answer:2,explanation:"For statement coverage, all statements including those inside the loop must execute â€” the loop must iterate at least once."},
{id:388,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"easy",question:"In EP, the purpose of testing invalid partitions is to:",options:["A. Verify the system correctly processes invalid inputs","B. Find values that crash the system","C. Achieve 100% code coverage","D. Test performance with invalid data"],answer:0,explanation:"Testing invalid partitions verifies the system handles invalid inputs gracefully (error messages, rejections)."},
{id:389,chapter:"Test Analysis and Design",topic:"Collaboration Approaches",difficulty:"medium",question:"In the 'Three Amigos' process, the 'tester' perspective primarily contributes:",options:["A. Technical architecture decisions","B. Identifying test scenarios, edge cases, and what could go wrong","C. Business priority and ROI analysis","D. Sprint velocity estimation"],answer:1,explanation:"Testers contribute by thinking about what could go wrong, edge cases, and how to verify the story's behavior."},
{id:390,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"hard",question:"When should you apply 3-value BVA instead of 2-value BVA?",options:["A. When precision is more important and defects at boundary-adjacent values are a concern","B. When the system has fewer input ranges","C. When performance testing is needed","D.3-value BVA is always preferred over 2-value BVA"],answer:0,explanation:"3-value BVA (boundary-1, boundary, boundary+1) is more thorough when defects near boundaries need extra coverage."},
{id:391,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"medium",question:"A developer claims their module has 100% statement coverage but there are known defects in it. This is possible because:",options:["A. Statement coverage tools are inaccurate","B. Coverage measures execution, not correctness â€” tests may execute code without asserting correct results","C. Known defects always prevent 100% coverage","D. This is impossible if 100% coverage is achieved"],answer:1,explanation:"Coverage tools measure execution paths, not whether the right results were verified â€” weak assertions miss defects."},
{id:392,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"extreme",question:"For a system that processes loan applications with 5 criteria, each with 2 possible values, the maximum number of decision table rules is 32. However, only 10 are feasible combinations. How many test cases are MINIMALLY required?",options:["A. 32","B. 10","C. 5","D. 2"],answer:1,explanation:"Only feasible (achievable in practice) rule combinations need to be tested â€” 10 feasible rules require 10 test cases."},
{id:393,chapter:"Test Analysis and Design",topic:"Experience-based Techniques",difficulty:"medium",question:"An exploratory test session log documents:",options:["A. Formal test case specifications","B. What was explored, issues found, time spent, and areas covered","C. Code coverage metrics","D. Developer notes on implementation"],answer:1,explanation:"Session notes document the scope, findings, time allocation, and areas covered during the exploratory session."},
{id:394,chapter:"Test Analysis and Design",topic:"Test Conditions",difficulty:"hard",question:"Which of the following BEST describes coverage items in requirements-based testing?",options:["A. Lines of code covered by tests","B. Individual requirements, use cases, or user stories that tests must cover","C. The number of test cases executed","D. Test environment configurations covered"],answer:1,explanation:"In requirements-based testing, coverage items are the individual requirements, use cases, or stories to be covered."},
{id:395,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"Which of the following is NOT an advantage of decision table testing?",options:["A. Systematically covers combinations of conditions","B. Easy to adapt when the number of conditions is very large","C. Clearly shows which conditions lead to which actions","D. Identifies missing requirements by revealing undocumented combinations"],answer:1,explanation:"Decision tables become unwieldy when conditions are numerous (2^N rules) â€” this is a limitation, not an advantage."},
{id:396,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"hard",question:"A function with cyclomatic complexity of 3 has how many independent paths?",options:["A. 1","B. 2","C. 3","D. 6"],answer:2,explanation:"Cyclomatic complexity directly equals the number of independent paths through the code."},
{id:397,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"easy",question:"In state transition testing, an event is BEST described as:",options:["A. A state of the system","B. An input or occurrence that triggers a transition from one state to another","C. The expected output of the system","D. A test case"],answer:1,explanation:"An event (input/trigger) causes a state transition from the current state to a new state."},
{id:398,chapter:"Test Analysis and Design",topic:"Experience-based Techniques",difficulty:"hard",question:"Why might a tester NOT rely SOLELY on exploratory testing for a safety-critical system?",options:["A. Exploratory testing is too slow","B. Safety-critical systems require documented, traceable, and repeatable test evidence","C. Exploratory testing is only for web applications","D. Safety-critical systems do not need exploratory testing"],answer:1,explanation:"Safety-critical systems require documented, repeatable, and auditable tests â€” exploratory testing alone cannot provide this."},
{id:399,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"Testing both the basic flow AND alternative flows of a use case achieves:",options:["A. Only happy-path coverage","B. More comprehensive coverage including normal and exceptional scenarios","C. 100% code coverage","D. Functional and non-functional coverage"],answer:1,explanation:"Testing both basic (happy path) and alternative (exception) flows gives comprehensive use case coverage."},
{id:400,chapter:"Test Analysis and Design",topic:"Test Conditions",difficulty:"extreme",question:"A project has 100 requirements. Test analysis produces 250 test conditions. After test design, 400 test cases are created. An average requirement has how many test cases?",options:["A. 2.5","B. 4","C. 1.6","D. 10"],answer:1,explanation:"400 test cases / 100 requirements = 4 test cases per requirement on average."},
{id:401,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"Which of the following BEST describes the purpose of boundary value analysis?",options:["A. To test all values in an equivalence partition","B. To focus testing on values at the edges of valid and invalid partitions","C. To test the system's response to null values","D. To measure code coverage at boundaries"],answer:1,explanation:"BVA focuses on boundary values where defects are most likely, maximizing defect detection per test."},
{id:402,chapter:"Test Analysis and Design",topic:"Experience-based Techniques",difficulty:"medium",question:"A tester who uses both domain expertise and creative thinking to explore the software is demonstrating which quality?",options:["A. Rigorous scripted testing discipline","B. Effective exploratory testing skill","C. Formal static analysis","D. Performance testing expertise"],answer:1,explanation:"Combining domain knowledge with creative thinking is the hallmark of skilled exploratory testing."},
{id:403,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"medium",question:"Which coverage criterion is MOST appropriate for embedded safety-critical software per DO-178C Level A?",options:["A. Statement coverage","B. Branch coverage","C. MC/DC","D. Path coverage"],answer:2,explanation:"DO-178C Level A (highest criticality) requires MC/DC coverage â€” the most rigorous structural criterion."},
{id:404,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"hard",question:"A state machine test that covers all valid transitions is called:",options:["A. 0-switch coverage","B. 1-switch coverage","C. All-states coverage","D. N-switch coverage"],answer:0,explanation:"0-switch (all transitions) coverage tests each valid transition individually at least once."},
{id:405,chapter:"Test Analysis and Design",topic:"Test Conditions",difficulty:"medium",question:"Which of the following BEST demonstrates the use of traceability in test design?",options:["A. Linking each test case to the requirement(s) it verifies","B. Tracking defects in a defect management system","C. Measuring code coverage after test execution","D. Comparing actual and expected results"],answer:0,explanation:"Traceability links test cases to requirements, ensuring coverage and supporting impact analysis."},
{id:406,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"extreme",question:"A financial system has different tax rates for income brackets: 0-10k (0%), 10k-40k (15%), 40k-80k (25%), >80k (32%). How many valid and invalid equivalence partitions exist?",options:["A. 4 valid, 2 invalid","B. 4 valid, 1 invalid","C. 4 valid, 3 invalid","D. 4 valid, 4 invalid"],answer:0,explanation:"4 valid income brackets + below 0 (invalid income) and above max (well, >80k is valid) = 4 valid, 2 invalid (negative, and the question of non-numeric). Typical answer: 4 valid, 2 invalid (below 0, non-numeric)."},
{id:407,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"hard",question:"A team is testing an e-commerce checkout process with complex discount logic. The cyclomatic complexity is 15. What does this indicate?",options:["A. The function has 15 statements","B. At least 15 independent paths exist and path coverage is likely impractical","C. 15 test cases will always achieve 100% coverage","D. The function has exactly 15 branches"],answer:1,explanation:"Cyclomatic complexity of 15 means 15 independent paths â€” high complexity suggesting path coverage may be impractical."},
{id:408,chapter:"Test Analysis and Design",topic:"Collaboration Approaches",difficulty:"easy",question:"In Agile testing, which of the following is MOST associated with ensuring testability of user stories?",options:["A. Sprint retrospective","B. Clear, measurable acceptance criteria","C. Continuous integration","D. Test automation framework"],answer:1,explanation:"Clear, measurable acceptance criteria make user stories testable and define the conditions for acceptance."},
{id:409,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"The concept of a 'decision table stub' refers to:",options:["A. A placeholder for missing actions","B. The left column(s) containing conditions and actions","C. A column representing a specific rule combination","D. An automated test script"],answer:1,explanation:"The stub is the left portion of a decision table containing condition names and action names."},
{id:410,chapter:"Test Analysis and Design",topic:"Experience-based Techniques",difficulty:"extreme",question:"A test team uses AI-assisted exploratory testing tools that suggest next test actions based on observed system behavior. This BEST represents:",options:["A. Static analysis","B. Augmented exploratory testing using intelligent test guidance","C. Scripted test automation","D. Model-based testing"],answer:1,explanation:"AI-assisted tools that guide exploratory testing based on observed behavior are a form of augmented exploratory testing."},

{id:411,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"easy",question:"Which of the following BEST describes a 'test oracle'?",options:["A. An expert tester who validates test results","B. A source providing expected results for comparison with actual results","C. A testing tool that generates test cases","D. A document containing test procedures"],answer:1,explanation:"A test oracle provides the expected outcomes against which actual test results are compared."},
{id:412,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"medium",question:"A function has 3 if statements in sequence (not nested). The minimum number of tests for 100% branch coverage is:",options:["A. 2","B. 3","C. 4","D. 6"],answer:0,explanation:"For 3 sequential if statements each with true/false paths, 2 tests can cover all branches if paths are independent."},
{id:413,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"Which of the following inputs belongs to an invalid equivalence partition for a percentage field (0-100)?",options:["A. 0","B. 50","C. 100","D. 101"],answer:3,explanation:"101 is above the valid range (0-100), placing it in the invalid partition above the upper boundary."},
{id:414,chapter:"Test Analysis and Design",topic:"Experience-based Techniques",difficulty:"hard",question:"A tester who 'follows their nose' when something seems suspicious and digs deeper is demonstrating:",options:["A. Poor test discipline","B. Effective exploratory testing through curiosity","C. Deviation from the test plan","D. Scope creep"],answer:1,explanation:"Investigating suspicious areas is a core exploratory testing skill â€” curiosity drives defect discovery."},
{id:415,chapter:"Test Analysis and Design",topic:"Test Conditions",difficulty:"hard",question:"A test condition derived from a non-functional requirement would include:",options:["A. Verifying a button redirects to the correct page","B. Verifying response time is under 2 seconds for 1000 concurrent users","C. Verifying the login form accepts valid credentials","D. Verifying error messages display correctly"],answer:1,explanation:"Non-functional test conditions relate to quality attributes like performance, security, and usability."},
{id:416,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"extreme",question:"For a system with 5 binary conditions, collapsing all 'don't care' combinations results in a minimum decision table size. If 8 rules can be collapsed to 3 due to 'don't cares', what is the MINIMUM test count?",options:["A. 32","B. 8","C. 3","D. 5"],answer:2,explanation:"After collapsing don't-care combinations, only 3 distinct rules remain â€” requiring only 3 test cases."},
{id:417,chapter:"Test Analysis and Design",topic:"Collaboration Approaches",difficulty:"hard",question:"In a Three Amigos session, who provides the perspective on HOW to test the story?",options:["A. Business representative","B. Developer","C. Tester","D. Product owner"],answer:2,explanation:"The tester in Three Amigos provides the testing perspective â€” how to verify the story, edge cases, and what could fail."},
{id:418,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"A test case for the basic flow of a use case verifies:",options:["A. Error handling when invalid data is entered","B. The normal, successful completion of the use case scenario","C. System performance under load","D. Security access controls"],answer:1,explanation:"The basic flow test verifies the most common successful scenario (happy path) of the use case."},
{id:419,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"medium",question:"Which of the following is FALSE about white-box testing?",options:["A. It can only be performed on the source code","B. It requires knowledge of the internal structure","C. It can be used to measure code coverage","D. It can be applied to test designs and architecture"],answer:0,explanation:"White-box techniques can be applied to any structural artifact (design, architecture, code) â€” not just source code."},
{id:420,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"extreme",question:"A string field has constraints: 1-50 chars, no special characters, starts with a letter. Which of the following test cases would be MOST likely to find defects?",options:["A. A 25-character all-letter string","B. A 51-character string","C. An empty string","D. All of B, C, and a string starting with a number"],answer:3,explanation:"Testing boundary violations (too long), empty string (below minimum), and violated format rules covers multiple failure modes."},
{id:421,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"The term 'test coverage' in black-box testing MOST commonly refers to:",options:["A. The percentage of code lines executed","B. The percentage of requirements or test conditions covered by tests","C. The number of defects found","D. The amount of time spent testing"],answer:1,explanation:"Black-box test coverage measures how many requirements, use cases, or test conditions have been covered."},
{id:422,chapter:"Test Analysis and Design",topic:"Experience-based Techniques",difficulty:"medium",question:"Which of the following is an example of a checklist-based test?",options:["A. Testing all boundary values of an input field","B. Working through a predefined list of common security vulnerabilities to check","C. Testing state transitions in a state machine","D. Designing tests from use cases"],answer:1,explanation:"Checking against a list of known security vulnerabilities is classic checklist-based testing."},
{id:423,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"hard",question:"A test achieves 100% statement coverage but misses a defect in an uncovered branch. Why is this possible?",options:["A. Statement coverage guarantees branch coverage","B. A branch can be missed even when all statements are covered â€” a branch may go untested","C. The defect must be in dead code","D. 100% statement coverage always finds all defects"],answer:1,explanation:"Statement coverage can be 100% even with uncovered branches â€” all-true or all-false paths may cover all statements."},
{id:424,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"hard",question:"In EP, testing only the mid-point of each partition is acceptable because:",options:["A. Mid-points are most likely to cause defects","B. Any representative value in a partition is equivalent for testing purposes","C. Mid-point testing is required by the ISTQB standard","D. Only mid-points are valid test values"],answer:1,explanation:"EP states any value in a partition is functionally equivalent â€” the choice of representative value is arbitrary."},
{id:425,chapter:"Test Analysis and Design",topic:"Test Conditions",difficulty:"easy",question:"What does 'coverage' measure in testing?",options:["A. The speed of test execution","B. The extent to which defined coverage items have been exercised","C. The number of defects found","D. The experience level of testers"],answer:1,explanation:"Coverage measures the extent to which defined test items (requirements, branches, etc.) have been tested."},
{id:426,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"An authentication system has a session timeout of 30 minutes. Relevant test values using BVA include:",options:["A. 29 minutes, 30 minutes, 31 minutes","B. 15 minutes only","C. 30 minutes only","D. 1 minute and 60 minutes"],answer:0,explanation:"BVA tests near the boundary: 29 min (should still be active), 30 min (boundary â€” timeout), 31 min (should be timed out)."},
{id:427,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"medium",question:"Which of the following correctly describes the relationship between the coverage criteria from WEAKEST to STRONGEST?",options:["A. Statement < Branch < Path","B. Branch < Statement < Path","C. Path < Branch < Statement","D. Statement < Path < Branch"],answer:0,explanation:"Statement coverage is weakest, branch coverage subsumes it, and path coverage is strongest (subsumes branch)."},
{id:428,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"hard",question:"Decision table testing and equivalence partitioning are MOST different in that:",options:["A. Decision tables test single conditions; EP tests combinations","B. EP handles single input partitions; decision tables handle combinations of multiple conditions","C. EP uses code knowledge; decision tables use specifications","D. Decision tables are for non-functional testing; EP is for functional testing"],answer:1,explanation:"EP partitions single inputs; decision tables handle the combinational logic of multiple conditions simultaneously."},
{id:429,chapter:"Test Analysis and Design",topic:"Experience-based Techniques",difficulty:"extreme",question:"A company is releasing a new payment feature on Black Friday. The team has limited time for testing. Using error guessing, which areas should be PRIORITIZED?",options:["A. All areas equally","B. Areas historically prone to defects: calculation logic, concurrency under load, transaction rollback","C. Only the new feature, ignoring existing code","D. User interface elements exclusively"],answer:1,explanation:"Error guessing with historical data prioritizes known high-risk areas â€” calculation logic, concurrency, and transactional integrity are classic payment failure points."},
{id:430,chapter:"Test Analysis and Design",topic:"Test Conditions",difficulty:"hard",question:"Which of the following is the MOST important characteristic of a test condition?",options:["A. It must be executable as a single test case","B. It must be unambiguous and traceable to a test basis item","C. It must cover at least 3 test cases","D. It must be based on code coverage"],answer:1,explanation:"Test conditions must be unambiguous (clear what to test) and traceable to requirements or design artifacts."},
{id:431,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"easy",question:"Which of the following would be an appropriate equivalence partition for a field that accepts only positive integers?",options:["A. Negative integers","B. Decimal numbers","C. 0","D. All of A, B, and C are invalid partitions"],answer:3,explanation:"Negative integers, decimals, and zero are all invalid partitions for a 'positive integers only' field."},
{id:432,chapter:"Test Analysis and Design",topic:"Collaboration Approaches",difficulty:"medium",question:"The INVEST criteria for user stories includes 'Testable'. This means:",options:["A. The story can be automated","B. There are clear acceptance criteria that allow testing to determine if the story is done","C. Performance tests can be run","D. The story has been reviewed by the test team"],answer:1,explanation:"'Testable' means the story has clear, observable acceptance criteria â€” you can test whether it's complete."},
{id:433,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"hard",question:"Branch/Decision coverage requires which of the following?",options:["A. Every statement to execute","B. Every branch (both true and false outcomes) of every decision to be exercised","C. Every path through the code to be traversed","D. Every condition to evaluate to true and false independently"],answer:1,explanation:"Branch coverage requires each branch (true/false) of every decision to be exercised by at least one test."},
{id:434,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"extreme",question:"A tester applies equivalence partitioning to a field with the rule: 'must be a whole number from 1 to 999 with no leading zeros.' How many equivalence partitions are there?",options:["A. 2 (valid and invalid)","B. 3 (valid: 1-999; invalid: <=0; invalid: >=1000)","C. 4 (valid; negative; zero; >999; and leading zeros or non-numeric)","D. 5+"],answer:3,explanation:"The field has multiple invalid partitions: <=0, >=1000, leading zeros (like '007'), and non-numeric â€” making 5+ partitions."},
{id:435,chapter:"Test Analysis and Design",topic:"Experience-based Techniques",difficulty:"medium",question:"Time-boxing an exploratory test session to 90 minutes is useful because:",options:["A. It ensures all tests are executed","B. It provides a defined, focused period for exploration with a debrief afterward","C. It limits the tester to pre-defined areas","D. It guarantees complete requirement coverage"],answer:1,explanation:"Time-boxing creates a structured exploration period with a clear end point, followed by a debrief."},
{id:436,chapter:"Test Analysis and Design",topic:"Test Conditions",difficulty:"medium",question:"Which of the following BEST describes a high-level test condition?",options:["A. A detailed test step in a test script","B. A general aspect of the system's behavior that needs to be tested","C. A specific expected result","D. A list of test data values"],answer:1,explanation:"High-level test conditions are general aspects (e.g., 'login functionality') refined into detailed test cases."},
{id:437,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"hard",question:"A test condition for an ATM system: 'Verify card is blocked after 3 incorrect PIN entries.' This condition leads to MINIMUM how many test cases?",options:["A. 1","B. 2","C. 3","D. 4"],answer:2,explanation:"At minimum 3 tests: 1st wrong PIN (not blocked), 2nd wrong PIN (not blocked), 3rd wrong PIN (blocked)."},
{id:438,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"medium",question:"When using white-box techniques, the test basis is:",options:["A. Business requirements","B. Source code, design, and architecture","C. User stories","D. Acceptance criteria"],answer:1,explanation:"White-box testing uses the internal structure (code, design, architecture) as its test basis."},
{id:439,chapter:"Test Analysis and Design",topic:"Collaboration Approaches",difficulty:"hard",question:"During a Three Amigos session, the developer argues that a story is too complex to estimate. What should the tester suggest?",options:["A. Skip testing this story","B. Break the story into smaller, testable stories","C. Increase the sprint capacity","D. Estimate the testing time separately"],answer:1,explanation:"Complex stories should be broken down into smaller, independently testable stories â€” a key Agile practice."},
{id:440,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"Which of the following is an example of a VALID partition for a password field requiring 8-16 characters?",options:["A. A 7-character password","B. A 17-character password","C. A 12-character password","D. An empty password"],answer:2,explanation:"12 characters is within the valid range (8-16), making it part of the valid equivalence partition."},
{id:441,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"extreme",question:"A system has a complex condition: if (A and B) or (C and D). For MC/DC, the minimum number of tests is:",options:["A. 2","B. 4","C. 5","D. 16"],answer:2,explanation:"MC/DC for 4 conditions requires N+1 = 4+1 = 5 tests, demonstrating each condition independently affects the outcome."},
{id:442,chapter:"Test Analysis and Design",topic:"Experience-based Techniques",difficulty:"medium",question:"What distinguishes a 'fault attack' from general error guessing?",options:["A. Fault attacks are always automated","B. Fault attacks use a structured, categorized list of common failure types","C. Error guessing uses more domain knowledge","D. They are identical techniques"],answer:1,explanation:"Fault attacks are a more structured form of error guessing, using categorized defect taxonomies/checklists."},
{id:443,chapter:"Test Analysis and Design",topic:"Test Conditions",difficulty:"hard",question:"A test condition identified during test analysis says 'Verify the system handles null inputs.' This is BEST described as:",options:["A. A test case","B. A test procedure","C. A high-level test condition","D. A test script"],answer:2,explanation:"'Verify the system handles null inputs' is a general test condition, not yet a specific test case."},
{id:444,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"extreme",question:"A software requirement states: 'The system shall process orders for quantities between 1 and 9999.' A tester applies 3-value BVA. What are the test values?",options:["A. 0, 1, 2, 9998, 9999, 10000","B. 1, 9999","C. 0, 1, 9999, 10000","D. 1, 5000, 9999"],answer:0,explanation:"3-value BVA at lower boundary: 0,1,2 and at upper boundary: 9998,9999,10000 = 6 test values."},
{id:445,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"hard",question:"Why is path coverage considered impractical for most real-world programs?",options:["A. Path coverage tools are expensive","B. Programs with loops and complex logic can have an infinite or astronomically large number of paths","C. Path coverage only works for safety-critical software","D. Path coverage does not improve defect detection"],answer:1,explanation:"Loops create exponential or infinite paths â€” making full path coverage computationally infeasible."},
{id:446,chapter:"Test Analysis and Design",topic:"Collaboration Approaches",difficulty:"medium",question:"Which of the following is NOT a typical output of a Three Amigos session?",options:["A. Refined acceptance criteria","B. Shared understanding of the user story","C. Identified test scenarios and edge cases","D. Sprint velocity report"],answer:3,explanation:"Sprint velocity reports are a Scrum metric â€” not an output of Three Amigos story refinement sessions."},
{id:447,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"In state transition testing, a 'guard condition' is:",options:["A. A condition that prevents a transition from occurring","B. A security check on the system","C. A protection mechanism against invalid inputs","D. An entry criterion for testing"],answer:0,explanation:"A guard condition is a condition that must be true for a transition to fire â€” it restricts when transitions can occur."},
{id:448,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"medium",question:"What is the PRIMARY reason to perform white-box testing in addition to black-box testing?",options:["A. White-box testing is cheaper","B. Black-box testing cannot achieve sufficient code coverage without structural knowledge","C. White-box testing verifies that untested code paths exist and can be exercised","D. White-box testing replaces black-box testing"],answer:2,explanation:"White-box testing reveals and exercises code paths that black-box tests based on specifications might miss."},
{id:449,chapter:"Test Analysis and Design",topic:"Experience-based Techniques",difficulty:"hard",question:"A tester creates a 'bug taxonomy' â€” a categorized list of defect types seen in previous projects. This is BEST used as a basis for:",options:["A. Exploratory test charters","B. A fault attack strategy","C. Regression test automation","D. Requirements review checklists"],answer:1,explanation:"A bug taxonomy provides the structured defect categories needed to design a systematic fault attack strategy."},
{id:450,chapter:"Test Analysis and Design",topic:"Test Conditions",difficulty:"extreme",question:"A test manager asks a tester to ensure 'full requirements coverage.' The tester should ensure:",options:["A. Every line of code is tested","B. Every requirement has at least one corresponding test condition and test case","C. All possible input combinations are tested","D. All equivalence partitions are tested"],answer:1,explanation:"Full requirements coverage means every requirement (the coverage items) has been covered by at least one test case."},

// ============================================================
// CHAPTER 5: Managing Test Activities (Q451-Q650)
// ============================================================
{id:451,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"easy",question:"Which of the following is TYPICALLY included in a test plan?",options:["A. Test execution results","B. Test objectives, scope, approach, resources, schedule, and risks","C. Defect reports","D. Test case specifications"],answer:1,explanation:"A test plan includes objectives, scope, approach, resources, schedule, and risk management."},
{id:452,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"easy",question:"The purpose of a test plan is to:",options:["A. Record the results of test execution","B. Define the scope, approach, resources, and schedule for testing","C. Document defects found during testing","D. Specify test procedures for execution"],answer:1,explanation:"A test plan defines what will be tested, how, by whom, and when â€” it guides the entire test effort."},
{id:453,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"medium",question:"Entry criteria in a test plan define:",options:["A. When testing should stop","B. The conditions that must be met before testing can begin","C. The quality metrics for the final release","D. Who is allowed to execute tests"],answer:1,explanation:"Entry criteria specify the prerequisites that must be satisfied before a particular test phase can begin."},
{id:454,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"medium",question:"Exit criteria in a test plan define:",options:["A. Who should exit the testing team","B. The conditions that must be met before a test phase can be considered complete","C. The maximum number of defects allowed","D. The system requirements for the test environment"],answer:1,explanation:"Exit criteria specify when testing activities can be considered complete for a given phase."},
{id:455,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"medium",question:"Which of the following is an example of a test exit criterion?",options:["A. The test environment is available","B. All high-priority test cases have been executed and no critical defects remain open","C. Requirements have been signed off","D. Test cases have been reviewed"],answer:1,explanation:"A typical exit criterion: all high-priority tests executed, no critical open defects."},
{id:456,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"easy",question:"Risk-based testing prioritizes testing based on:",options:["A. The number of lines of code in each module","B. The probability and impact of potential failures","C. The cost of developing each feature","D. The alphabetical order of features"],answer:1,explanation:"Risk = probability of occurrence x impact of failure; high-risk areas get more test coverage."},
{id:457,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"medium",question:"Product risk in testing is BEST described as:",options:["A. Risk that the project will exceed its budget","B. The risk that the software has defects that will cause failures in production","C. Risk associated with testing activities","D. Risk from unclear requirements"],answer:1,explanation:"Product risk relates to potential defects and failures in the software under test."},
{id:458,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"medium",question:"Project risk in testing is BEST described as:",options:["A. The risk that the software has defects","B. Risk related to testing activities themselves: late delivery, resource shortages, skills gaps","C. The risk of poor user acceptance","D. Risk from performance issues"],answer:1,explanation:"Project risks affect the test project: resource issues, schedule delays, tool problems, etc."},
{id:459,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"hard",question:"A risk matrix helps in risk-based testing by:",options:["A. Automatically generating test cases for high-risk areas","B. Visualizing and prioritizing risks by likelihood and impact","C. Replacing the need for test planning","D. Defining the test environment requirements"],answer:1,explanation:"A risk matrix plots risks by probability and impact, helping prioritize testing effort."},
{id:460,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"hard",question:"In risk-based testing, which module should receive the MOST testing attention?",options:["A. A module with low probability of failure and low impact","B. A module with high probability of failure and high impact","C. A module with low probability of failure and high impact","D. All modules equally"],answer:1,explanation:"High probability and high impact = highest risk level = most testing attention."},
{id:461,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"easy",question:"Test monitoring involves:",options:["A. Writing test cases","B. Comparing test progress against the test plan and reporting status","C. Executing test cases","D. Setting up the test environment"],answer:1,explanation:"Test monitoring tracks ongoing testing progress against the test plan and reports status to stakeholders."},
{id:462,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"medium",question:"Which of the following is a test metric used for test monitoring?",options:["A. Number of developers on the team","B. Test case execution rate and defect detection rate","C. Size of the codebase","D. Number of requirements in the project"],answer:1,explanation:"Test metrics include execution rate, pass/fail rate, defect detection rate, and coverage metrics."},
{id:463,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"medium",question:"A test burndown chart is MOST useful for:",options:["A. Showing the total number of defects over time","B. Tracking test case execution progress against the plan","C. Measuring code coverage","D. Documenting test environment issues"],answer:1,explanation:"A test burndown chart shows how many tests remain to be executed versus the planned schedule."},
{id:464,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"hard",question:"Test control actions in response to deviations from the test plan might include:",options:["A. Ignoring the deviation and continuing as planned","B. Reprioritizing tests, adjusting scope, or allocating additional resources","C. Canceling the project","D. Replacing the test team"],answer:1,explanation:"Test control involves taking corrective actions: reprioritizing, adjusting scope, or adding resources."},
{id:465,chapter:"Managing the Test Activities",topic:"Configuration Management",difficulty:"easy",question:"Configuration management in testing ensures:",options:["A. The test plan is approved by management","B. Testware and test objects are uniquely identified, version-controlled, and traceable","C. All tests are automated","D. The test environment is always available"],answer:1,explanation:"Configuration management ensures testware and test objects are properly versioned and traceable."},
{id:466,chapter:"Managing the Test Activities",topic:"Configuration Management",difficulty:"medium",question:"Why is version control important for test scripts?",options:["A. It makes test scripts run faster","B. It allows teams to track changes, revert to previous versions, and know which version was used for each test run","C. It automatically updates test scripts when requirements change","D. It reduces the storage needed for test artifacts"],answer:1,explanation:"Version control ensures teams can track changes to scripts, revert as needed, and audit which version was used."},
{id:467,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"easy",question:"What is the purpose of a defect report?",options:["A. To document the test plan","B. To record and communicate a defect found during testing","C. To approve software for release","D. To measure test coverage"],answer:1,explanation:"A defect report documents a found defect to enable it to be investigated, prioritized, and fixed."},
{id:468,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"easy",question:"Which of the following is typically included in a defect report?",options:["A. The project budget","B. Steps to reproduce, expected result, actual result, severity, and priority","C. The development team's performance metrics","D. The test schedule"],answer:1,explanation:"A defect report includes: steps to reproduce, expected vs. actual results, severity, priority, and environment."},
{id:469,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"medium",question:"What is the difference between defect severity and defect priority?",options:["A. They are the same thing","B. Severity is the impact on the system; priority is the urgency of fixing it","C. Severity is set by developers; priority is set by testers","D. Priority is the technical impact; severity is the business urgency"],answer:1,explanation:"Severity = technical impact on system functionality; priority = business urgency of fixing the defect."},
{id:470,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"medium",question:"A cosmetic UI defect that doesn't affect functionality but is visible on the home page should be:",options:["A. High severity, high priority","B. Low severity, high priority","C. High severity, low priority","D. Low severity, low priority"],answer:1,explanation:"A cosmetic defect is low severity (minimal technical impact) but could be high priority (visible to all users on home page)."},
{id:471,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"hard",question:"A test approach document is BEST described as:",options:["A. A detailed schedule of test activities","B. The testing strategy for a specific project, detailing how testing will be conducted","C. A list of all test cases","D. The defect management process"],answer:1,explanation:"A test approach describes the testing strategy for a specific project â€” methods, tools, and techniques to be used."},
{id:472,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"hard",question:"Risk mitigation in testing involves:",options:["A. Accepting all identified risks","B. Taking actions to reduce the probability or impact of identified risks","C. Documenting risks without action","D. Transferring all risks to the development team"],answer:1,explanation:"Risk mitigation involves taking proactive steps to reduce the likelihood or consequences of identified risks."},
{id:473,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"hard",question:"What is a 'defect lifecycle'?",options:["A. The time from defect introduction to software retirement","B. The process a defect goes through from discovery to closure","C. The impact of a defect over time","D. The lifecycle of defect management tools"],answer:1,explanation:"A defect lifecycle tracks a defect from discovery through analysis, fixing, retesting, and closure."},
{id:474,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"medium",question:"Which defect status indicates the defect has been fixed and is awaiting retesting?",options:["A. Open","B. In Progress","C. Fixed / Resolved","D. Closed"],answer:2,explanation:"'Fixed/Resolved' means the developer has addressed the defect and it is ready for confirmation testing."},
{id:475,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"hard",question:"A test manager notices that the actual test execution rate is significantly lower than planned. Which is the MOST appropriate action?",options:["A. Stop testing and release the software","B. Investigate the cause and implement corrective action (resource adjustment, scope revision)","C. Update the plan to match the actual rate","D. Ask testers to work overtime without investigating the cause"],answer:1,explanation:"The test manager should investigate the root cause and take corrective action: resource reallocation, scope adjustment, etc."},
{id:476,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"medium",question:"Which of the following is a factor that influences the test approach?",options:["A. The number of developers in the team","B. Software development lifecycle model, available tools, and risk level","C. The color scheme of the user interface","D. The name of the project manager"],answer:1,explanation:"Test approach is influenced by the SDLC, available resources, tools, risks, and project constraints."},
{id:477,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"extreme",question:"A test team is running out of time before a major release. Using risk-based testing, they should:",options:["A. Execute all test cases in alphabetical order","B. Prioritize and execute tests for highest-risk features first, defer low-risk testing","C. Stop testing and release immediately","D. Execute only automated tests"],answer:1,explanation:"Risk-based testing allocates effort to highest-risk areas first â€” ensuring critical risks are covered even if time runs out."},
{id:478,chapter:"Managing the Test Activities",topic:"Configuration Management",difficulty:"hard",question:"Which of the following BEST describes a 'testware baseline'?",options:["A. The minimum coverage required for release","B. A formally approved version of testware that serves as the reference for comparison","C. The initial state of the test environment","D. The test team's performance benchmark"],answer:1,explanation:"A baseline is a formally approved version of a configuration item â€” used as a reference for future changes."},
{id:479,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"hard",question:"Which of the following BEST describes 'defect clustering'?",options:["A. Multiple testers submitting the same defect","B. The tendency for defects to be concentrated in a small number of modules","C. Grouping defects by severity in the defect tracker","D. Creating clusters of related test cases"],answer:1,explanation:"Defect clustering (Pareto principle): 80% of defects tend to be found in 20% of the modules."},
{id:480,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"extreme",question:"In a project with changing requirements, which type of testing approach is MOST appropriate?",options:["A. A rigid, fully-documented test plan with no changes allowed","B. An adaptive/agile test approach that accommodates changing requirements","C. Deferring all testing until requirements are stable","D. Only testing the stable requirements"],answer:1,explanation:"In projects with changing requirements, an adaptive approach that accommodates changes is essential."},
{id:481,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"medium",question:"Which document typically contains the test strategy at an organizational level?",options:["A. Test plan","B. Test case specification","C. Test policy","D. Defect report"],answer:2,explanation:"A test policy (or organizational test strategy) describes the organization-wide approach to testing."},
{id:482,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"medium",question:"Which of the following test metrics measures the EFFECTIVENESS of testing?",options:["A. Number of test cases written","B. Defect detection percentage (DDP)","C. Number of test environments","D. Hours spent on testing"],answer:1,explanation:"DDP (defects found during testing / total defects found) measures testing effectiveness at finding defects."},
{id:483,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"extreme",question:"A defect found in production that was NOT found during testing is called:",options:["A. A missing defect","B. An escape","C. A critical defect","D. A production anomaly"],answer:1,explanation:"A defect that 'escapes' testing and is found in production is called an escape â€” a key testing effectiveness metric."},
{id:484,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"hard",question:"Which of the following is a product risk that a test manager should consider?",options:["A. Test tool procurement delays","B. Complex payment logic likely to have calculation errors","C. Team member availability","D. Test environment setup time"],answer:1,explanation:"Product risks are potential defects in the software itself â€” complex logic is a high product risk area."},
{id:485,chapter:"Managing the Test Activities",topic:"Configuration Management",difficulty:"medium",question:"Maintaining a 'test environment configuration record' helps ensure:",options:["A. Tests execute faster","B. Tests can be reproduced exactly by documenting the environment's configuration","C. Developers can write better code","D. The test plan is up to date"],answer:1,explanation:"Environment configuration records enable reproducibility â€” essential for confirming defects and for auditing."},
{id:486,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"medium",question:"What should a tester do when they discover a defect that was already reported by a colleague?",options:["A. Create a new defect report to emphasize the importance","B. Mark their finding as a duplicate of the existing report","C. Ignore it since it is already reported","D. Report it as a separate defect with different severity"],answer:1,explanation:"Duplicate defects should be linked to the original report to avoid confusion and wasted fix effort."},
{id:487,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"hard",question:"What is the purpose of test effort estimation in test planning?",options:["A. To determine how many defects will be found","B. To predict the resources, time, and cost needed to complete the test activities","C. To assign test cases to testers","D. To define acceptance criteria"],answer:1,explanation:"Test effort estimation predicts the resources, time, and cost required to execute the testing plan."},
{id:488,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"hard",question:"Which of the following is a PURPOSE of test reporting?",options:["A. To blame developers for defects","B. To communicate test progress, quality status, and risks to stakeholders","C. To provide a record of test cases for future projects","D. To measure developer performance"],answer:1,explanation:"Test reports communicate testing status, quality information, and risks to help stakeholders make decisions."},
{id:489,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"extreme",question:"A feature has a 5% probability of failure but would cause the entire system to crash if it fails. How should it be classified?",options:["A. Low risk â€” probability is only 5%","B. Medium risk â€” it depends on other factors","C. High risk â€” low probability but catastrophic impact","D. No risk â€” it's a feature, not a risk"],answer:2,explanation:"Risk = probability x impact; even low probability with catastrophic impact creates high risk requiring significant testing."},
{id:490,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"medium",question:"When should test planning begin in a project?",options:["A. After requirements are complete","B. After development starts","C. As early as possible in the SDLC","D. When testing is about to start"],answer:2,explanation:"Test planning should begin as early as possible â€” ideally at project inception, alongside requirements development."},
{id:491,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"medium",question:"Which of the following is NOT typically in the defect lifecycle workflow?",options:["A. New","B. Assigned","C. Fixed","D. Released to Production"],answer:3,explanation:"'Released to Production' is a release management activity â€” not a standard defect lifecycle state."},
{id:492,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"extreme",question:"A test manager receives a metric showing 200 test cases were executed with a 95% pass rate, but the software has a critical unseen defect. Which metric would BEST have indicated this risk?",options:["A. Pass rate","B. Code coverage showing low coverage in critical modules","C. Test case execution rate","D. Number of test cases written"],answer:1,explanation:"Low code/requirements coverage in critical modules would have indicated insufficient testing in important areas."},
{id:493,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"medium",question:"Risk identification in test planning typically involves:",options:["A. One person listing risks alone","B. Collaboration between testers, developers, stakeholders, and experts to identify all significant risks","C. Reviewing the previous project's defect log only","D. Using automated risk assessment tools exclusively"],answer:1,explanation:"Effective risk identification requires collaboration from multiple perspectives â€” testers, dev, business, and subject matter experts."},
{id:494,chapter:"Managing the Test Activities",topic:"Configuration Management",difficulty:"hard",question:"A tester cannot reproduce a defect because the test environment has been updated since the defect was found. This illustrates the importance of:",options:["A. Better defect reports","B. Configuration management â€” tracking environment state when defects are found","C. More frequent regression testing","D. Faster defect fixing"],answer:1,explanation:"Configuration management ensures environment states are recorded, enabling defect reproduction."},
{id:495,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"hard",question:"Suspension criteria in a test plan define:",options:["A. When testing should be permanently stopped","B. Conditions under which testing is temporarily halted until an issue is resolved","C. The criteria for pausing individual test cases","D. When the test environment should be shut down"],answer:1,explanation:"Suspension criteria define when testing should temporarily stop (e.g., critical defect blocks further testing)."},
{id:496,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"hard",question:"An anomaly report is BEST described as:",options:["A. A report that only covers critical defects","B. A report that documents any unexpected event or deviation during testing, even if it is later determined not to be a defect","C. A report on test execution performance","D. A report for defects found in production only"],answer:1,explanation:"Anomaly reports document any unexpected behavior â€” it may or may not be a defect after investigation."},
{id:497,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"hard",question:"Which of the following BEST describes residual risk?",options:["A. Risks that have been completely eliminated","B. The remaining risk after risk mitigation actions have been applied","C. Risks identified but not yet analyzed","D. Risks transferred to insurance"],answer:1,explanation:"Residual risk is the risk remaining after mitigation â€” it's accepted as the cost of doing business."},
{id:498,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"extreme",question:"A test manager is asked to estimate testing effort for a project with no historical data. Which estimation technique involves experts providing estimates independently then reaching consensus?",options:["A. Work breakdown structure","B. Wideband Delphi","C. Three-point estimation","D. Use case point estimation"],answer:1,explanation:"Wideband Delphi involves independent expert estimates followed by discussion and consensus â€” useful without historical data."},
{id:499,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"hard",question:"A test summary report is produced at the end of a test phase. Which of the following should it contain?",options:["A. Individual developer performance evaluations","B. Testing activities summary, metrics, defect status, deviations from plan, and evaluation of exit criteria","C. Test case specifications","D. Project budget analysis"],answer:1,explanation:"A test summary report documents what was tested, metrics, defects found, and whether exit criteria were met."},
{id:500,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"medium",question:"Which of the following BEST describes the purpose of defect triage?",options:["A. Writing defect reports for new defects","B. Reviewing, prioritizing, and assigning defects to be addressed","C. Retesting fixed defects","D. Archiving closed defects"],answer:1,explanation:"Defect triage reviews new defects, determines their validity, assigns priority/severity, and routes them for fixing."},
{id:501,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"medium",question:"A test strategy is DIFFERENT from a test plan in that:",options:["A. A test strategy covers a specific project; a test plan is organization-wide","B. A test strategy describes the general approach; a test plan provides project-specific details","C. A test strategy is written by developers; a test plan by testers","D. They are the same document"],answer:1,explanation:"A test strategy is a general, reusable approach; a test plan applies the strategy to a specific project."},
{id:502,chapter:"Managing the Test Activities",topic:"Configuration Management",difficulty:"medium",question:"Which of the following is an example of a configuration item in testing?",options:["A. A developer's personal notes","B. Test scripts stored in version control","C. Meeting minutes from a project status meeting","D. The project manager's risk log"],answer:1,explanation:"Configuration items are formally managed artifacts â€” test scripts in version control are a key testing CI."},
{id:503,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"extreme",question:"A defect is classified as 'severity 1, priority 3.' This MOST likely means:",options:["A. The defect is critical but can wait to be fixed â€” perhaps it occurs in a rarely used feature","B. The defect is minor but must be fixed immediately","C. Both severity and priority are low","D. The defect blocks all other testing"],answer:0,explanation:"High severity (critical impact) but low/medium priority (doesn't need immediate fix) â€” occurs in rare, low-traffic area."},
{id:504,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"extreme",question:"A test manager uses risk information to decide which tests to automate first. This BEST illustrates:",options:["A. Test automation strategy","B. Risk-informed test optimization","C. Random test selection","D. Test metric analysis"],answer:1,explanation:"Using risk to prioritize automation investment is a practical application of risk-based testing."},
{id:505,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"hard",question:"What should be included in the 'scope' section of a test plan?",options:["A. Who will fix the defects","B. What features and functions will and will not be tested, and why","C. The test execution schedule","D. The test team's salaries"],answer:1,explanation:"The scope section defines what's in and out of scope for testing â€” and provides rationale for exclusions."},
{id:506,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"medium",question:"Which metric BEST indicates the quality of testing (not the software)?",options:["A. Number of defects found","B. Percentage of test cases passing","C. Defect detection efficiency (DDE) â€” defects found in testing vs. total defects","D. Lines of code covered"],answer:2,explanation:"DDE measures what proportion of all defects were found by testing â€” a quality-of-testing metric."},
{id:507,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"hard",question:"When a developer marks a defect as 'Not a Bug,' the tester should:",options:["A. Close the defect immediately","B. Review the rationale â€” if they disagree, escalate for resolution per the defect process","C. Re-open it and reassign to another developer","D. Accept the developer's classification without question"],answer:1,explanation:"The tester should review the developer's reasoning; if they disagree, the defect process should define escalation."},
{id:508,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"easy",question:"Which of the following is NOT typically a role of the test manager in test planning?",options:["A. Estimating test effort","B. Defining the test approach","C. Writing individual test cases","D. Identifying testing risks"],answer:2,explanation:"Writing individual test cases is a tester activity â€” test managers focus on planning, strategy, and management."},
{id:509,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"hard",question:"A newly developed payment module has never been tested before. How should a risk-based tester treat it?",options:["A. Lower risk â€” it's new, so no known defects","B. Higher risk â€” new code with no testing history has higher probability of defects","C. Same risk as existing, well-tested modules","D. Risk cannot be assessed for new modules"],answer:1,explanation:"New, untested code has higher product risk â€” no track record means defects are more likely."},
{id:510,chapter:"Managing the Test Activities",topic:"Configuration Management",difficulty:"extreme",question:"A test was passing last week but is now failing. The code hasn't changed, but the test environment was updated. Configuration management would help by:",options:["A. Automatically fixing the failing test","B. Providing a record of what changed in the environment to identify the root cause","C. Reverting the code to last week","D. Generating new test cases"],answer:1,explanation:"Configuration management records environment changes, enabling root cause analysis of unexpected test failures."},
{id:511,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"easy",question:"What is the MAIN purpose of a test progress report?",options:["A. To list all defects found to date","B. To communicate current testing status, progress, and risks to stakeholders","C. To document the test cases executed","D. To approve the final software release"],answer:1,explanation:"Test progress reports keep stakeholders informed of test status, progress, risks, and upcoming activities."},
{id:512,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"medium",question:"Which of the following is an example of a deferred defect?",options:["A. A defect fixed before the current release","B. A defect that will be fixed in a future release due to low priority or time constraints","C. A defect that cannot be reproduced","D. A defect reported in a previous version"],answer:1,explanation:"Deferred defects are known issues postponed to a future release due to priority or schedule constraints."},
{id:513,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"extreme",question:"In an Agile project, which document typically replaces the traditional comprehensive test plan?",options:["A. Sprint report","B. Lightweight test plan or test strategy in the Definition of Done","C. User story","D. Product backlog"],answer:1,explanation:"Agile projects often use lightweight, iterative test plans integrated into sprint activities, rather than comprehensive upfront documents."},
{id:514,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"medium",question:"Risk analysis in test planning should be performed:",options:["A. Only once at the beginning of the project","B. Continuously throughout the project as risks change","C. Only during system testing","D. After all defects are found"],answer:1,explanation:"Risk analysis is ongoing â€” new risks emerge and known risks change probability/impact throughout the project."},
{id:515,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"hard",question:"A defect that was closed is reopened because retesting showed the fix was incomplete. This defect status is BEST described as:",options:["A. New","B. In Progress","C. Re-opened","D. Rejected"],answer:2,explanation:"A 'Re-opened' status indicates the defect was closed but has been found to still exist after retesting."},
{id:516,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"hard",question:"Which metric would MOST help a test manager assess whether the team will finish testing on time?",options:["A. Total number of test cases","B. Planned vs. actual test case execution rate over time","C. Number of defects found per day","D. Code coverage percentage"],answer:1,explanation:"Tracking planned vs. actual execution rate reveals if the team is on pace to complete testing within the schedule."},
{id:517,chapter:"Managing the Test Activities",topic:"Configuration Management",difficulty:"hard",question:"Why is it important to maintain traceability between test cases and software versions?",options:["A. To ensure developers write better code","B. To know which tests ran against which version, enabling accurate defect investigation","C. To reduce the number of test cases","D. To speed up test execution"],answer:1,explanation:"Traceability between tests and software versions ensures accurate defect tracking and regression analysis."},
{id:518,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"medium",question:"Which of the following BEST describes a 'test level' in a test plan?",options:["A. The difficulty rating of test cases","B. A group of testing activities organized and managed together (unit, integration, system, acceptance)","C. The seniority level of testers","D. The number of test cycles planned"],answer:1,explanation:"Test levels (unit, integration, system, acceptance) organize testing into distinct phases, each in a test plan."},
{id:519,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"extreme",question:"A highly experienced team is developing a simple CRUD application. Risk-based testing would MOST likely lead to:",options:["A. Maximum testing effort on all modules","B. Focused, lightweight testing on complex business logic and reduced coverage of simple CRUD operations","C. No testing needed since the team is experienced","D. Full path coverage on all modules"],answer:1,explanation:"Risk-based testing reduces effort on well-understood, low-risk areas (simple CRUD) and focuses on complex logic."},
{id:520,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"extreme",question:"A test manager needs to convince management to defer fixing a medium-severity defect until after release. The BEST justification is:",options:["A. The defect is in a module that no one uses","B. Risk analysis shows the probability and impact are acceptable given the workaround available","C. The developer doesn't have time to fix it","D. The tester doesn't think it's important"],answer:1,explanation:"Deferring a defect requires a risk-based justification â€” acceptable risk level with a known workaround."},
{id:521,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"hard",question:"What should be done when actual testing reveals that the original test effort estimate was significantly too low?",options:["A. Continue testing as planned without reporting","B. Report the variance to stakeholders and revise the plan with corrective actions","C. Remove test cases to meet the original schedule","D. Ask developers to fix defects faster"],answer:1,explanation:"Estimation errors must be reported and the test plan revised â€” transparency with stakeholders is essential."},
{id:522,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"medium",question:"Which of the following is a LAGGING indicator of test quality?",options:["A. Defect density in test execution","B. Production defect rate (escapes after release)","C. Test coverage metrics","D. Test execution progress"],answer:1,explanation:"Production defect rate (escapes) is a lagging indicator â€” it measures quality after the fact."},
{id:523,chapter:"Managing the Test Activities",topic:"Configuration Management",difficulty:"easy",question:"Which of the following is the PRIMARY benefit of using a test management tool for configuration management?",options:["A. Automatic test generation","B. Centralized, version-controlled storage of all test artifacts with audit trails","C. Faster test execution","D. Elimination of manual testing"],answer:1,explanation:"Test management tools provide central storage with version control and audit trails for all test artifacts."},
{id:524,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"hard",question:"Which of the following is NOT a common risk identification technique?",options:["A. Expert interviews","B. Brainstorming","C. Test execution","D. Checklists of common project risks"],answer:2,explanation:"Test execution is not a risk identification technique â€” it finds defects. Risk identification uses interviews, checklists, and brainstorming."},
{id:525,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"medium",question:"What information should be provided when a tester encounters an issue they cannot reproduce?",options:["A. No report is needed for non-reproducible issues","B. Document what was observed, environmental conditions, and attempts to reproduce","C. Report it as a critical defect to ensure attention","D. Skip it and continue with other tests"],answer:1,explanation:"Non-reproducible issues should be documented with all available context â€” they may indicate intermittent defects."},
{id:526,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"medium",question:"Which factor should MOST influence how much testing is needed?",options:["A. The number of developers on the team","B. The risk level of the software being tested","C. The testing budget alone","D. The preferences of the test manager"],answer:1,explanation:"Risk level (probability x impact of failure) is the primary driver of how much testing effort is needed."},
{id:527,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"extreme",question:"The test manager receives a dashboard showing: 600/1000 tests run, 90% pass rate, critical defect density 0.5/KLOC, and 30 open P1 defects. The MOST concerning metric is:",options:["A. 600/1000 tests run","B. 90% pass rate","C. 30 open P1 (critical) defects","D. 0.5 defects/KLOC"],answer:2,explanation:"30 open critical (P1) defects is the most concerning â€” critical defects unresolved represent direct release risk."},
{id:528,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"hard",question:"A defect that cannot be reproduced in any environment is MOST likely:",options:["A. A critical defect requiring immediate attention","B. An intermittent defect related to timing, environment, or data state","C. Not a real defect","D. A performance defect"],answer:1,explanation:"Non-reproducible defects are often intermittent â€” related to timing, environment configuration, or specific data states."},
{id:529,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"extreme",question:"A test plan for a safety-critical medical device would differ from one for a web application MOST significantly in:",options:["A. Fewer test cases for medical devices","B. Greater emphasis on formal documentation, traceability, and regulatory compliance evidence","C. No need for automation in medical devices","D. Medical device testing requires less risk analysis"],answer:1,explanation:"Safety-critical systems require formal, documented, traceable test evidence for regulatory bodies (FDA, IEC)."},
{id:530,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"hard",question:"What is the purpose of residual risk acceptance in testing?",options:["A. To eliminate all risks before release","B. To formally acknowledge that some risks remain and decide they are acceptable for release","C. To defer all remaining risks to future versions","D. To assign residual risks to the development team"],answer:1,explanation:"Residual risk acceptance is a formal decision that the remaining risks are acceptable for the planned release."},

{id:531,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"medium",question:"What does 'test scope' define in a test plan?",options:["A. The budget for testing","B. The features, functions, and quality attributes that will and will not be tested","C. The testing timeline","D. The test team structure"],answer:1,explanation:"Test scope defines what is and is not included in the testing effort for the project."},
{id:532,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"medium",question:"A defect is found during unit testing that would have been critical if found in production. How should it be classified?",options:["A. Low severity since it was found early","B. Its actual severity based on the impact it would have had â€” likely high severity","C. Medium severity since it's a unit test finding","D. Low priority since it was found early"],answer:1,explanation:"Severity reflects the impact of the defect on the system â€” finding it early doesn't change its technical severity."},
{id:533,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"hard",question:"Pass/fail rate alone is a POOR measure of software quality because:",options:["A. It is difficult to calculate","B. It doesn't show which tests were run â€” low pass rate could be due to poor tests, not poor software","C. It measures only functional testing","D. Pass rates are always 100%"],answer:1,explanation:"A high pass rate may indicate good software OR weak tests. Pass rate context (test quality, coverage) matters."},
{id:534,chapter:"Managing the Test Activities",topic:"Configuration Management",difficulty:"hard",question:"Why should test environments be documented as configuration items?",options:["A. To allow tests to run faster","B. To ensure consistent, reproducible test conditions and enable defect investigation","C. To reduce the number of test environments needed","D. To replace test plans with environment documentation"],answer:1,explanation:"Documented environments ensure tests are reproducible and defect investigation can identify environment-related issues."},
{id:535,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"medium",question:"Which of the following BEST describes how risk-based testing improves release decisions?",options:["A. It eliminates all risks before release","B. It provides evidence that high-risk areas were thoroughly tested, supporting informed release decisions","C. It reduces the number of tests needed for release","D. It replaces the decision-making role of stakeholders"],answer:1,explanation:"Risk-based testing ensures high-risk areas are well-covered, giving stakeholders confidence in the release decision."},
{id:536,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"extreme",question:"A production system has a defect that causes data loss for 0.001% of transactions. Despite its low occurrence, it should be treated as:",options:["A. Low priority due to low occurrence","B. High severity due to catastrophic data loss impact, requiring immediate attention","C. Medium severity since it's rare","D. An acceptable production risk"],answer:1,explanation:"Data loss is catastrophic regardless of occurrence rate â€” severity is high, and fixing it should be prioritized."},
{id:537,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"hard",question:"A test plan includes a 'risk log' that categorizes risks as 'high, medium, low.' This supports which testing activity?",options:["A. Test execution","B. Risk-based test prioritization and resource allocation","C. Defect reporting","D. Configuration management"],answer:1,explanation:"A risk log supports risk-based testing by guiding where to focus testing effort based on risk levels."},
{id:538,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"medium",question:"A test manager reports 'green' status on a dashboard but 20% of critical tests have not yet been executed. This BEST illustrates:",options:["A. Effective test management","B. Misleading reporting â€” status should reflect critical test coverage gaps","C. Normal test progress","D. An example of risk-based testing"],answer:1,explanation:"Dashboard status must honestly reflect critical gaps â€” reporting 'green' when critical areas are untested is misleading."},
{id:539,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"hard",question:"A tester is asked to suggest which automated tests should be in the smoke test suite. Using risk-based thinking, they should include:",options:["A. All existing automated tests","B. Tests that verify the most critical functions and highest-risk areas","C. The fastest tests regardless of coverage","D. Only tests that have never failed"],answer:1,explanation:"Smoke tests should prioritize critical functionality and high-risk areas to quickly validate build quality."},
{id:540,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"easy",question:"Which of the following BEST describes 'defect density'?",options:["A. The severity of defects found","B. The number of defects found per unit (e.g., per KLOC or per function point)","C. The rate at which defects are fixed","D. The number of testers required to find defects"],answer:1,explanation:"Defect density measures the concentration of defects (e.g., per 1,000 lines of code or per function point)."},
{id:541,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"medium",question:"An 'assumption' in a test plan is BEST described as:",options:["A. A risk that has been identified","B. A condition believed to be true that has not been verified but affects the plan","C. A constraint on the test activities","D. A test objective"],answer:1,explanation:"An assumption is an unverified belief that the plan is based on â€” if false, the plan may need revision."},
{id:542,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"medium",question:"Why is it important to compare actual defect trends with the predicted defect discovery curve?",options:["A. To identify when testing has caught enough defects","B. To detect if defect discovery is lower than expected, which may indicate insufficient testing or testing in wrong areas","C. To prove that the development team is doing poorly","D. To measure tester productivity"],answer:1,explanation:"If defect discovery is lower than predicted, it may mean testing isn't thorough enough or is missing defect-prone areas."},
{id:543,chapter:"Managing the Test Activities",topic:"Configuration Management",difficulty:"medium",question:"Which of the following is NOT a benefit of version control for test scripts?",options:["A. Ability to track changes to tests over time","B. Ability to roll back to previous script versions","C. Automatic fixing of broken tests when code changes","D. Audit trail of who changed what and when"],answer:2,explanation:"Version control does NOT automatically fix broken tests â€” that requires human intervention or AI tools."},
{id:544,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"extreme",question:"A payment processing module processes $10 million per day. If it fails, the company loses $10 million per hour. A competing feature has $100/day usage. How should a risk-based test manager allocate testing effort?",options:["A. 50/50 between both features","B. Significantly more testing on the payment module due to dramatically higher financial impact","C. More testing on the competing feature since it's newer","D. Equal effort since both are business-critical"],answer:1,explanation:"Financial impact drives risk prioritization â€” $10M/hour potential loss vs. $100/day demands disproportionate testing coverage."},
{id:545,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"hard",question:"In which section of the test plan would you describe the techniques to be used for test design?",options:["A. Scope","B. Test approach","C. Resources","D. Schedule"],answer:1,explanation:"The test approach section describes techniques, methods, and tools to be used for test design and execution."},
{id:546,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"hard",question:"When logging a defect, why is it important to include the exact version of the software under test?",options:["A. To impress management with detail","B. To ensure the defect can be accurately reproduced and to know if it was fixed in a later version","C. To measure developer performance","D. It is not important to include the software version"],answer:1,explanation:"Software version information ensures the defect can be reproduced in the right build and tracked across versions."},
{id:547,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"medium",question:"Which of the following metrics would BEST indicate testing is complete?",options:["A. All test cases written","B. Exit criteria are met: required coverage achieved, open defects below threshold, all critical tests passed","C. The scheduled end date has passed","D. The development team has stopped coding"],answer:1,explanation:"Testing completion is best indicated by meeting defined exit criteria â€” not just running out of time."},
{id:548,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"easy",question:"Who typically approves the test plan?",options:["A. The test team alone","B. Project management and key stakeholders","C. Only the test manager","D. The development team lead"],answer:1,explanation:"Test plans are typically approved by project management and key stakeholders to ensure alignment."},
{id:549,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"medium",question:"Which of the following BEST describes a risk-based test completion criterion?",options:["A. All 1000 test cases executed","B. All risks rated 'high' have been mitigated through testing to acceptable levels","C. All modules have been tested","D. The test schedule end date has passed"],answer:1,explanation:"Risk-based exit criteria focus on risk reduction: high-risk areas are covered to acceptable levels."},
{id:550,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"medium",question:"A 'severity 1' defect is found 2 days before release. What should the test manager recommend?",options:["A. Release on schedule â€” users can work around it","B. Escalate immediately â€” severity 1 defects must be fixed before release or the release decision must be formally accepted by stakeholders","C. Defer it to the next sprint without informing stakeholders","D. Mark it as low priority since the deadline is near"],answer:1,explanation:"Severity 1 (critical) defects must be escalated â€” either fixed or formally accepted as a risk by stakeholders."},
{id:551,chapter:"Managing the Test Activities",topic:"Configuration Management",difficulty:"extreme",question:"A team discovers that two testers have been running different versions of the same test script, producing inconsistent results. This MOST likely resulted from:",options:["A. Inadequate test case design","B. Failure to use version control â€” testers had different local copies","C. Poor test execution technique","D. Environmental differences"],answer:1,explanation:"This is a classic configuration management failure â€” without version control, testers work from different script versions."},
{id:552,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"extreme",question:"A test manager is planning testing for a 6-month Agile project with 2-week sprints. The MOST appropriate planning approach is:",options:["A. Write a complete 50-page test plan before sprint 1","B. Create an overall test strategy with lightweight per-sprint planning that adapts as requirements evolve","C. Plan only after all sprints are complete","D. Create 13 separate test plans, one per sprint"],answer:1,explanation:"Agile test planning uses an overall strategy with iterative, adaptive sprint-level planning â€” not a monolithic upfront plan."},
{id:553,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"medium",question:"What information helps a developer MOST when trying to fix a reported defect?",options:["A. The tester's opinion of the defect's cause","B. Clear steps to reproduce, the environment, actual vs. expected results, and any relevant logs","C. The number of similar defects in the past","D. The test coverage metrics"],answer:1,explanation:"Reproducible steps, environment details, and actual vs. expected results are most valuable for developers fixing defects."},
{id:554,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"hard",question:"When should a test manager escalate testing issues to project management?",options:["A. Only when testing is complete","B. When deviations from the plan cannot be resolved within the test team's authority","C. After every test cycle","D. Only if the entire test schedule is at risk"],answer:1,explanation:"Escalation is needed when issues exceed the test manager's authority to resolve â€” e.g., resource allocation, scope changes."},
{id:555,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"medium",question:"A module has been tested extensively across multiple releases with no defects found. Risk-based testing would suggest:",options:["A. More testing since it could still have defects","B. Reduced testing since historical evidence suggests it is stable â€” risk is lower","C. Eliminate all testing for this module","D. Only automated testing for this module"],answer:1,explanation:"Historical defect-free status reduces assessed risk â€” risk-based testing can reduce coverage for proven stable modules."},
{id:556,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"medium",question:"Which of the following is typically defined in the 'resources' section of a test plan?",options:["A. Test techniques to be used","B. Test team members, their roles, and the required test environments and tools","C. The test schedule","D. Risk mitigation actions"],answer:1,explanation:"The resources section defines who (people), what (tools/environments), and how much (effort) for testing."},
{id:557,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"extreme",question:"A defect report includes: 'Sometimes the login fails. Not sure how to reproduce.' This report is problematic because:",options:["A. It has too much detail","B. It lacks reproducibility steps, making the defect extremely difficult to investigate and fix","C. The defect should be marked as critical","D. Defect reports should never describe intermittent issues"],answer:1,explanation:"Defect reports without reproducible steps are nearly impossible to investigate and fix effectively."},
{id:558,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"medium",question:"In Agile, test progress is MOST commonly tracked using:",options:["A. Comprehensive test progress reports","B. Burn-down/burn-up charts and sprint metrics integrated in the team's tracking tool","C. Separate test reporting from development","D. Monthly status reports"],answer:1,explanation:"Agile teams use burn-down charts and sprint metrics for lightweight, real-time progress tracking."},
{id:559,chapter:"Managing the Test Activities",topic:"Configuration Management",difficulty:"medium",question:"The MAIN purpose of maintaining test environment configurations under configuration management is:",options:["A. To allow testers to change environments freely","B. To ensure tests are run in consistent, documented environments and anomalies can be investigated","C. To reduce the cost of test environments","D. To automate test environment setup"],answer:1,explanation:"CM for environments ensures consistency, reproducibility, and auditability â€” critical for reliable testing."},
{id:560,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"hard",question:"Which of the following activities is NOT typically part of risk-based test planning?",options:["A. Risk identification","B. Risk analysis (likelihood and impact)","C. Risk mitigation through testing","D. Risk acceptance by testers without stakeholder involvement"],answer:3,explanation:"Risk acceptance is a stakeholder decision, not made unilaterally by testers â€” all other options are valid risk-based activities."},
{id:561,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"medium",question:"Which of the following BEST describes a 'test objective' in a test plan?",options:["A. A metric for measuring test progress","B. A specific goal the testing is intended to achieve","C. A constraint on the testing activities","D. A definition of the test environment"],answer:1,explanation:"Test objectives define what testing is trying to achieve â€” e.g., verify functional requirements, detect critical defects."},
{id:562,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"medium",question:"What is 'defect masking'?",options:["A. Hiding defects from management","B. A situation where one defect prevents another from being detected","C. A testing technique that masks sensitive data","D. Classifying critical defects as low severity"],answer:1,explanation:"Defect masking occurs when one defect prevents another from being triggered â€” e.g., a crash prevents reaching a subsequent defect."},
{id:563,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"extreme",question:"A test manager sees the number of new defects being reported is decreasing day by day. Without further analysis, this COULD mean:",options:["A. Only that the software quality is improving","B. Fewer defects are being found OR the team is running out of new test scenarios OR defect reporting is declining","C. Testing is complete","D. The test team is doing excellent work"],answer:1,explanation:"Declining defect rates have multiple possible causes â€” it could be quality improvement, test saturation, or reduced rigor."},
{id:564,chapter:"Managing the Test Activities",topic:"Configuration Management",difficulty:"medium",question:"A tester sets up the test environment manually each time. This is problematic because:",options:["A. Manual setups are always faster","B. It can lead to inconsistent environments, unreproducible tests, and wasted time","C. Manual setup is required for all test types","D. This eliminates the need for configuration management"],answer:1,explanation:"Manual environment setup introduces variability â€” environments may differ between setups, causing inconsistent results."},
{id:565,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"medium",question:"The term 'risk appetite' in testing refers to:",options:["A. The number of risks a team is willing to find","B. The level of risk that an organization is willing to accept","C. The speed at which risks are identified","D. The budget allocated for risk testing"],answer:1,explanation:"Risk appetite is the organization's tolerance for risk â€” how much residual risk they're willing to accept at release."},
{id:566,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"hard",question:"A test plan shows 3 test cycles. What does this likely mean?",options:["A. Three testers will execute the tests","B. Testing will be performed in three iterations, typically build-test-fix-retest cycles","C. Three different products will be tested","D. The test plan was written three times"],answer:1,explanation:"Multiple test cycles represent iterative rounds of testing and fixing, each cycle building on the previous."},
{id:567,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"hard",question:"What is the difference between a defect priority and release priority?",options:["A. They are the same","B. Defect priority is the urgency of fixing; release priority affects which version a fix will be included in","C. Release priority is determined by testers; defect priority by developers","D. Defect priority is always higher than release priority"],answer:1,explanation:"A defect's fix priority may differ from which release it targets â€” a medium-priority defect may still be fixed in a patch."},
{id:568,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"hard",question:"A test manager observes that the defect fix rate is lower than the defect discovery rate. This indicates:",options:["A. The test team is finding too many defects","B. The defect backlog is growing â€” development cannot fix defects as fast as they are found","C. Testing is too effective","D. The project will finish ahead of schedule"],answer:1,explanation:"When discovery exceeds fix rate, the backlog grows â€” a warning sign that may require resource rebalancing."},
{id:569,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"extreme",question:"A team performs risk-based testing but still has 10% of tests unexecuted at release. The most important consideration is:",options:["A. 90% coverage is always sufficient","B. Whether the 10% untested represents high-risk areas â€” if not, the residual risk may be acceptable","C. All tests must be completed before release","D. The 10% should be tested in production"],answer:1,explanation:"Risk-based decisions require knowing WHICH tests were skipped â€” skipping low-risk tests is acceptable; skipping high-risk tests is not."},
{id:570,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"extreme",question:"A test plan includes a 'traceability matrix' section. What is the purpose of this section?",options:["A. To map test cases to requirements, ensuring coverage and supporting impact analysis","B. To show the project organizational chart","C. To list defects found during testing","D. To define the test environment specifications"],answer:0,explanation:"A Requirements Traceability Matrix (RTM) maps requirements to test cases, ensuring full coverage."},

{id:571,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"easy",question:"Which of the following BEST describes the role of a defect tracking system?",options:["A. To automatically fix reported defects","B. To record, track, and manage the lifecycle of defects from discovery to closure","C. To generate test cases","D. To measure developer performance"],answer:1,explanation:"A defect tracking system manages the complete defect lifecycle â€” recording, routing, tracking, and closing defects."},
{id:572,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"medium",question:"Which of the following is a LEADING indicator that helps predict future test quality?",options:["A. Production defect rate","B. Defect fix rate â€” fast fixing indicates good team response","C. Test coverage â€” high coverage predicts better defect detection","D. Number of closed defects"],answer:2,explanation:"Leading indicators (like coverage) predict future outcomes; lagging indicators (like production defect rate) reflect past performance."},
{id:573,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"medium",question:"A 'test approach' in an Agile context would MOST likely include:",options:["A. A fixed 100-page test plan","B. The types of testing per sprint, automation strategy, and how regression will be managed","C. Only the manual testing approach","D. Test cases for all planned sprints"],answer:1,explanation:"An Agile test approach covers testing types per sprint, automation strategy, and regression approach."},
{id:574,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"medium",question:"How does risk-based testing help when time is limited?",options:["A. It eliminates the need for testing","B. It ensures the most critical and highest-risk areas are tested first, maximizing value from limited time","C. It reduces the number of defects that need to be fixed","D. It automates all testing"],answer:1,explanation:"Risk-based testing maximizes testing value by ensuring high-risk, high-impact areas are covered first."},
{id:575,chapter:"Managing the Test Activities",topic:"Configuration Management",difficulty:"hard",question:"Which of the following BEST describes 'test environment provisioning'?",options:["A. Hiring new test environment managers","B. Setting up the hardware, software, network, and data needed to support testing","C. Backing up the test environment","D. Documenting the test environment specifications"],answer:1,explanation:"Test environment provisioning involves setting up all resources needed for testing to begin."},
{id:576,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"hard",question:"A tester submits a defect for a feature that does not exist in the current release scope. The defect should be:",options:["A. Marked as critical","B. Marked as out of scope/rejected with an explanation","C. Fixed immediately","D. Escalated to management"],answer:1,explanation:"Out-of-scope issues should be rejected or redirected with an explanation â€” they are not valid defects for the current build."},
{id:577,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"hard",question:"Why is it important to plan for test environment setup in advance?",options:["A. To reduce defect density","B. To avoid delays in testing caused by environment issues â€” a common project bottleneck","C. To improve code quality","D. To help developers understand requirements"],answer:1,explanation:"Environment setup delays are a leading cause of testing delays â€” advance planning mitigates this risk."},
{id:578,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"hard",question:"A stakeholder asks for a test summary report. What MUST it include?",options:["A. Individual developer performance metrics","B. Summary of what was tested, metrics (execution, pass/fail, coverage), open defects, and overall quality assessment","C. Only the list of passed test cases","D. The source code changes made during the project"],answer:1,explanation:"A test summary report provides an overall picture: what was tested, metrics, defects, and quality assessment."},
{id:579,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"extreme",question:"After release, the production system experiences a failure in a module that was classified as 'low risk' during testing. What should the team do?",options:["A. Ignore it since it was correctly classified as low risk","B. Reassess the risk analysis â€” the classification may have been incorrect or conditions changed","C. Blame the test team for not finding the defect","D. Increase testing of all modules equally"],answer:1,explanation:"Production failures in 'low risk' areas require risk reassessment â€” was the classification wrong? Did conditions change?"},
{id:580,chapter:"Managing the Test Activities",topic:"Configuration Management",difficulty:"medium",question:"Which activity should PRECEDE test environment setup in the test process?",options:["A. Test execution","B. Test analysis and design","C. Test closure","D. Defect reporting"],answer:1,explanation:"Test analysis and design should produce the requirements for the test environment before it is set up."},
{id:581,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"medium",question:"The ROOT CAUSE of a defect is BEST described as:",options:["A. The first tester to find the defect","B. The earliest actions or conditions that led to the defect being introduced","C. The defect's impact on the system","D. The module where the defect exists"],answer:1,explanation:"Root cause analysis identifies the underlying reason why a defect was introduced â€” the earliest causal event."},
{id:582,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"medium",question:"When planning test data requirements, a test manager should consider:",options:["A. Only using real production data for testing","B. The volume, variety, and sensitivity of data needed, and data privacy regulations","C. Using the same data set for all test levels","D. Generating test data only after testing begins"],answer:1,explanation:"Test data planning considers data needs (volume, variety), privacy (GDPR, HIPAA), and how data will be generated/managed."},
{id:583,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"medium",question:"What does a 'quality gate' in a CI/CD pipeline represent?",options:["A. A physical security gate at the server room","B. A defined set of criteria that must be met before a build can progress to the next stage","C. A code review checkpoint","D. A performance testing milestone"],answer:1,explanation:"Quality gates define pass/fail criteria (coverage, defect thresholds) that must be met at each pipeline stage."},
{id:584,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"hard",question:"A new third-party component is integrated into a critical payment system. From a risk perspective, testing should:",options:["A. Focus only on the new component in isolation","B. Cover both the component and its integration with the payment system, prioritizing the integration points","C. Be reduced since the component is from a trusted vendor","D. Be deferred until after the full release"],answer:1,explanation:"Third-party integrations are high-risk areas â€” the integration points especially need thorough testing."},
{id:585,chapter:"Managing the Test Activities",topic:"Configuration Management",difficulty:"medium",question:"Which of the following BEST describes 'test data management'?",options:["A. Managing the test team's workload","B. Creating, maintaining, and managing data used in testing, ensuring it is appropriate, available, and compliant","C. Storing defect reports in a database","D. Managing test case documentation"],answer:1,explanation:"Test data management covers creating, maintaining, versioning, and governing data used in test execution."},
{id:586,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"extreme",question:"A defect management system shows 500 open defects. The release is in 2 weeks. Without fixing all defects, what should the test manager recommend?",options:["A. Release with all 500 open defects","B. Triage all defects: fix critical/high; defer or accept low-risk defects with documented rationale","C. Cancel the release until all defects are fixed","D. Close all defects as 'Won't Fix'"],answer:1,explanation:"Defect triage sorts defects by risk â€” fix critical ones, formally accept or defer low-risk ones with stakeholder agreement."},
{id:587,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"easy",question:"What is the purpose of defining test entry criteria?",options:["A. To define who can perform testing","B. To specify conditions that must be met before testing can start, preventing wasted effort","C. To define the test completion requirements","D. To set performance benchmarks"],answer:1,explanation:"Entry criteria prevent testing from starting before preconditions (stable build, environment ready) are met, avoiding waste."},
{id:588,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"extreme",question:"A test manager receives data: 1000 tests planned, 950 executed, 800 passed, 150 failed, 80 critical defects open. The FIRST action should be:",options:["A. Report the 80% pass rate as satisfactory","B. Investigate the 80 critical defects and determine if any block release","C. Execute the remaining 50 tests immediately","D. Close all 150 failed tests"],answer:1,explanation:"80 critical open defects is the most urgent issue â€” critical defects must be investigated before any release decision."},
{id:589,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"medium",question:"A risk-based test approach would reduce testing in which scenario?",options:["A. A new, complex feature critical to business operations","B. A simple UI text change in a low-traffic section of the application","C. A change to the core payment processing algorithm","D. A security feature update"],answer:1,explanation:"Low-risk changes (simple text in low-traffic areas) can receive reduced testing coverage in a risk-based approach."},
{id:590,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"hard",question:"A tester finds what appears to be a defect but is actually expected behavior per the requirement. The tester should:",options:["A. Force the defect through as critical","B. Close the report as 'Not a defect' and note the expected behavior, possibly flagging the requirement as misleading","C. Escalate to management","D. Continue to argue it is a defect"],answer:1,explanation:"When behavior matches requirements, it's not a defect â€” close it appropriately, but flag if the requirement itself may be wrong."},
{id:591,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"hard",question:"Which of the following is NOT a typical section in an IEEE 829-style test plan?",options:["A. Test objectives","B. Risk register","C. Source code review results","D. Test schedule"],answer:2,explanation:"Source code review results are a deliverable of static testing/reviews â€” not a standard test plan section."},
{id:592,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"medium",question:"Test metrics should be selected based on:",options:["A. What is easiest to collect","B. What provides actionable information to support decision-making and improvement","C. What makes the team look good","D. What the test tool automatically produces"],answer:1,explanation:"Metrics should provide actionable information supporting decisions â€” not just whatever is easy to collect."},
{id:593,chapter:"Managing the Test Activities",topic:"Configuration Management",difficulty:"hard",question:"A team uses Infrastructure as Code (IaC) to provision test environments automatically. This BEST represents:",options:["A. Replacing configuration management","B. Automated, version-controlled environment provisioning â€” an effective CM practice","C. Eliminating the need for test environments","D. A security risk"],answer:1,explanation:"IaC provides automated, repeatable, version-controlled environment setup â€” an excellent configuration management practice."},
{id:594,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"hard",question:"In risk-based testing, who should ultimately decide which risks are acceptable at release?",options:["A. The test manager","B. The development team","C. The product owner and business stakeholders","D. An external auditor"],answer:2,explanation:"Risk acceptance is a business decision â€” product owners and stakeholders decide what risk is acceptable to take."},
{id:595,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"medium",question:"A defect report is returned to the tester because the developer cannot reproduce it. The tester should:",options:["A. Close the report immediately","B. Provide additional reproduction information or verify if environmental differences explain the issue","C. Escalate it to the test manager immediately","D. Resubmit the report with higher severity"],answer:1,explanation:"The tester should investigate further â€” provide more context, check for environment differences, or help the developer reproduce it."},
{id:596,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"medium",question:"Which of the following is a CONSTRAINT that might appear in a test plan?",options:["A. Testing must achieve 90% branch coverage","B. Testing must be completed within 6 weeks with 2 testers and no additional budget","C. All defects must be fixed before release","D. Only automated testing will be used"],answer:1,explanation:"Constraints are limitations on testing: time (6 weeks), resources (2 testers), and budget are common constraints."},
{id:597,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"medium",question:"Which of the following is a test reporting content item that helps stakeholders make a release decision?",options:["A. Details of individual test steps","B. Number and severity of open defects, coverage achieved, and risk assessment","C. Test case creation dates","D. Names of testers who found each defect"],answer:1,explanation:"Release decisions need: defect status, coverage achieved, and risk assessment â€” key test report items."},
{id:598,chapter:"Managing the Test Activities",topic:"Configuration Management",difficulty:"easy",question:"What does 'test artifact' mean?",options:["A. An antique testing tool","B. Any work product created during the testing process","C. A defect found in an artifact","D. A type of test environment"],answer:1,explanation:"Test artifacts are work products produced during testing: test plans, test cases, scripts, reports, defect logs, etc."},
{id:599,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"extreme",question:"A test team uses Monte Carlo simulation to model testing risk. This BEST represents:",options:["A. Poor testing practice","B. Quantitative risk analysis using probability distributions to model test outcome uncertainty","C. Test automation","D. A test design technique"],answer:1,explanation:"Monte Carlo simulation models uncertainty quantitatively using probability distributions â€” advanced risk analysis."},
{id:600,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"medium",question:"Which of the following is the MAIN reason for documenting assumptions in a test plan?",options:["A. To blame stakeholders if assumptions are wrong","B. To clearly communicate dependencies so stakeholders can validate or challenge them","C. To reduce the number of risks to manage","D. To meet audit requirements"],answer:1,explanation:"Documenting assumptions enables stakeholders to review and challenge them â€” preventing plan failures based on false assumptions."},
{id:601,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"medium",question:"Why should defect reports be written objectively without emotional language?",options:["A. Emotional language makes reports longer","B. Objective reports are easier to understand, facilitate faster fixing, and maintain professional relationships","C. Emotional language is only appropriate for severity 1 defects","D. Developers prefer descriptive language"],answer:1,explanation:"Objective, factual defect reports facilitate investigation and fixing while maintaining professional developer-tester relationships."},
{id:602,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"hard",question:"A test team is tracking 'test effectiveness' as a metric. Which formula BEST represents test effectiveness?",options:["A. Total tests run / Total tests planned","B. Defects found during testing / (Defects found during testing + Defects found in production)","C. Tests passed / Tests executed","D. Defects per KLOC"],answer:1,explanation:"Test effectiveness = DDE (Defect Detection Efficiency) = testing defects / all defects; measures how well testing catches defects."},
{id:603,chapter:"Managing the Test Activities",topic:"Configuration Management",difficulty:"medium",question:"Change management in the context of testing means:",options:["A. Managing the team's resistance to Agile adoption","B. Controlling changes to test artifacts to prevent uncontrolled modifications","C. Documenting project scope changes","D. Managing configuration of production servers"],answer:1,explanation:"Change management in testing controls modifications to test artifacts â€” ensuring changes are authorized and tracked."},
{id:604,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"medium",question:"A product risk that has HIGH impact but LOW probability should receive:",options:["A. No testing â€” probability is too low","B. Some testing proportional to impact â€” even low-probability catastrophic failures need coverage","C. The same testing as high probability/low impact risks","D. Only exploratory testing"],answer:1,explanation:"High-impact risks need some coverage even at low probability â€” catastrophic outcomes justify testing investment."},
{id:605,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"hard",question:"In test planning, 'test data requirements' would specify:",options:["A. The number of test cycles","B. What data is needed, how it will be created, and how sensitive data will be protected","C. The test execution schedule","D. Team member assignments"],answer:1,explanation:"Test data planning covers what data is needed, how to obtain/generate it, and data privacy compliance."},
{id:606,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"hard",question:"Root cause analysis of defects MOST benefits the testing process by:",options:["A. Identifying which testers should be retrained","B. Understanding why defects were introduced, enabling process improvements to prevent recurrence","C. Increasing the number of test cases","D. Speeding up defect fixing"],answer:1,explanation:"Root cause analysis identifies underlying process issues, enabling preventive measures for future development."},
{id:607,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"medium",question:"Which of the following is a test metric that DIRECTLY measures requirement coverage?",options:["A. Statement coverage percentage","B. Requirements coverage percentage (test cases vs. requirements)","C. Defect density","D. Test execution rate"],answer:1,explanation:"Requirements coverage = requirements with passing tests / total requirements â€” directly measures functional coverage."},
{id:608,chapter:"Managing the Test Activities",topic:"Configuration Management",difficulty:"hard",question:"Why is it important to keep test scripts synchronized with the software under test?",options:["A. To reduce test execution time","B. Outdated scripts fail for the wrong reasons, producing false failures and wasting investigation time","C. To improve code quality","D. To reduce the number of test cases"],answer:1,explanation:"Tests that fail due to outdated scripts (not defects) waste investigation time and mask real quality issues."},
{id:609,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"extreme",question:"A test manager is planning for a project with a fixed deadline and fixed budget. Which approach BEST handles the trade-off?",options:["A. Test everything; extend the deadline","B. Risk-based prioritization: ensure critical and high-risk areas are tested within budget/time","C. Test only automated tests","D. Reduce the test team to save budget"],answer:1,explanation:"With fixed constraints, risk-based prioritization maximizes testing value within the available resources."},
{id:610,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"extreme",question:"During regression testing after a major release, 5 new defects are found that were not present in the previous version. These are MOST likely caused by:",options:["A. Tester error","B. Regression defects introduced by changes made for the new version","C. Test environment problems","D. Incomplete test cases"],answer:1,explanation:"New defects found in previously working functionality are regression defects caused by recent changes."},
{id:611,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"extreme",question:"Test metrics show: requirements coverage 95%, branch coverage 60%, 5 P1 open defects, 3 P2 open, 20 P3 open. The MOST serious quality concern is:",options:["A. Requirements coverage","B. The 5 P1 critical defects","C. Branch coverage","D. The 20 P3 defects"],answer:1,explanation:"P1 critical defects are the most serious concern â€” they represent potential blocking or catastrophic failures."},
{id:612,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"hard",question:"What is the role of stakeholders in risk-based testing?",options:["A. They should not be involved in risk assessment","B. They provide business context and help identify, prioritize, and accept product risks","C. They only accept risks at the end of the project","D. They should be consulted only for critical risks"],answer:1,explanation:"Stakeholders bring business context to risk identification and ultimately decide on risk acceptance."},
{id:613,chapter:"Managing the Test Activities",topic:"Configuration Management",difficulty:"medium",question:"A 'golden environment' in testing refers to:",options:["A. The most expensive test environment","B. A clean, known-good baseline environment used as a reference for testing","C. A production-like environment for performance testing","D. The first test environment set up for a project"],answer:1,explanation:"A golden environment is a clean, stable reference state used to ensure consistent, baseline test execution."},
{id:614,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"medium",question:"Which of the following factors increases testing effort?",options:["A. Well-documented requirements","B. Complex business logic, new technology, and high risk","C. Experienced test team","D. Mature, well-tested codebase"],answer:1,explanation:"Complexity, novelty, and high risk increase testing effort; conversely, simplicity and maturity reduce it."},
{id:615,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"medium",question:"Which defect status indicates testing has confirmed the fix works correctly?",options:["A. Fixed","B. Closed","C. Resolved","D. Verified"],answer:3,explanation:"'Verified' (or 'Confirmed Fixed') status means retesting has confirmed the fix successfully resolves the defect."},
{id:616,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"medium",question:"Which of the following is a RISK indicator that testing should be extended?",options:["A. All planned tests have been executed","B. High defect discovery rate with many critical defects still being found","C. Test coverage has reached 100%","D. The test team is on schedule"],answer:1,explanation:"High ongoing defect discovery rates, especially critical ones, suggest the software needs more testing before release."},
{id:617,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"hard",question:"When a risk is 'accepted,' what happens in testing?",options:["A. The risk is eliminated","B. Testing for the risk is reduced or skipped, and the residual risk is documented and owned by stakeholders","C. The risk is transferred to the development team","D. Additional testing is done to reduce the risk"],answer:1,explanation:"Risk acceptance means stakeholders acknowledge and own the residual risk â€” testing for it may be reduced."},
{id:618,chapter:"Managing the Test Activities",topic:"Configuration Management",difficulty:"medium",question:"Which of the following is an example of a 'test baseline'?",options:["A. The performance benchmark of the test environment","B. A frozen, approved version of testware at a specific point in time","C. The initial set of requirements","D. The test team's skill level"],answer:1,explanation:"A test baseline is a formally approved snapshot of testware (plans, cases, scripts) at a specific project point."},
{id:619,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"hard",question:"A test plan is reviewed and found to be missing coverage for API testing. Which section was MOST likely incomplete?",options:["A. Test schedule","B. Test scope and test levels/types","C. Defect management","D. Resources and tools"],answer:1,explanation:"Missing test types (API testing) would be a gap in the scope or test levels/types section of the test plan."},
{id:620,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"medium",question:"Which of the following BEST describes the purpose of a defect triage meeting?",options:["A. To write new defect reports","B. To review new and open defects, assess priority, assign them, and make decisions about resolution","C. To retest fixed defects","D. To delete old closed defects"],answer:1,explanation:"Defect triage meetings review open defects, validate them, assign priorities, and decide on resolution paths."},
{id:621,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"hard",question:"A project has 30 P1 defects open 1 week before release. The test manager should MOST likely:",options:["A. Release with the open defects","B. Convene an emergency triage with all stakeholders to assess release viability","C. Close all P1 defects automatically","D. Extend the project by 3 months"],answer:1,explanation:"30 critical open defects require immediate stakeholder review â€” a release decision must be made with full information."},
{id:622,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"extreme",question:"A risk-based approach allocates 40% of testing effort to Module A (high risk), 35% to Module B (medium risk), and 25% to Module C (low risk). After release, most production defects come from Module B. This suggests:",options:["A. Risk-based testing always fails","B. Module B's risk was underestimated â€” the risk assessment should be updated for future projects","C. Module A's testing was insufficient","D. Module C should have received more testing"],answer:1,explanation:"Production defects in a 'medium risk' module suggest the risk assessment underestimated Module B's defect probability."},
{id:623,chapter:"Managing the Test Activities",topic:"Configuration Management",difficulty:"hard",question:"In Agile, how should test artifact version control be managed?",options:["A. Tested artifacts are created fresh for each sprint without version control","B. Test artifacts should be in the same version control system as code, treated as first-class project artifacts","C. Version control is only for production code","D. Test artifacts should be emailed between team members"],answer:1,explanation:"In Agile, test artifacts should be version-controlled alongside code â€” ensuring synchronized, traceable changes."},
{id:624,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"hard",question:"A tester finds a usability issue (not a functional defect) during testing. Should it be reported?",options:["A. No â€” only functional defects should be reported","B. Yes â€” usability issues should be reported as test anomalies for product owner evaluation","C. Only if the tester considers it serious","D. Only after user acceptance testing"],answer:1,explanation:"All anomalies, including usability issues, should be reported â€” the product owner decides if they need to be fixed."},
{id:625,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"medium",question:"Which of the following should be defined in a test plan for Agile development?",options:["A. A complete list of all test cases for the entire project","B. Test strategy, automation approach, continuous testing strategy, and sprint testing activities","C. The complete project schedule","D. Final release acceptance criteria only"],answer:1,explanation:"Agile test plans cover strategy, automation, continuous testing, and iterative sprint activities â€” not exhaustive upfront test case lists."},
{id:626,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"medium",question:"A test manager uses 'velocity' to predict when testing will be complete. This is MOST associated with which methodology?",options:["A. Waterfall","B. V-model","C. Agile/Scrum","D. Spiral"],answer:2,explanation:"Velocity (story points completed per sprint) is an Agile Scrum metric used for planning and forecasting."},
{id:627,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"hard",question:"A test manager decides not to test a low-risk feature due to budget constraints. This decision should be:",options:["A. Made independently without documentation","B. Documented with risk rationale and formally accepted by stakeholders","C. Hidden from stakeholders","D. Automatically approved since it is low risk"],answer:1,explanation:"Any decision to skip testing must be formally documented and accepted by stakeholders â€” even for low-risk items."},
{id:628,chapter:"Managing the Test Activities",topic:"Configuration Management",difficulty:"extreme",question:"A team uses Docker containers to spin up identical test environments for each test run. This BEST addresses which challenge?",options:["A. Test case design","B. Environment consistency and the 'works on my machine' problem","C. Defect reporting","D. Test coverage measurement"],answer:1,explanation:"Containerization ensures identical, reproducible test environments â€” eliminating environment-related test variability."},
{id:629,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"hard",question:"What is the MAIN purpose of maintaining a test data catalog?",options:["A. To document all test cases","B. To track available test data sets, their content, and status for efficient test data reuse","C. To store defect reports","D. To define test environment requirements"],answer:1,explanation:"A test data catalog enables efficient reuse, helps avoid sensitive data issues, and tracks data availability."},
{id:630,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"extreme",question:"A defect is found in the test environment that cannot be reproduced in production. This MOST likely indicates:",options:["A. The defect is not real","B. The test environment differs significantly from production â€” environment configuration should be reviewed","C. The tester made an error","D. The defect is intermittent"],answer:1,explanation:"Environment-only defects often indicate significant differences between test and production environments."},
{id:631,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"medium",question:"What does a rising defect discovery curve (finding more defects over time) typically indicate?",options:["A. The software is getting better","B. Testing is reaching new, previously untested areas or defect clustering is being encountered","C. Testing is finishing","D. The team's productivity is declining"],answer:1,explanation:"Rising defect rates typically mean testing is accessing new areas or hitting defect-dense modules."},
{id:632,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"medium",question:"Which of the following BEST describes 'risk-based regression testing'?",options:["A. Running all regression tests regardless of what changed","B. Running only regression tests for areas likely to be affected by changes, based on risk analysis","C. Avoiding regression testing to save time","D. Only running automated regression tests"],answer:1,explanation:"Risk-based regression testing focuses on areas most likely affected by changes, guided by impact analysis."},
{id:633,chapter:"Managing the Test Activities",topic:"Configuration Management",difficulty:"medium",question:"What is 'test environment parity'?",options:["A. Having equal numbers of test and production environments","B. Making the test environment as similar to production as possible","C. Running the same tests in multiple environments simultaneously","D. Ensuring test coverage equals production coverage"],answer:1,explanation:"Test environment parity means the test environment closely mirrors production to catch environment-specific defects."},
{id:634,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"hard",question:"A test manager identifies that a critical dependency (the test environment) may not be ready in time. This should be:",options:["A. Hidden from stakeholders until confirmed","B. Documented as a risk in the test plan with a mitigation strategy","C. Ignored if there's a chance it will be resolved","D. Escalated immediately without any planning"],answer:1,explanation:"Dependency risks should be documented in the test plan with mitigation strategies and reported to stakeholders."},
{id:635,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"hard",question:"What is the MAIN purpose of categorizing defects by type (e.g., logic error, missing feature, UI issue)?",options:["A. To assign blame for each defect","B. To identify patterns for process improvement and prevent similar defects in future","C. To determine who should fix the defect","D. To set defect priority automatically"],answer:1,explanation:"Categorizing defects reveals patterns (e.g., many logic errors may indicate requirements issues) for process improvement."},
{id:636,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"extreme",question:"After a sprint, the team reports 100% of tests passing. However, code coverage is only 30%. What is the MOST important concern?",options:["A. The 100% pass rate is excellent performance","B. 70% of the code was untested â€” the high pass rate is misleading and risky","C. 30% coverage is acceptable for Agile","D. More tests should be added next sprint"],answer:1,explanation:"100% pass with 30% coverage means 70% of code is completely untested â€” the pass rate is misleading."},
{id:637,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"easy",question:"Who typically owns the test plan?",options:["A. The development team lead","B. The test manager","C. The product owner","D. Senior management"],answer:1,explanation:"The test manager is the owner of the test plan â€” responsible for its creation, maintenance, and execution."},
{id:638,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"hard",question:"A system was previously released with extensive testing. A hotfix is now being applied to one small, isolated module. Risk-based testing would suggest:",options:["A. Full regression of the entire system","B. Focused testing on the changed module and its direct interactions, with lightweight smoke testing","C. No testing since the change is small","D. Full acceptance testing"],answer:1,explanation:"A small, isolated change warrants focused testing on the change and its immediate interactions â€” not full regression."},
{id:639,chapter:"Managing the Test Activities",topic:"Configuration Management",difficulty:"hard",question:"What is the relationship between configuration management and defect management?",options:["A. They are independent processes","B. Configuration management ensures defects can be traced to specific software and environment versions","C. Defect management replaces configuration management","D. Configuration management is only for environments, not defects"],answer:1,explanation:"CM enables defects to be traced to exact software versions and environments, supporting accurate investigation."},
{id:640,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"medium",question:"Which of the following BEST describes 'defect age'?",options:["A. How long a defect has been in the system before it was found","B. How long a defect has been open in the defect tracking system","C. The severity level of the defect","D. The number of days it took to fix the defect"],answer:1,explanation:"Defect age measures how long a defect has been open/unresolved â€” high age may indicate low priority or forgotten defects."},
{id:641,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"medium",question:"A master test plan covers which test levels?",options:["A. Only system testing","B. All test levels for the project â€” component, integration, system, and acceptance","C. Only acceptance testing","D. Only the test levels assigned to the test team"],answer:1,explanation:"A master test plan is the overarching plan covering all test levels and types for the entire project."},
{id:642,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"medium",question:"Which of the following test metrics helps identify test rework effort?",options:["A. Test coverage","B. Number of tests that needed to be modified due to requirement changes","C. Number of defects found","D. Test execution rate"],answer:1,explanation:"Tests modified due to requirement changes represent rework effort â€” a measure of requirements stability impact."},
{id:643,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"medium",question:"Which of the following is an example of a 'risk mitigation strategy' in testing?",options:["A. Accepting that defects will be found in production","B. Adding additional test cases for high-risk areas to reduce the probability of undetected defects","C. Reducing the test scope to finish faster","D. Asking developers to write more unit tests"],answer:1,explanation:"Adding more tests to high-risk areas is a direct mitigation of product risk â€” reducing defect probability."},
{id:644,chapter:"Managing the Test Activities",topic:"Configuration Management",difficulty:"easy",question:"Why should test results be archived at the end of a project?",options:["A. To increase server storage usage","B. For future reference, audits, regulatory compliance, and lessons learned in future projects","C. To delete them safely later","D. Because they are required for the defect management system"],answer:1,explanation:"Archived test results support audits, regulatory compliance, future project reference, and organizational learning."},
{id:645,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"hard",question:"A test plan describes testing for 'non-regression purposes' only. This means:",options:["A. Testing only new features","B. Testing to ensure existing functionality has not been broken by new changes","C. Testing without any test cases","D. Testing only defect fixes"],answer:1,explanation:"Non-regression testing ensures existing functionality remains intact after changes â€” this is regression testing."},
{id:646,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"hard",question:"A tester identifies a security vulnerability in the application. They should MOST appropriately:",options:["A. Fix it themselves","B. Report it immediately through the defect management system, marking it as security-related and high severity","C. Discuss it only with developers","D. Wait until formal security testing begins"],answer:1,explanation:"Security vulnerabilities should be reported immediately through formal channels â€” they may require urgent attention."},
{id:647,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"hard",question:"What does 'test completion' mean in the context of test monitoring?",options:["A. All planned test cases have been executed","B. Defined exit criteria have been met and the test phase is officially closed","C. The test team has been disbanded","D. All defects have been fixed and closed"],answer:1,explanation:"Test completion occurs when all defined exit criteria are met â€” not just when tests are run."},
{id:648,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"extreme",question:"A test manager documents that 'automated regression testing covers 80% of the high-risk area.' This statement represents:",options:["A. A test metric","B. Risk mitigation evidence â€” demonstrating the risk has been reduced through testing","C. A test objective","D. A test completion criterion"],answer:1,explanation:"Documenting testing coverage of high-risk areas provides evidence of risk mitigation to stakeholders."},
{id:649,chapter:"Managing the Test Activities",topic:"Configuration Management",difficulty:"medium",question:"'Test data versioning' is important because:",options:["A. Test data never changes","B. Test results may depend on specific data states â€” versioning allows reproducibility of past test runs","C. Test data versions replace test case versions","D. Only databases need versioning"],answer:1,explanation:"Test data versioning ensures the exact data used in historical test runs can be reproduced for investigation."},
{id:650,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"extreme",question:"A test plan for a cloud-native microservices application should specifically address which unique challenges?",options:["A. Manual testing only since microservices are complex","B. Service virtualization, contract testing, chaos engineering, and distributed tracing for testing","C. Ignoring integration testing since each service is independent","D. Testing only the API gateway"],answer:1,explanation:"Microservices require unique testing strategies: service virtualization, contract testing, and chaos engineering."},

// ============================================================
// CHAPTER 6: Test Tools (Q651â€“Q820)
// ============================================================
{id:651,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"easy",question:"Which of the following is an example of a test management tool?",options:["A. Selenium WebDriver","B. Jira or TestRail","C. JUnit","D. Checkmarx"],answer:1,explanation:"Jira and TestRail are test management tools used to plan, track, and manage testing activities."},
{id:652,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"easy",question:"Which of the following BEST describes a test execution tool?",options:["A. A tool that designs test cases","B. A tool that automatically executes tests and records results","C. A tool that manages defects","D. A tool that generates test data"],answer:1,explanation:"Test execution tools automatically run tests and record pass/fail results â€” e.g., Selenium, pytest, JUnit."},
{id:653,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"easy",question:"What type of tool is Selenium WebDriver?",options:["A. Static analysis tool","B. Test management tool","C. UI test automation tool","D. Performance testing tool"],answer:2,explanation:"Selenium WebDriver is a UI test automation tool for web applications."},
{id:654,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"easy",question:"Which of the following is a BENEFIT of test automation?",options:["A. Eliminates the need for test planning","B. Enables repetitive tests to be executed faster and more consistently","C. Guarantees all defects will be found","D. Replaces the need for manual testing entirely"],answer:1,explanation:"Test automation enables fast, consistent execution of repetitive tests â€” improving efficiency and coverage."},
{id:655,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"easy",question:"Which of the following is a RISK of using test automation?",options:["A. Tests run too fast","B. High initial setup cost and maintenance effort for automated test scripts","C. Tests become too consistent","D. Test management tools cost too much"],answer:1,explanation:"Automation has high initial investment and ongoing maintenance â€” a key risk, especially as code changes."},
{id:656,chapter:"Test Tools",topic:"Tool Categories",difficulty:"easy",question:"What type of testing does JMeter MOST support?",options:["A. Unit testing","B. Security testing","C. Performance/load testing","D. UI testing"],answer:2,explanation:"Apache JMeter is primarily used for performance and load testing."},
{id:657,chapter:"Test Tools",topic:"Tool Categories",difficulty:"easy",question:"Which type of tool is SonarQube?",options:["A. Test execution tool","B. Test management tool","C. Static code analysis tool","D. Performance testing tool"],answer:2,explanation:"SonarQube is a static code analysis platform for code quality and security."},
{id:658,chapter:"Test Tools",topic:"CI/CD",difficulty:"easy",question:"What does CI stand for in CI/CD?",options:["A. Continuous Inspection","B. Continuous Integration","C. Controlled Inspection","D. Continuous Installation"],answer:1,explanation:"CI stands for Continuous Integration â€” automating the build and test process on every code commit."},
{id:659,chapter:"Test Tools",topic:"CI/CD",difficulty:"easy",question:"What does CD stand for in CI/CD?",options:["A. Code Deployment","B. Continuous Delivery or Continuous Deployment","C. Controlled Development","D. Code Design"],answer:1,explanation:"CD stands for Continuous Delivery (automated deployment to staging) or Continuous Deployment (to production)."},
{id:660,chapter:"Test Tools",topic:"CI/CD",difficulty:"medium",question:"Which of the following BEST describes the role of automated tests in a CI/CD pipeline?",options:["A. Optional - only run on request","B. A quality gate that runs on every build, providing fast feedback on code quality","C. Only run before major releases","D. Only run by the QA team manually"],answer:1,explanation:"Automated tests in CI/CD run on every commit, providing fast feedback and acting as quality gates."},
{id:661,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"medium",question:"Which of the following is a test tool for API testing?",options:["A. Selenium","B. JMeter","C. Postman","D. SonarQube"],answer:2,explanation:"Postman is a widely used API testing tool for REST and SOAP services."},
{id:662,chapter:"Test Tools",topic:"Tool Categories",difficulty:"medium",question:"A tool that generates large volumes of random or semi-random inputs to find defects is called a:",options:["A. Static analyzer","B. Fuzzer","C. Load tester","D. Coverage analyzer"],answer:1,explanation:"Fuzzers (fuzzing tools) generate random or semi-random inputs to uncover security vulnerabilities and edge-case defects."},
{id:663,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"medium",question:"What is the 'Automation Pyramid' concept?",options:["A. A hierarchy recommending more automated tests at lower levels (unit) and fewer at higher levels (UI)","B. A management structure for test teams","C. A risk matrix for automation","D. A process for selecting automation tools"],answer:0,explanation:"The test automation pyramid recommends many fast unit tests at the base, fewer integration tests, and even fewer UI tests at the top."},
{id:664,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"medium",question:"A 'mock' in test automation is BEST described as:",options:["A. A test that simulates user behavior","B. A test double that simulates a dependency's behavior with programmed responses","C. A performance test script","D. An automated acceptance test"],answer:1,explanation:"A mock is a test double that simulates a dependency (e.g., an API) with programmed expected behaviors."},
{id:665,chapter:"Test Tools",topic:"CI/CD",difficulty:"medium",question:"In a CI/CD pipeline, which tests should run FIRST?",options:["A. UI tests â€” they have the most business value","B. Slowest tests â€” to find the most critical defects quickly","C. Fast unit tests â€” to get rapid feedback on basic code correctness","D. Manual tests â€” since they are most thorough"],answer:2,explanation:"Fast unit tests run first in the pipeline to give developers immediate feedback on basic code issues."},
{id:666,chapter:"Test Tools",topic:"Tool Categories",difficulty:"medium",question:"Which of the following BEST describes a 'test data generation tool'?",options:["A. A tool that executes test cases","B. A tool that creates test data (random, boundary, realistic) for use in testing","C. A tool that manages test case documentation","D. A tool that measures code coverage"],answer:1,explanation:"Test data generation tools create structured, realistic, or boundary-value data for use in test execution."},
{id:667,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"medium",question:"Which of the following is a risk when introducing a new test tool?",options:["A. Tests run too fast","B. The team may lack skills to use the tool effectively, leading to poor automation quality","C. The tool will find too many defects","D. Tests become too reproducible"],answer:1,explanation:"A key risk with new tools is lack of skills â€” poorly implemented automation can be worse than no automation."},
{id:668,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"medium",question:"A bug tracking tool like Jira is classified as what type of test tool?",options:["A. Test execution tool","B. Defect/issue tracking and test management tool","C. Static analysis tool","D. Performance monitoring tool"],answer:1,explanation:"Jira serves as both a defect tracker and a project/test management tool."},
{id:669,chapter:"Test Tools",topic:"CI/CD",difficulty:"medium",question:"Which CI/CD tool is used to automate build, test, and deployment pipelines?",options:["A. Postman","B. Jenkins","C. JUnit","D. Selenium"],answer:1,explanation:"Jenkins is a CI/CD automation server for building pipelines that include automated testing and deployment."},
{id:670,chapter:"Test Tools",topic:"Tool Categories",difficulty:"medium",question:"Which of the following is a CORRECT example of white-box test support tools?",options:["A. Selenium for UI testing","B. Code coverage tools like JaCoCo or Istanbul","C. JMeter for load testing","D. TestRail for test management"],answer:1,explanation:"Code coverage tools (JaCoCo, Istanbul) support white-box testing by measuring statement and branch coverage."},
{id:671,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"hard",question:"What is the purpose of a 'test oracle' in automated testing?",options:["A. A testing expert who validates test results","B. A mechanism that determines whether the actual output of a test matches the expected output","C. An automation tool that generates test cases","D. A CI/CD server"],answer:1,explanation:"In automation, the test oracle is the comparison mechanism that determines pass/fail by comparing actual vs. expected results."},
{id:672,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"hard",question:"The ROI (Return on Investment) of test automation is MOST difficult to justify when:",options:["A. Tests are run frequently in regression","B. The software changes frequently, requiring constant script maintenance","C. The test team is large","D. The organization has a long-term project"],answer:1,explanation:"Frequent software changes increase maintenance costs, making ROI difficult to justify for automation."},
{id:673,chapter:"Test Tools",topic:"CI/CD",difficulty:"hard",question:"Continuous Deployment differs from Continuous Delivery in that:",options:["A. They are the same thing","B. Continuous Deployment automatically deploys to production; Continuous Delivery requires manual approval","C. Continuous Delivery deploys to production; Continuous Deployment deploys to staging","D. Continuous Deployment is only for startups"],answer:1,explanation:"CD (Deployment) automatically pushes to production; CD (Delivery) prepares the release but requires human approval."},
{id:674,chapter:"Test Tools",topic:"Tool Categories",difficulty:"hard",question:"A tool that monitors system behavior and performance metrics in production is BEST categorized as:",options:["A. Test execution tool","B. Observability or monitoring tool supporting shift-right testing","C. Static analysis tool","D. Test data tool"],answer:1,explanation:"Production monitoring/observability tools support shift-right testing by detecting issues in live environments."},
{id:675,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"hard",question:"Which of the following BEST describes 'test automation debt'?",options:["A. The cost of test automation tools","B. The accumulation of unmaintained, outdated, or poorly written automated tests that reduce test suite reliability","C. A financial obligation for test tool licenses","D. The difference between manual and automated test counts"],answer:1,explanation:"Test automation debt is the accumulation of unmaintained scripts that fail for the wrong reasons, reducing trust in automation."},
{id:676,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"hard",question:"A 'headless browser' in test automation is BEST described as:",options:["A. A browser without a graphical user interface, used for faster automated testing","B. A browser that hides the test execution from users","C. A virtual machine for running browsers","D. A lightweight browser for mobile testing"],answer:0,explanation:"Headless browsers run without a GUI, enabling faster automated web testing in CI pipelines."},
{id:677,chapter:"Test Tools",topic:"CI/CD",difficulty:"hard",question:"A 'shift-left' approach in CI/CD means:",options:["A. Moving deployment to a different team","B. Running tests as early as possible in the build pipeline â€” unit tests before integration before UI","C. Shifting developer responsibilities to testers","D. Moving manual tests earlier in the schedule"],answer:1,explanation:"Shift-left in CI/CD runs the fastest, most basic tests first (unit), catching issues before slower tests run."},
{id:678,chapter:"Test Tools",topic:"Tool Categories",difficulty:"hard",question:"Behavior-Driven Development (BDD) frameworks like Cucumber are BEST classified as:",options:["A. Performance testing tools","B. Executable specification and acceptance test automation frameworks","C. Static analysis tools","D. Load testing frameworks"],answer:1,explanation:"Cucumber and similar BDD frameworks enable Given-When-Then scenarios to be executed as automated acceptance tests."},
{id:679,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"hard",question:"Which of the following BEST describes a 'false positive' in automated testing?",options:["A. A test that correctly identifies a defect","B. A test that reports a failure when the software is actually working correctly","C. A test that passes when there is a defect","D. A test that is incorrectly written"],answer:1,explanation:"A false positive is when an automated test fails despite the software being correct â€” often due to brittle test scripts."},
{id:680,chapter:"Test Tools",topic:"CI/CD",difficulty:"hard",question:"Canary releases are used in CD pipelines to:",options:["A. Test systems using canary users","B. Gradually roll out changes to a small subset of users before full deployment","C. Test software in isolated canary environments","D. Deploy software only to testing environments"],answer:1,explanation:"Canary releases deploy to a small user percentage first, monitoring for issues before full rollout."},
{id:681,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"extreme",question:"A test team is evaluating automation tools for a complex enterprise application. The MOST important criteria for selection should include:",options:["A. The tool with the most features","B. Compatibility with the application technology stack, team skills, maintenance cost, and integration capability","C. The tool with the lowest license cost","D. The most popular tool by downloads"],answer:1,explanation:"Tool selection must consider technical fit, team skills, total cost of ownership, and integration with the CI/CD ecosystem."},
{id:682,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"extreme",question:"A team automates 1000 tests but 300 fail intermittently without real defects (flaky tests). This MOST likely indicates:",options:["A. The software has 300 defects","B. Poor automation quality â€” tests depend on timing, shared state, or external services causing intermittent failures","C. The automation tool is defective","D. The test environment is too fast"],answer:1,explanation:"Flaky tests (intermittent failures without real defects) indicate brittle automation that depends on timing, state, or external dependencies."},
{id:683,chapter:"Test Tools",topic:"CI/CD",difficulty:"extreme",question:"A CI pipeline runs 5000 automated tests after every commit. The pipeline takes 2 hours to complete. Developers complain the feedback is too slow. The BEST solution is:",options:["A. Run only 100 tests","B. Parallelize tests across multiple agents and optimize the pipeline structure","C. Run tests only once per day","D. Reduce the number of tests"],answer:1,explanation:"Test parallelization across multiple agents is the best way to speed up large test suites without reducing coverage."},
{id:684,chapter:"Test Tools",topic:"Tool Categories",difficulty:"extreme",question:"A team implements contract testing between microservices using Pact. This BEST addresses which testing challenge?",options:["A. UI testing across browsers","B. Verifying integration contracts between services without requiring all services to run simultaneously","C. Performance testing of individual services","D. Static analysis of service code"],answer:1,explanation:"Contract testing (Pact) verifies API contracts between consumer and provider services independently."},
{id:685,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"hard",question:"Which of the following is NOT a benefit of using test management tools?",options:["A. Centralized test case storage and version control","B. Test execution scheduling and tracking","C. Automatic defect fixing","D. Reporting and metrics generation"],answer:2,explanation:"Test management tools do not automatically fix defects â€” they support tracking, management, and reporting."},
{id:686,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"medium",question:"Which type of tool supports accessibility testing?",options:["A. JMeter","B. axe or WAVE (accessibility evaluation tools)","C. Selenium","D. JUnit"],answer:1,explanation:"Accessibility tools like axe and WAVE evaluate web content against WCAG accessibility standards."},
{id:687,chapter:"Test Tools",topic:"CI/CD",difficulty:"medium",question:"In a DevOps pipeline, 'infrastructure as code' (IaC) supports testing by:",options:["A. Replacing test automation","B. Enabling automated, repeatable test environment provisioning","C. Monitoring production systems","D. Writing test cases automatically"],answer:1,explanation:"IaC enables automated, version-controlled environment setup â€” ensuring consistent test environments for CI/CD."},
{id:688,chapter:"Test Tools",topic:"Tool Categories",difficulty:"medium",question:"A tool that monitors network traffic between the browser and server during testing is BEST described as:",options:["A. Load testing tool","B. Network proxy / performance monitoring tool","C. Static analysis tool","D. Code coverage tool"],answer:1,explanation:"Network proxy tools (e.g., Charles Proxy, Fiddler) capture and analyze network traffic during testing."},
{id:689,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"extreme",question:"An organization spends 60% of their automation maintenance effort on UI tests. This BEST supports which recommendation?",options:["A. Add more UI tests to justify the investment","B. Shift more coverage to unit and API tests â€” UI tests are brittle and expensive to maintain","C. Replace the automation team","D. Stop automating and revert to manual testing"],answer:1,explanation:"UI tests are inherently brittle and maintenance-heavy â€” the automation pyramid recommends minimal UI test coverage."},
{id:690,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"hard",question:"A 'stub' in test automation differs from a 'mock' in that:",options:["A. Stubs provide canned responses; mocks also verify interactions occurred as expected","B. Stubs are only used in unit testing; mocks in integration testing","C. They are identical concepts","D. Mocks are slower than stubs"],answer:0,explanation:"Stubs provide pre-programmed responses; mocks additionally verify that specific interactions (calls) occurred correctly."},
{id:691,chapter:"Test Tools",topic:"CI/CD",difficulty:"medium",question:"A 'quality gate' in a CI/CD pipeline would typically fail a build when:",options:["A. A developer pushes code","B. Code coverage drops below the defined threshold or new critical defects are introduced","C. Tests take longer than expected","D. A new branch is created"],answer:1,explanation:"Quality gates enforce standards like minimum coverage, maximum code smells, or no new critical issues."},
{id:692,chapter:"Test Tools",topic:"Tool Categories",difficulty:"hard",question:"Chaos Monkey, developed by Netflix, is an example of which type of test tool?",options:["A. Unit testing framework","B. Chaos engineering / resilience testing tool","C. Static analysis tool","D. Test data generator"],answer:1,explanation:"Chaos Monkey is a chaos engineering tool that randomly terminates instances to test system resilience."},
{id:693,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"medium",question:"Test automation provides the GREATEST benefit when tests are:",options:["A. Run once per quarter","B. Run frequently and repeatedly â€” e.g., on every code commit in CI","C. Run only before major releases","D. Run manually with automated recording"],answer:1,explanation:"Automation ROI improves with frequency of execution â€” the more often tests run, the more value they provide."},
{id:694,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"medium",question:"What is the purpose of 'test data masking' tools?",options:["A. To hide test results from stakeholders","B. To anonymize sensitive production data for safe use in testing environments","C. To generate random test data","D. To mask test cases from unauthorized users"],answer:1,explanation:"Data masking tools anonymize real production data (PII, financial data) for safe use in non-production environments."},
{id:695,chapter:"Test Tools",topic:"CI/CD",difficulty:"hard",question:"In a DevOps pipeline, 'feature flags' support testing by:",options:["A. Flagging failing tests as features","B. Enabling code to be deployed but features to be turned on/off, supporting gradual rollout and A/B testing","C. Marking high-priority features for testing","D. Automatically generating feature tests"],answer:1,explanation:"Feature flags enable deployed code to be toggled on/off, supporting gradual rollouts, A/B testing, and dark launches."},
{id:696,chapter:"Test Tools",topic:"Tool Categories",difficulty:"hard",question:"DAST (Dynamic Application Security Testing) differs from SAST in that:",options:["A. DAST is performed without executing the application","B. DAST analyzes running applications from the outside; SAST analyzes static code","C. SAST finds more vulnerabilities than DAST","D. DAST is only for mobile applications"],answer:1,explanation:"DAST tests live running applications (black-box); SAST analyzes source code statically â€” they are complementary."},
{id:697,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"hard",question:"Which of the following is a SUCCESS factor for test automation adoption?",options:["A. Automating everything immediately","B. Starting with high-value, stable tests and gradually expanding with a clear automation strategy","C. Replacing all manual testers with automation","D. Choosing the most expensive tool"],answer:1,explanation:"Successful automation starts with stable, high-value tests and grows incrementally with a clear strategy."},
{id:698,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"hard",question:"What is 'keyword-driven test automation'?",options:["A. Testing using search engine keywords","B. An automation framework where test logic is defined using readable keyword actions, enabling non-programmers to create tests","C. Testing that searches for keywords in application output","D. An automated test tool for content testing"],answer:1,explanation:"Keyword-driven automation uses action keywords (click, enter, verify) so testers without coding skills can create tests."},
{id:699,chapter:"Test Tools",topic:"CI/CD",difficulty:"extreme",question:"A team uses blue-green deployment in their CD pipeline. This supports testing by:",options:["A. Running tests only in blue environments","B. Allowing instant rollback to the previous stable environment if testing reveals issues in the new version","C. Using two different testing tools simultaneously","D. Splitting tests across development teams"],answer:1,explanation:"Blue-green deployment maintains two identical environments â€” enabling instant rollback if the new deployment fails testing."},
{id:700,chapter:"Test Tools",topic:"Tool Categories",difficulty:"hard",question:"An 'API contract testing' tool like Pact addresses which challenge?",options:["A. UI testing across browsers","B. Ensuring consumer-provider API contracts are maintained as services evolve independently","C. Performance testing of APIs","D. Security testing of API endpoints"],answer:1,explanation:"Contract testing ensures that as microservices evolve, the API contracts between them remain compatible."},
{id:701,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"medium",question:"Which of the following is a characteristic of a GOOD automated test?",options:["A. It is difficult to maintain","B. It is fast, reliable, independent, and provides clear failure messages","C. It depends on the execution order of other tests","D. It requires manual verification of results"],answer:1,explanation:"Good automated tests are FIRST: Fast, Independent, Reliable, Self-validating, Timely."},
{id:702,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"medium",question:"'Test automation cannot replace exploratory testing' because:",options:["A. Automation tools are too slow","B. Automation tests known scenarios; exploratory testing discovers unknown defects through human creativity","C. Automation is only useful for regression","D. Exploratory testing is always cheaper"],answer:1,explanation:"Automation verifies known scenarios reliably; exploratory testing discovers unexpected defects through human ingenuity."},
{id:703,chapter:"Test Tools",topic:"CI/CD",difficulty:"hard",question:"A monorepo CI pipeline runs all 50,000 tests on every commit, taking 4 hours. The MOST effective optimization is:",options:["A. Reduce the number of tests","B. Implement test selection â€” only run tests affected by changed code using impact analysis","C. Run only smoke tests","D. Switch to a different CI tool"],answer:1,explanation:"Test impact analysis selects only tests affected by changes, dramatically reducing CI execution time without losing coverage."},
{id:704,chapter:"Test Tools",topic:"Tool Categories",difficulty:"medium",question:"Which of the following is an example of an IDE (Integrated Development Environment) plugin for test support?",options:["A. JMeter","B. TestNG or JUnit plugin integrated into IntelliJ or Eclipse","C. Jenkins","D. Postman"],answer:1,explanation:"IDE plugins like JUnit/TestNG integrations allow developers to run and debug unit tests directly in their IDE."},
{id:705,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"extreme",question:"An organization is considering replacing their current test management tool. The MOST important consideration is:",options:["A. The new tool has more features","B. Migration of existing test data, team adoption, integration with current tools, and total cost of ownership","C. The vendor's market position","D. The number of API integrations available"],answer:1,explanation:"Tool replacement requires careful evaluation of migration complexity, team adoption, integration, and TCO."},
{id:706,chapter:"Test Tools",topic:"CI/CD",difficulty:"extreme",question:"GitOps is an approach where:",options:["A. Git is used only for code version control","B. Infrastructure and application configurations are managed through Git, enabling audit trails and automated CI/CD","C. Testing is done only in Git branches","D. Git replaces CI/CD tools"],answer:1,explanation:"GitOps uses Git as the single source of truth for infrastructure and application state, enabling automated CD."},
{id:707,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"hard",question:"What is the role of 'Page Object Model' in UI test automation?",options:["A. A method to reduce the number of tests","B. A design pattern that creates an abstraction layer between test code and UI elements, reducing maintenance","C. A tool for recording UI tests","D. A performance testing approach for pages"],answer:1,explanation:"Page Object Model abstracts UI element locators into reusable page classes, making tests more maintainable."},
{id:708,chapter:"Test Tools",topic:"Tool Categories",difficulty:"hard",question:"A 'service virtualization' tool is MOST useful when:",options:["A. Testing requires expensive or unavailable third-party services","B. Testing the UI of an application","C. Analyzing code coverage","D. Managing test cases"],answer:0,explanation:"Service virtualization simulates unavailable/costly dependencies (third-party APIs, legacy systems) for testing."},
{id:709,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"hard",question:"Which of the following BEST describes the risk of 'over-reliance on automated testing'?",options:["A. Tests will run too fast","B. The team may miss exploratory defects and reduce manual testing skills, creating blind spots","C. Test coverage will be too high","D. The automation tool will automatically find all defects"],answer:1,explanation:"Over-reliance on automation means unknown defects go undiscovered â€” human creativity in testing remains essential."},
{id:710,chapter:"Test Tools",topic:"CI/CD",difficulty:"hard",question:"Which metric in a CI/CD pipeline measures how quickly failing tests are detected and fixed?",options:["A. Build success rate","B. Mean Time To Detect (MTTD) and Mean Time To Recovery (MTTR)","C. Number of test cases executed","D. Code coverage percentage"],answer:1,explanation:"MTTD and MTTR measure how quickly the team detects and recovers from CI failures â€” key pipeline health metrics."},
{id:711,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"medium",question:"Appium is used for which type of testing?",options:["A. API testing","B. Desktop application testing","C. Mobile application testing","D. Performance testing"],answer:2,explanation:"Appium is a cross-platform mobile test automation framework for iOS and Android applications."},
{id:712,chapter:"Test Tools",topic:"Tool Categories",difficulty:"medium",question:"A tool that records user actions in a browser and generates automated test scripts is called a:",options:["A. Static analyzer","B. Test recorder","C. Mock generator","D. Coverage analyzer"],answer:1,explanation:"Test recorders capture user interactions and generate automation scripts â€” e.g., Selenium IDE, Katalon Recorder."},
{id:713,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"hard",question:"What is 'test script fragility' in automation?",options:["A. Scripts that run too fast","B. Automated tests that break easily when minor UI or API changes occur","C. Scripts that take too long to write","D. Scripts that are difficult to read"],answer:1,explanation:"Fragile scripts break with minor changes (renamed UI elements, layout changes), requiring frequent maintenance."},
{id:714,chapter:"Test Tools",topic:"CI/CD",difficulty:"medium",question:"Which of the following is a TEST in a typical CI pipeline ordered correctly?",options:["A. UI tests > Integration tests > Unit tests","B. Unit tests > Integration tests > E2E/UI tests","C. E2E tests > Unit tests > Integration tests","D. All tests in parallel simultaneously"],answer:1,explanation:"The CI pipeline follows the test pyramid: unit (fastest, most) first, integration next, UI/E2E (slowest, fewest) last."},
{id:715,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"extreme",question:"A team uses AI-powered test generation tools that analyze code and generate test cases automatically. Which benefit is MOST realistic?",options:["A. Complete test coverage with no manual effort","B. Reduced test creation time with AI-suggested test cases that still require human review","C. Replacement of all manual testing","D. Guaranteed defect-free software"],answer:1,explanation:"AI test generation accelerates test creation but generated tests still require human review for correctness and completeness."},
{id:716,chapter:"Test Tools",topic:"Tool Categories",difficulty:"hard",question:"A 'test harness' is BEST described as:",options:["A. A physical safety device for testers","B. A collection of software and test data that enables a component to be tested in isolation","C. A test management tool","D. A CI/CD server"],answer:1,explanation:"A test harness includes stubs, drivers, and supporting code that enables testing of components in isolation."},
{id:717,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"extreme",question:"An organization has 3000 automated tests but deploys new features every 2 hours. The main challenge is likely:",options:["A. Too many tests","B. Test maintenance and flakiness at high velocity â€” keeping 3000 tests green requires continuous effort","C. Too few developers","D. Tests are too slow"],answer:1,explanation:"High deployment velocity with many tests creates constant maintenance pressure â€” flaky or outdated tests block CI."},
{id:718,chapter:"Test Tools",topic:"CI/CD",difficulty:"extreme",question:"A team implements 'test sharding' in their CI pipeline. This means:",options:["A. Reducing the number of tests","B. Splitting the test suite across multiple parallel machines to reduce execution time","C. Running the same test multiple times to verify stability","D. Sharding database test data"],answer:1,explanation:"Test sharding distributes tests across multiple parallel executors, dramatically reducing total pipeline duration."},
{id:719,chapter:"Test Tools",topic:"Tool Categories",difficulty:"extreme",question:"RASP (Runtime Application Self-Protection) differs from DAST/SAST in that:",options:["A. RASP is a testing tool run by the test team","B. RASP is a runtime security tool embedded in the application that detects and blocks attacks in production","C. RASP only works for web applications","D. RASP replaces penetration testing"],answer:1,explanation:"RASP is a production security tool that operates at runtime â€” it's not a testing tool but complements security testing."},
{id:720,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"medium",question:"Which of the following is a MAIN advantage of using a version control system for test scripts?",options:["A. Tests run faster","B. History of changes is maintained, enabling reversion, collaboration, and auditability","C. Tests are automatically generated","D. Test execution is automated"],answer:1,explanation:"Version control maintains change history, enables team collaboration, and allows rollback to working versions."},

{id:721,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"medium",question:"What is a 'test environment as a service' (TEaaS)?",options:["A. A physical test lab service","B. Cloud-based, on-demand test environment provisioning for testing","C. A testing outsourcing service","D. An environment monitoring service"],answer:1,explanation:"TEaaS provides cloud-based, on-demand test environments, enabling scalable and cost-effective test infrastructure."},
{id:722,chapter:"Test Tools",topic:"CI/CD",difficulty:"hard",question:"In a CI/CD pipeline, 'shift-right' testing includes:",options:["A. Moving all testing earlier in the pipeline","B. A/B testing, canary releases, and production monitoring to catch issues in live environments","C. Running right-aligned test reports","D. Performing only manual tests"],answer:1,explanation:"Shift-right practices include A/B testing, canary releases, chaos engineering, and production monitoring."},
{id:723,chapter:"Test Tools",topic:"Tool Categories",difficulty:"medium",question:"Which of the following BEST describes 'model-based testing'?",options:["A. Testing using financial models","B. Automatically generating test cases from a model (state machine, UML) of the system under test","C. Testing 3D model rendering","D. A manual testing approach for complex systems"],answer:1,explanation:"Model-based testing uses formal models (state machines, UML) to automatically generate test cases."},
{id:724,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"hard",question:"Which of the following is a risk specific to cloud-based test execution tools?",options:["A. Tests run too fast","B. Data security concerns, vendor lock-in, and dependency on internet connectivity","C. Limited test case storage","D. Tests cannot be automated"],answer:1,explanation:"Cloud testing tools raise concerns about data security, vendor lock-in, and connectivity dependency."},
{id:725,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"medium",question:"A 'spy' in test automation is BEST described as:",options:["A. A security test that monitors application activity","B. A test double that records interactions for later assertion while still calling the real implementation","C. A tool that monitors test execution","D. A mock that simulates all interactions"],answer:1,explanation:"A spy wraps the real implementation and records calls to it, allowing assertions about how the code was used."},
{id:726,chapter:"Test Tools",topic:"CI/CD",difficulty:"medium",question:"What is the purpose of a 'release gate' in CD?",options:["A. A physical security gate at the data center","B. An automated check that must pass before deployment proceeds to the next environment","C. A manual review step by the QA team","D. A documentation review checkpoint"],answer:1,explanation:"Release gates are automated pass/fail checks (tests, coverage, security scans) that control pipeline progression."},
{id:727,chapter:"Test Tools",topic:"Tool Categories",difficulty:"easy",question:"Which of the following is an example of a static analysis tool?",options:["A. Selenium WebDriver","B. SonarQube","C. JMeter","D. TestRail"],answer:1,explanation:"SonarQube is a static analysis tool for code quality and security â€” it analyzes code without execution."},
{id:728,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"medium",question:"'Test automation as part of the CI/CD pipeline' provides which PRIMARY benefit?",options:["A. Eliminates all manual testing","B. Provides fast, automated feedback to developers within minutes of a code change","C. Reduces the need for test planning","D. Guarantees 100% code coverage"],answer:1,explanation:"CI/CD automation provides the core DevOps benefit: fast feedback loops that enable rapid, quality-assured delivery."},
{id:729,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"hard",question:"Which of the following is NOT a purpose of test automation?",options:["A. Running regression tests faster","B. Providing consistent, repeatable test execution","C. Replacing the need for test strategy and planning","D. Enabling tests to run overnight"],answer:2,explanation:"Automation does not replace test strategy â€” strategic decisions about what and how to test remain human responsibilities."},
{id:730,chapter:"Test Tools",topic:"Tool Categories",difficulty:"hard",question:"Which type of tool would help ensure that a web application meets WCAG 2.1 accessibility standards?",options:["A. Performance testing tool","B. Accessibility testing tool (e.g., axe, WAVE)","C. Security scanning tool","D. Load testing tool"],answer:1,explanation:"Accessibility tools like axe and WAVE automatically check web pages against WCAG accessibility guidelines."},
{id:731,chapter:"Test Tools",topic:"CI/CD",difficulty:"extreme",question:"A team implements 'progressive delivery' with feature flags and canary releases. This approach BEST supports which testing objective?",options:["A. Eliminating system testing","B. Testing new features in production gradually, limiting blast radius while gathering real user feedback","C. Replacing all automated testing","D. Reducing test planning effort"],answer:1,explanation:"Progressive delivery enables safe production testing â€” features are gradually exposed to users with monitoring."},
{id:732,chapter:"Test Tools",topic:"Tool Categories",difficulty:"hard",question:"A tool that provides a record of all API calls made during a test session for debugging is BEST described as:",options:["A. Static analyzer","B. API monitoring/proxy tool","C. Test management tool","D. Code coverage tool"],answer:1,explanation:"API monitoring and proxy tools record all API interactions, enabling debugging and contract verification."},
{id:733,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"extreme",question:"An organization has 80% automated test coverage but still has frequent production escapes. The MOST likely cause is:",options:["A. Too much automation","B. The automated tests cover the wrong scenarios or have weak assertions","C. The automation tool is defective","D. The testers are not skilled enough"],answer:1,explanation:"High coverage with poor assertions or wrong scenarios means tests run but don't verify the right behaviors."},
{id:734,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"medium",question:"Which of the following is an example of a 'test double'?",options:["A. Running a test twice to confirm results","B. A stub, mock, spy, fake, or dummy used to replace a real component in testing","C. A pair of testers executing the same test","D. A duplicate test case"],answer:1,explanation:"Test doubles (stubs, mocks, spies, fakes, dummies) replace real components to enable isolated testing."},
{id:735,chapter:"Test Tools",topic:"CI/CD",difficulty:"hard",question:"Which of the following BEST describes the purpose of a 'smoke test' in a CI/CD pipeline?",options:["A. To test the system's fire suppression","B. A quick sanity check that verifies the most critical functions work before running the full suite","C. A performance test at pipeline startup","D. A security test run on every commit"],answer:1,explanation:"Smoke tests quickly verify basic functionality works before investing time in the full test suite."},
{id:736,chapter:"Test Tools",topic:"Tool Categories",difficulty:"medium",question:"Unit testing frameworks like JUnit, pytest, or NUnit provide which core feature?",options:["A. UI recording and playback","B. Test organization, assertion libraries, test runner, and reporting","C. Load simulation for performance testing","D. API endpoint testing"],answer:1,explanation:"Unit test frameworks provide: test organization (suites), assertion methods, test runners, and result reporting."},
{id:737,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"medium",question:"A team adopts test automation without first ensuring their tests are designed well. The MOST likely outcome is:",options:["A. Excellent test automation quality","B. Automated bad tests â€” fast execution of poorly designed tests with poor coverage","C. Improved software quality immediately","D. Reduced defect rate"],answer:1,explanation:"Automating poorly designed tests accelerates the production of low-quality test output â€” 'garbage in, garbage out.'"},
{id:738,chapter:"Test Tools",topic:"CI/CD",difficulty:"medium",question:"Which of the following is a BENEFIT of integrating security testing into the CI/CD pipeline (DevSecOps)?",options:["A. Security vulnerabilities can only be found after deployment","B. Security issues are detected early in the pipeline when they are cheapest to fix","C. Security testing replaces penetration testing","D. Security tools eliminate all vulnerabilities"],answer:1,explanation:"DevSecOps shifts security testing left â€” finding vulnerabilities early in CI is far cheaper than fixing post-deployment."},
{id:739,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"hard",question:"What is the purpose of a 'test fixture' in automated testing?",options:["A. A physical device for hardware testing","B. A set of preconditions and context (data, environment state) established before a test runs","C. A reporting template","D. An assertion mechanism"],answer:1,explanation:"A test fixture sets up the known state (data, environment) needed before a test runs, ensuring consistent preconditions."},
{id:740,chapter:"Test Tools",topic:"Tool Categories",difficulty:"extreme",question:"A team uses AI-powered tools to predict which tests are most likely to fail based on code change analysis. This BEST represents:",options:["A. Full regression testing","B. AI-assisted test impact analysis and risk-based test selection","C. Static code analysis","D. Random test selection"],answer:1,explanation:"AI-powered test impact analysis predicts which tests to run based on changed code â€” optimizing CI feedback loops."},
{id:741,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"hard",question:"Which of the following BEST describes a 'brittle test'?",options:["A. A test that fails too quickly","B. A test that fails due to minor, unrelated changes in the application or environment","C. A test with weak assertions","D. A test that cannot be automated"],answer:1,explanation:"Brittle tests fail on minor, unrelated changes (UI layout shifts, timing changes) â€” a major maintenance burden."},
{id:742,chapter:"Test Tools",topic:"CI/CD",difficulty:"extreme",question:"A team uses 'mutation testing' to evaluate test suite quality. This involves:",options:["A. Running tests in random order","B. Injecting small defects (mutations) into code and checking if tests detect them","C. Testing code that has been modified","D. A type of security testing"],answer:1,explanation:"Mutation testing introduces small code changes (mutations) and checks if tests fail â€” measuring test suite effectiveness."},
{id:743,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"hard",question:"What is a 'test pyramid' and why is it relevant to tool selection?",options:["A. A 3D model for test data","B. A model recommending many unit tests, fewer integration tests, and few UI tests, guiding tool investment","C. A way to prioritize test cases","D. A security testing framework"],answer:1,explanation:"The test pyramid guides tool investment: invest in unit testing frameworks, fewer integration tools, minimal UI tools."},
{id:744,chapter:"Test Tools",topic:"Tool Categories",difficulty:"hard",question:"Which tool type is MOST appropriate for testing that the system handles millions of records without performance degradation?",options:["A. Unit testing framework","B. Volume testing tool","C. Security scanner","D. Accessibility tool"],answer:1,explanation:"Volume testing tools can simulate large data loads to verify system performance with millions of records."},
{id:745,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"hard",question:"An automated test that always passes is MOST likely:",options:["A. A well-written test","B. A test with no assertions (never fails â€” but also never catches defects)","C. A performance test","D. A fully reliable test"],answer:1,explanation:"Tests without assertions always 'pass' â€” they execute but never verify anything, providing false confidence."},
{id:746,chapter:"Test Tools",topic:"CI/CD",difficulty:"hard",question:"Why is it important to store CI/CD pipeline configurations in version control?",options:["A. To make the pipeline faster","B. To track changes, enable audit trails, and allow rollback of pipeline configuration changes","C. To share the pipeline with competitors","D. To reduce storage costs"],answer:1,explanation:"Version-controlled pipeline configs provide audit trails, change history, and rollback capability."},
{id:747,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"medium",question:"What type of testing tool is Playwright?",options:["A. API testing tool","B. Cross-browser web UI test automation framework","C. Mobile testing tool","D. Performance testing tool"],answer:1,explanation:"Playwright is a modern cross-browser end-to-end web testing framework supporting Chrome, Firefox, and WebKit."},
{id:748,chapter:"Test Tools",topic:"Tool Categories",difficulty:"medium",question:"A tool that captures and replays network traffic for regression testing of APIs is BEST described as:",options:["A. Static analyzer","B. API traffic recorder/replay tool","C. UI automation tool","D. Code coverage tool"],answer:1,explanation:"API traffic recorders capture real API interactions and replay them as regression tests."},
{id:749,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"extreme",question:"A team's CI pipeline takes 45 minutes to complete. Developers push code 20 times per day. The pipeline queue is growing. The BEST solution is:",options:["A. Reduce code pushes","B. Optimize the pipeline with parallelization, caching, and test sharding","C. Increase the number of developers","D. Only run tests once per day"],answer:1,explanation:"Pipeline optimization through parallelization, dependency caching, and test sharding reduces wait times."},
{id:750,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"easy",question:"Which of the following BEST describes the purpose of test automation?",options:["A. To replace all human testing activities","B. To automate repetitive, time-consuming tests to free up testers for higher-value activities","C. To guarantee the software is defect-free","D. To reduce the need for test planning"],answer:1,explanation:"Automation handles repetitive tasks (regression, smoke tests) so testers focus on exploratory and complex testing."},
{id:751,chapter:"Test Tools",topic:"CI/CD",difficulty:"easy",question:"In CI/CD, 'fail fast' means:",options:["A. Fixing defects quickly","B. Running the fastest tests first to detect failures as quickly as possible","C. Releasing software faster","D. Failing all tests before release"],answer:1,explanation:"Fail-fast in CI/CD means running quick unit tests first so failures are discovered and reported immediately."},
{id:752,chapter:"Test Tools",topic:"Tool Categories",difficulty:"easy",question:"A 'coverage tool' helps testers understand:",options:["A. Which requirements have been tested","B. Which parts of the code have been executed during testing","C. Which defects have been found","D. Which test cases have been executed"],answer:1,explanation:"Code coverage tools measure which code statements, branches, or paths have been exercised during testing."},
{id:753,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"medium",question:"Test data privacy compliance tools help with:",options:["A. Improving test execution speed","B. Ensuring sensitive data (PII, financial) is masked or anonymized in test environments","C. Generating more test cases","D. Monitoring production systems"],answer:1,explanation:"Data privacy tools ensure compliance with GDPR, HIPAA, and similar regulations in test environments."},
{id:754,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"hard",question:"What is 'Property-Based Testing'?",options:["A. Testing software properties like color and font","B. A testing approach where tests verify that properties/invariants hold for a large set of automatically generated inputs","C. A test management approach","D. Testing real estate management software"],answer:1,explanation:"Property-based testing generates many inputs automatically and verifies that defined properties always hold."},
{id:755,chapter:"Test Tools",topic:"CI/CD",difficulty:"hard",question:"In a CD pipeline, which automated activity is performed LAST before production deployment?",options:["A. Unit testing","B. Performance testing","C. Smoke testing of the staging environment","D. Static code analysis"],answer:2,explanation:"Final smoke/acceptance testing in the staging environment is typically the last gate before production deployment."},
{id:756,chapter:"Test Tools",topic:"Tool Categories",difficulty:"hard",question:"A 'runtime dependency injection' framework in testing enables:",options:["A. Injecting SQL into databases for security testing","B. Replacing real dependencies with test doubles at runtime without modifying production code","C. Generating test data at runtime","D. Monitoring runtime performance"],answer:1,explanation:"DI frameworks allow replacing real dependencies (databases, services) with mocks/stubs without changing production code."},
{id:757,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"hard",question:"What is the main reason test automation ROI is difficult to measure?",options:["A. Automation tools cost too much","B. The value is in prevented defects and saved time â€” both are hard to quantify precisely","C. ROI only applies to commercial tools","D. Automation does not provide real value"],answer:1,explanation:"ROI from test automation is hard to measure because prevented defects and time savings are counterfactual â€” hard to prove."},
{id:758,chapter:"Test Tools",topic:"CI/CD",difficulty:"medium",question:"What does 'build promotion' mean in a CD pipeline?",options:["A. Promoting the best developer who built the pipeline","B. Moving a successfully tested build artifact to the next environment (dev -> staging -> production)","C. Increasing the build server's compute power","D. Updating the build server software"],answer:1,explanation:"Build promotion moves verified artifacts through pipeline stages â€” dev to staging to production."},
{id:759,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"medium",question:"Which type of test tool helps manage and execute performance test scenarios?",options:["A. JUnit","B. Apache JMeter or Gatling","C. SonarQube","D. TestRail"],answer:1,explanation:"JMeter and Gatling are performance testing tools for load, stress, and endurance testing."},
{id:760,chapter:"Test Tools",topic:"Tool Categories",difficulty:"hard",question:"Which of the following is a PRIMARY advantage of using BDD frameworks for test automation?",options:["A. Faster test execution","B. Tests are written in readable natural language that all stakeholders can understand and verify","C. Better code coverage","D. Reduced test maintenance"],answer:1,explanation:"BDD's readable Given-When-Then format bridges the gap between technical tests and business understanding."},
{id:761,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"medium",question:"An organization uses the same automated tests for system and regression testing. A key risk is:",options:["A. Tests run too frequently","B. Changes in the system may not be reflected in the automated tests, missing new regression scenarios","C. Tests run too slowly","D. Too many tests are executed"],answer:1,explanation:"Automation must be maintained to reflect system changes â€” static scripts become obsolete and miss new scenarios."},
{id:762,chapter:"Test Tools",topic:"CI/CD",difficulty:"hard",question:"Which metric BEST measures CI pipeline health?",options:["A. Number of tests in the pipeline","B. Build success rate and mean time between build failures","C. Number of developers committing code","D. Lines of code committed per day"],answer:1,explanation:"Build success rate and MTBF measure how stable and reliable the CI pipeline is over time."},
{id:763,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"easy",question:"Which of the following is a common unit testing framework for Java?",options:["A. Selenium","B. JMeter","C. JUnit","D. Jenkins"],answer:2,explanation:"JUnit is the standard unit testing framework for Java applications."},
{id:764,chapter:"Test Tools",topic:"Tool Categories",difficulty:"easy",question:"OWASP ZAP is an example of which type of testing tool?",options:["A. Performance testing tool","B. Security testing (DAST) tool","C. Unit testing framework","D. Test management tool"],answer:1,explanation:"OWASP ZAP is a dynamic application security testing tool for finding web vulnerabilities."},
{id:765,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"extreme",question:"A team automates 100% of their test cases, including exploratory-style scenarios. After 6 months, they find defects only through automation. This MOST likely indicates:",options:["A. Perfect automation quality","B. The team has stopped thinking creatively about testing â€” automation cannot replace human creativity","C. The software is defect-free","D. Automation has achieved complete coverage"],answer:1,explanation:"100% automation dependence eliminates the human curiosity and creativity that finds unknown defects."},
{id:766,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"hard",question:"What is 'visual regression testing'?",options:["A. Testing whether the UI looks correct by comparing screenshots with baseline images","B. Testing a user's vision capabilities","C. A type of exploratory testing","D. A regression testing approach using user feedback"],answer:0,explanation:"Visual regression testing compares UI screenshots against baselines to detect unintended visual changes."},
{id:767,chapter:"Test Tools",topic:"CI/CD",difficulty:"extreme",question:"A DevOps team uses 'synthetic monitoring' in production. This BEST represents:",options:["A. Testing with fake users","B. Automated production tests that continuously verify critical user journeys using scripted transactions","C. A type of static analysis","D. Production load testing"],answer:1,explanation:"Synthetic monitoring runs scripted tests continuously in production to proactively detect issues."},
{id:768,chapter:"Test Tools",topic:"Tool Categories",difficulty:"medium",question:"Which of the following is an example of a 'mobile emulator' used in testing?",options:["A. A physical mobile device","B. Android Emulator or iOS Simulator â€” software that mimics mobile device behavior","C. A cloud device farm","D. A browser developer tools mobile mode"],answer:1,explanation:"Android Emulator and iOS Simulator are software-based mobile device simulators for testing without real devices."},
{id:769,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"hard",question:"In a legacy system with no automated tests, the BEST first step toward automation is:",options:["A. Automate all existing manual tests at once","B. Start with a small set of high-value smoke tests and build incrementally","C. Buy the most comprehensive automation tool available","D. Replace the legacy system first"],answer:1,explanation:"Starting small with high-value smoke tests builds automation incrementally, managing risk and building team skills."},
{id:770,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"medium",question:"What does 'test parallelization' mean?",options:["A. Running tests in a specific order","B. Running multiple tests simultaneously across multiple threads or machines to reduce total execution time","C. Testing multiple features at the same time","D. Running the same test on multiple test data sets"],answer:1,explanation:"Test parallelization executes tests concurrently, reducing total execution time for large suites."},
{id:771,chapter:"Test Tools",topic:"CI/CD",difficulty:"hard",question:"In DevOps, 'observability' refers to:",options:["A. Watching developers code","B. The ability to understand a system's internal state from its external outputs (logs, metrics, traces)","C. A type of security testing","D. Monitoring test execution"],answer:1,explanation:"Observability (logging, metrics, tracing) enables teams to understand system behavior in production â€” supporting shift-right testing."},
{id:772,chapter:"Test Tools",topic:"Tool Categories",difficulty:"medium",question:"Which tool category helps testers create test data that meets complex business rules?",options:["A. Static analyzers","B. Test data generation and synthesis tools","C. Performance testing tools","D. Coverage analyzers"],answer:1,explanation:"Test data synthesis tools generate realistic, rule-compliant test data for complex business scenarios."},
{id:773,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"hard",question:"'Golden master testing' compares current system output with a previously approved (golden) output. The main risk is:",options:["A. It is too slow","B. If the golden master contains defects, they become the accepted standard","C. It requires too many tools","D. The golden master cannot be automated"],answer:1,explanation:"If the baseline (golden master) has defects, those defects become accepted â€” incorrect behavior is treated as correct."},
{id:774,chapter:"Test Tools",topic:"CI/CD",difficulty:"medium",question:"Automated rollback in a CD pipeline means:",options:["A. Developers manually revert changes","B. The system automatically reverts to the previous version if deployment health checks or tests fail","C. Tests are automatically removed from the pipeline","D. The pipeline deletes failed builds"],answer:1,explanation:"Automated rollback reverts to the last known good state if deployment tests or health checks fail."},
{id:775,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"hard",question:"When selecting a test automation tool for a mobile application, which factor is MOST critical?",options:["A. The tool's logo design","B. Support for the target platforms (iOS/Android), real device testing, and integration with CI/CD","C. The number of licenses available","D. The tool's release date"],answer:1,explanation:"Platform support, real device testing capability, and CI/CD integration are the critical selection criteria for mobile test tools."},
{id:776,chapter:"Test Tools",topic:"Tool Categories",difficulty:"hard",question:"What is 'chaos engineering' and how does it relate to test tools?",options:["A. Testing in a disorganized manner","B. Deliberately injecting failures into production systems to test resilience, supported by chaos tools","C. A type of security testing","D. Random test execution"],answer:1,explanation:"Chaos engineering uses tools to inject failures (network outages, service crashes) in production to test resilience."},
{id:777,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"medium",question:"The PRIMARY purpose of integrating automated tests with a CI/CD pipeline is:",options:["A. To slow down the deployment process","B. To provide continuous quality feedback, catching regressions immediately after code changes","C. To replace manual testing entirely","D. To increase the number of test cases"],answer:1,explanation:"Continuous automated testing in CI/CD catches regressions immediately, maintaining quality at high deployment velocity."},
{id:778,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"easy",question:"Which of the following is a common use for Cypress in web testing?",options:["A. Load testing","B. End-to-end web application testing","C. Static code analysis","D. Mobile testing"],answer:1,explanation:"Cypress is a popular JavaScript-based end-to-end testing framework for web applications."},
{id:779,chapter:"Test Tools",topic:"CI/CD",difficulty:"medium",question:"A 'nightly build' in CI means:",options:["A. Builds only happen at night","B. A full automated build-and-test cycle run overnight, providing a daily quality snapshot","C. Builds are never run during business hours","D. Deployments happen at night only"],answer:1,explanation:"Nightly builds run comprehensive tests overnight, providing daily quality feedback without slowing development."},
{id:780,chapter:"Test Tools",topic:"Tool Categories",difficulty:"hard",question:"A 'live site test' or 'production test' is a form of:",options:["A. Unit testing","B. Shift-right testing â€” testing in the production environment with real users","C. Integration testing","D. Static testing"],answer:1,explanation:"Production/live site tests are shift-right testing practices that verify system behavior in the real production environment."},
{id:781,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"easy",question:"Which of the following is NOT a benefit of using automated regression tests?",options:["A. Faster execution than manual testing","B. Consistent, repeatable execution","C. Ability to find all new types of defects","D. Available to run 24/7"],answer:2,explanation:"Automated tests only find defects in scenarios they test â€” they cannot discover new, unanticipated defect types."},
{id:782,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"medium",question:"What is the purpose of 'test result reporting' in test management tools?",options:["A. To hide test failures from management","B. To aggregate, visualize, and communicate test outcomes to stakeholders","C. To generate new test cases","D. To update the software under test"],answer:1,explanation:"Test result reporting aggregates pass/fail data, coverage metrics, and defect counts for stakeholder communication."},
{id:783,chapter:"Test Tools",topic:"CI/CD",difficulty:"extreme",question:"A company releases 50 times per day using a CI/CD pipeline. Manual regression testing is impossible at this speed. The BEST solution is:",options:["A. Reduce releases to once per day for manual testing","B. Implement comprehensive automated regression at unit, integration, and E2E levels with monitoring","C. Stop regression testing entirely","D. Only test in production after deployment"],answer:1,explanation:"At high deployment velocity, automated multi-level regression (unit, integration, E2E) plus monitoring is the only viable approach."},
{id:784,chapter:"Test Tools",topic:"Tool Categories",difficulty:"medium",question:"Test management tools typically support which of the following?",options:["A. Code compilation and building","B. Test case organization, execution tracking, coverage reporting, and defect linking","C. Production monitoring","D. Security scanning"],answer:1,explanation:"Test management tools support test organization, planning, execution tracking, coverage, and defect integration."},
{id:785,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"hard",question:"A test team discovers their automated tests pass on the test environment but fail on production. This MOST likely indicates:",options:["A. The automated tests are defective","B. Environment differences between test and production â€” configuration or data parity issues","C. The production system is faster","D. Automation only works in test environments"],answer:1,explanation:"Test-to-production failures often stem from environment differences â€” configuration, data, or network topology."},
{id:786,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"hard",question:"What is the difference between a 'stub' and a 'fake' in test automation?",options:["A. They are identical concepts","B. A stub provides hard-coded responses; a fake is a simplified but working implementation of the real thing","C. Fakes are always automated; stubs are manual","D. Stubs are for databases; fakes are for APIs"],answer:1,explanation:"Stubs return hard-coded responses; fakes are simplified working implementations (e.g., in-memory database vs. real DB)."},
{id:787,chapter:"Test Tools",topic:"CI/CD",difficulty:"hard",question:"What is 'environment drift' in testing?",options:["A. Test environments moving to a different physical location","B. Gradual divergence of test environments from their intended configuration over time","C. Differences between development and test environments","D. The process of updating test environments"],answer:1,explanation:"Environment drift occurs when environments change gradually and unofficially, causing inconsistent test results."},
{id:788,chapter:"Test Tools",topic:"Tool Categories",difficulty:"hard",question:"A 'test impact analysis' tool determines:",options:["A. The business impact of software defects","B. Which tests are affected by specific code changes, enabling targeted test execution","C. The financial return on testing investment","D. The performance impact of running tests"],answer:1,explanation:"Test impact analysis tools identify which tests are relevant to changed code, reducing unnecessary test execution."},
{id:789,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"extreme",question:"A team reports that their test automation covers 95% of requirements but they still have many production issues. The ROOT CAUSE is MOST likely:",options:["A. 5% untested requirements causing all issues","B. Tests may be present but assertions are weak â€” passing tests don't verify correct behavior","C. The automation tool is unreliable","D. Manual testing should replace automation"],answer:1,explanation:"Weak assertions (tests that run but don't adequately verify outcomes) create false confidence despite high coverage."},
{id:790,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"medium",question:"Which of the following BEST describes 'exploratory testing tools'?",options:["A. Tools that replace exploratory testing with automation","B. Tools that support exploratory testing (session recording, bug reporting, screen capture) without scripting tests","C. Static analysis tools","D. Performance monitoring tools"],answer:1,explanation:"Exploratory testing tools support (not replace) testers: session recording, instant defect capture, and note-taking."},
{id:791,chapter:"Test Tools",topic:"CI/CD",difficulty:"medium",question:"A 'deployment pipeline' in CD is BEST described as:",options:["A. The water pipes in a data center","B. An automated sequence of stages (build, test, deploy) through which code changes flow to production","C. A manual process for code deployment","D. A document describing the deployment process"],answer:1,explanation:"A deployment pipeline automates the stages code changes go through â€” from commit to production delivery."},
{id:792,chapter:"Test Tools",topic:"Tool Categories",difficulty:"hard",question:"'Negative testing' tools help verify:",options:["A. That the system rejects positive inputs","B. That the system handles invalid, unexpected, or malicious inputs without crashing or misbehaving","C. That tests pass rather than fail","D. Performance under negative conditions"],answer:1,explanation:"Negative testing verifies graceful handling of invalid inputs, out-of-range values, and malicious data."},
{id:793,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"hard",question:"What is the 'Total Cost of Ownership' (TCO) consideration for test automation tools?",options:["A. Only the initial license cost","B. License cost, training, implementation, maintenance, infrastructure, and upgrade costs over the tool's lifetime","C. Only the maintenance cost","D. Only the infrastructure cost"],answer:1,explanation:"TCO includes all costs over the tool's lifetime: licenses, training, setup, maintenance, infrastructure, and upgrades."},
{id:794,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"hard",question:"What is 'continuous testing' in the context of DevOps?",options:["A. Testing that never stops","B. Automated testing embedded at every stage of the delivery pipeline to provide continuous quality feedback","C. Testing performed by the operations team","D. 24/7 manual testing shifts"],answer:1,explanation:"Continuous testing provides automated quality feedback at every pipeline stage, enabling fast, confident delivery."},
{id:795,chapter:"Test Tools",topic:"CI/CD",difficulty:"hard",question:"When does 'shift-right' testing in CD provide value that 'shift-left' cannot?",options:["A. Finding requirements defects","B. Detecting issues that only appear under real production conditions (load, data patterns, user behavior)","C. Finding unit-level defects","D. Replacing integration testing"],answer:1,explanation:"Production-only issues (emergent behavior, real data patterns, actual user load) require shift-right testing approaches."},
{id:796,chapter:"Test Tools",topic:"Tool Categories",difficulty:"easy",question:"Which of the following is an example of a 'performance monitoring tool' used in production?",options:["A. JUnit","B. New Relic or Datadog","C. Selenium","D. TestRail"],answer:1,explanation:"New Relic and Datadog are Application Performance Monitoring (APM) tools used in production environments."},
{id:797,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"medium",question:"When is test automation MOST cost-effective?",options:["A. For one-time, short-term projects","B. For stable features that are tested repeatedly in regression cycles","C. For exploratory testing scenarios","D. For acceptance testing run once before release"],answer:1,explanation:"Automation ROI grows with repetition â€” stable features tested many times in regression justify automation investment."},
{id:798,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"extreme",question:"A team is implementing 'self-healing test automation' where AI adjusts test locators when UI changes. The MAIN benefit is:",options:["A. Tests find more defects automatically","B. Reduced maintenance effort when UI changes occur â€” tests automatically adapt to locator changes","C. 100% code coverage","D. Elimination of manual testing"],answer:1,explanation:"Self-healing automation reduces maintenance burden by automatically adapting to minor UI changes."},
{id:799,chapter:"Test Tools",topic:"CI/CD",difficulty:"medium",question:"In a CI/CD pipeline, 'artifact management' refers to:",options:["A. Managing historical test artifacts like test cases","B. Storing, versioning, and distributing build artifacts (JARs, Docker images, packages)","C. Managing configuration files","D. Archiving old CI pipelines"],answer:1,explanation:"Artifact management systems (like Nexus, Artifactory) store and distribute build outputs across pipeline stages."},
{id:800,chapter:"Test Tools",topic:"Tool Categories",difficulty:"medium",question:"Which tool would a test team use to verify that a system's API responses match a defined OpenAPI/Swagger specification?",options:["A. JUnit","B. API contract testing tool or Postman with schema validation","C. SonarQube","D. JMeter"],answer:1,explanation:"API contract tools and Postman with schema validation verify API responses match defined specifications."},
{id:801,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"extreme",question:"An organization runs automated tests in production via synthetic monitoring and A/B testing. A concern with this approach is:",options:["A. Tests run too slowly","B. Production test data may contain real user data requiring privacy controls","C. Automation tools don't work in production","D. A/B testing is not a testing technique"],answer:1,explanation:"Production testing requires careful data handling â€” real user data in test scenarios raises privacy/compliance concerns."},
{id:802,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"medium",question:"Robot Framework is an example of which type of test tool?",options:["A. Performance testing tool","B. Keyword-driven, data-driven test automation framework","C. Static analysis tool","D. Defect management tool"],answer:1,explanation:"Robot Framework is a keyword-driven, data-driven test automation framework supporting acceptance and ATDD."},
{id:803,chapter:"Test Tools",topic:"CI/CD",difficulty:"extreme",question:"A team wants to test database schema migration scripts as part of their CI pipeline. Which approach is MOST appropriate?",options:["A. Skip database testing in CI â€” too complex","B. Run migration scripts against a test database in CI with automated schema validation tests","C. Only test migrations in production","D. Manually test migrations before each release"],answer:1,explanation:"Automated database migration testing in CI prevents broken schema changes from reaching production."},
{id:804,chapter:"Test Tools",topic:"Tool Categories",difficulty:"hard",question:"Which of the following is a BENEFIT of using test data management tools in a large enterprise?",options:["A. Tests run faster","B. Centralized, consistent test data reduces duplication, ensures compliance, and improves collaboration","C. Automation is not needed","D. Defects are automatically fixed"],answer:1,explanation:"Centralized TDM tools reduce data duplication, ensure consistency, support compliance, and improve team efficiency."},
{id:805,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"hard",question:"'Technical debt' in test automation refers to:",options:["A. The cost of test automation tools","B. Accumulated poor automation practices (copy-paste, no framework, brittle locators) that slow future work","C. The financial return on automation investment","D. The time debt owed to testers for overtime"],answer:1,explanation:"Technical debt in automation is the accumulation of shortcuts and poor practices that increase future maintenance costs."},
{id:806,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"medium",question:"What is the purpose of a 'test execution dashboard'?",options:["A. To display developer performance metrics","B. To provide real-time visibility into test execution status, coverage, and defect trends","C. To automate test case generation","D. To monitor production system health"],answer:1,explanation:"Execution dashboards provide real-time visibility into testing status, helping managers and stakeholders track progress."},
{id:807,chapter:"Test Tools",topic:"CI/CD",difficulty:"medium",question:"What is 'environment promotion' in CI/CD?",options:["A. Promoting the test environment manager","B. Moving a tested, verified artifact from one environment to the next (dev -> test -> staging -> production)","C. Improving test environment performance","D. Updating the CI server software"],answer:1,explanation:"Environment promotion moves verified builds through pipeline stages toward production deployment."},
{id:808,chapter:"Test Tools",topic:"Tool Categories",difficulty:"extreme",question:"A team implements 'observability-driven testing' where production logs and traces guide testing focus areas. This BEST represents:",options:["A. An inefficient testing approach","B. Using production intelligence (logs, traces, errors) to inform and improve test coverage and focus","C. A replacement for automated testing","D. A form of manual testing"],answer:1,explanation:"Using production observability data to guide test improvement is a powerful feedback loop in modern testing."},
{id:809,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"hard",question:"A team discovers that their CI pipeline passes but the application fails in staging. The MOST likely cause is:",options:["A. The CI pipeline has too many tests","B. The CI environment doesn't match staging â€” configuration, data, or external service differences","C. The staging environment is broken","D. CI tests are too simple"],answer:1,explanation:"CI-to-staging failures indicate environment parity issues â€” CI doesn't accurately represent the staging/production configuration."},
{id:810,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"hard",question:"Which of the following BEST describes 'parameterized testing' in automation frameworks?",options:["A. Testing with system parameters","B. Running the same test logic with multiple sets of input data, avoiding test duplication","C. Testing performance parameters","D. Using parameters to configure test tools"],answer:1,explanation:"Parameterized tests run the same test case with multiple data sets, enabling data-driven testing without code duplication."},
{id:811,chapter:"Test Tools",topic:"CI/CD",difficulty:"hard",question:"A team uses 'DORA metrics' to measure DevOps performance. The four DORA metrics are:",options:["A. Defect rate, occurrence, regression, analysis","B. Deployment frequency, lead time for changes, change failure rate, time to restore service","C. Development, operations, release, acceptance","D. Delivery, observability, reliability, availability"],answer:1,explanation:"DORA metrics measure DevOps delivery performance: deployment frequency, lead time, failure rate, and recovery time."},
{id:812,chapter:"Test Tools",topic:"Tool Categories",difficulty:"medium",question:"'Contract testing' between microservices helps ensure:",options:["A. Legal contracts are met","B. Service interfaces remain compatible as each service evolves independently","C. Services are performant","D. Security contracts are enforced"],answer:1,explanation:"Contract testing ensures that independently deployed microservices maintain compatible interfaces."},
{id:813,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"medium",question:"The PRIMARY risk of implementing test automation too quickly is:",options:["A. Tests will be completed ahead of schedule","B. Automation may be built on an unstable foundation, requiring significant rework","C. The automation tool will be replaced","D. Too many defects will be found"],answer:1,explanation:"Rushing automation without proper architecture and strategy often leads to unmaintainable automation that requires rework."},
{id:814,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"medium",question:"What is 'record and replay' test automation and what is its main limitation?",options:["A. Recording developer meetings and replaying them; very effective","B. Recording user actions and replaying them as tests; brittle to UI changes","C. Recording API calls and replaying them; not suitable for UI","D. Recording test results and replaying test sessions"],answer:1,explanation:"Record-replay captures UI interactions but creates brittle tests that break with minor UI changes."},
{id:815,chapter:"Test Tools",topic:"CI/CD",difficulty:"medium",question:"'Infrastructure as Code' (IaC) combined with test automation enables:",options:["A. Writing application code in testing language","B. Automated, reproducible environment setup as part of the CI/CD pipeline","C. Testing infrastructure without code","D. Reducing the amount of code needed for testing"],answer:1,explanation:"IaC enables automated, version-controlled, reproducible environment provisioning integrated with CI/CD pipelines."},
{id:816,chapter:"Test Tools",topic:"Tool Categories",difficulty:"hard",question:"Which of the following is an example of 'specification-based' test automation?",options:["A. Selenium WebDriver tests","B. Formal specification tools that generate tests from mathematical models","C. JMeter performance scripts","D. Code coverage analysis"],answer:1,explanation:"Specification-based tools generate tests from formal specifications or models, providing mathematical rigor."},
{id:817,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"hard",question:"An automated test suite has 90% of tests written for the UI layer. What is the MAIN concern?",options:["A. Too high UI coverage","B. High maintenance cost and slow execution â€” UI tests are the most expensive and brittle","C. Insufficient UI testing","D. The automation tool is wrong"],answer:1,explanation:"An inverted automation pyramid (most tests at UI) is expensive to maintain and slow â€” the opposite of best practice."},
{id:818,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"medium",question:"What is the purpose of a 'test doubles library' like Mockito (Java) or unittest.mock (Python)?",options:["A. To double the number of test cases","B. To provide frameworks for creating mocks, stubs, and spies easily in unit tests","C. To run tests twice for reliability","D. To duplicate test environments"],answer:1,explanation:"Mockito and unittest.mock provide easy-to-use frameworks for creating test doubles (mocks, stubs, spies) in unit tests."},
{id:819,chapter:"Test Tools",topic:"CI/CD",difficulty:"medium",question:"In a CI pipeline, a build is said to be 'green' when:",options:["A. The code uses environmentally friendly practices","B. All automated tests pass and quality gates are satisfied","C. The build completes in under 2 minutes","D. All code has been reviewed"],answer:1,explanation:"A 'green' build means all tests pass and quality gates are met â€” the code is healthy and can progress."},
{id:820,chapter:"Test Tools",topic:"Tool Categories",difficulty:"hard",question:"'Specification by Example' tooling (e.g., Cucumber, SpecFlow) bridges which gap?",options:["A. The gap between development and operations","B. The gap between business requirements (in natural language) and automated acceptance tests","C. The gap between unit and system testing","D. The gap between developers and testers"],answer:1,explanation:"BDD/SbE tools turn natural language acceptance criteria into executable automated tests, bridging business and technical teams."},
{id:821,chapter:"Fundamentals of Testing",topic:"Why Testing is Necessary",difficulty:"medium",question:"QA vs QC: QA focuses on processes; QC focuses on finding defects in products.",options:["A. True — QA prevents; QC finds","B. False — they are the same","C. True but they overlap completely","D. False — QA finds defects; QC prevents them"],answer:0,explanation:"QA improves processes to prevent defects; QC (testing) examines products to find defects."},
{id:822,chapter:"Testing Throughout the SDLC",topic:"Test Levels",difficulty:"hard",question:"End-to-end testing validates complete workflows — it is MOST closely aligned with which test level?",options:["A. Unit testing","B. Component testing","C. System testing","D. Unit integration"],answer:2,explanation:"End-to-end testing validates complete system workflows — a system testing activity."},
{id:823,chapter:"Static Testing",topic:"Review Types",difficulty:"medium",question:"A round-robin informal review is BEST described as:",options:["A. A formal inspection","B. Team members reviewing each other's work in rotation","C. A walkthrough led by the author","D. An automated code review"],answer:1,explanation:"Round-robin reviews are informal peer reviews where team members review each other's work in turn."},
{id:824,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"hard",question:"In a state transition diagram, which factor MOST directly impacts test completeness?",options:["A. The number of states","B. Coverage criterion chosen (all-states vs. all-transitions)","C. Speed of transitions","D. The initial state only"],answer:1,explanation:"The chosen coverage criterion (all-states vs. all-transitions) determines how complete the testing is."},
{id:825,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"medium",question:"Three-Point Estimation for test effort uses:",options:["A. Three separate estimates by three testers","B. Optimistic, most likely, and pessimistic estimates in a weighted formula","C. Three rounds of planning poker","D. Three different estimation techniques"],answer:1,explanation:"Three-point estimation: (Optimistic + 4 x Most Likely + Pessimistic) / 6 for a weighted average."},
{id:826,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"easy",question:"A defect tracking tool integrated with test management provides:",options:["A. Automatic defect fixing","B. Traceability between test failures and reported defects","C. Automatic test generation from defects","D. Auto-closure of defects after retesting"],answer:1,explanation:"Integration provides traceability — linking failed tests to the defects they discovered."},
{id:827,chapter:"Fundamentals of Testing",topic:"Testing Principles",difficulty:"medium",question:"Which principle explains why a team can never be certain all defects are found?",options:["A. Exhaustive testing is impossible","B. Testing shows presence of defects, not their absence","C. Defects cluster together","D. Early testing saves time"],answer:1,explanation:"Testing can confirm defects exist but cannot prove none remain — certainty of zero defects is impossible."},
{id:828,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"medium",question:"Testing an application with new third-party library versions is BEST described as:",options:["A. Regression testing","B. Compatibility testing","C. Integration testing","D. System testing"],answer:1,explanation:"Compatibility testing verifies the system works with different versions of its dependencies."},
{id:829,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"medium",question:"Defect density of a reviewed work product measures:",options:["A. Defect severity distribution","B. Number of defects per unit size found during review","C. Time to find each defect","D. Cost of fixing defects"],answer:1,explanation:"Defect density = defects per unit (page, KLOC) — measures concentration of defects in a work product."},
{id:830,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"medium",question:"A developer achieves 100% statement coverage. Can logic be claimed as fully tested?",options:["A. Yes - 100% statement coverage means all logic is tested","B. No - branches and conditions may not all be exercised","C. Yes - statement is the strongest coverage criterion","D. Only if path coverage is also achieved"],answer:1,explanation:"Statement coverage alone does not test all decision outcomes — branches and conditions may be missed."},
{id:831,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"hard",question:"A risk heat map in sprint planning MAINLY helps to:",options:["A. Visualize code complexity","B. Identify and visually prioritize high-risk areas for testing focus","C. Monitor team productivity","D. Track defect trends"],answer:1,explanation:"Risk heat maps visualize risk by area, helping allocate testing effort to highest-risk features."},
{id:832,chapter:"Test Tools",topic:"CI/CD",difficulty:"hard",question:"Flaky tests in a CI pipeline are problematic because:",options:["A. They always fail and indicate real defects","B. They intermittently pass or fail without code changes, eroding pipeline trust","C. They are too slow for CI","D. They always pass and hide defects"],answer:1,explanation:"Flaky tests undermine CI reliability — teams ignore failures, which may mask real defects."},
{id:833,chapter:"Fundamentals of Testing",topic:"Test Activities",difficulty:"medium",question:"Test completion criteria (exit criteria) define:",options:["A. Conditions for starting a new test phase","B. Conditions that must be met before declaring a test phase complete","C. Pass/fail criteria for individual tests","D. Requirements for test environment"],answer:1,explanation:"Exit criteria specify what conditions must be met before a test phase is declared complete."},
{id:834,chapter:"Testing Throughout the SDLC",topic:"Test Levels",difficulty:"medium",question:"A simulator vs. emulator in testing: the key difference is:",options:["A. They are identical","B. Simulators mimic behavior; emulators replicate internal hardware/software implementation","C. Simulators are faster","D. Emulators are only for mobile"],answer:1,explanation:"Simulators mimic external behavior; emulators replicate the internal implementation."},
{id:835,chapter:"Static Testing",topic:"Feedback and Review Process",difficulty:"hard",question:"The MAIN benefit of an independent reviewer is:",options:["A. They are always more experienced","B. Different perspective reduces familiarity bias and finds defects the author misses","C. It is faster than self-review","D. It reduces review meeting time"],answer:1,explanation:"Independent reviewers challenge assumptions and spot errors the author's familiarity blindness causes them to miss."},
{id:836,chapter:"Test Analysis and Design",topic:"Test Conditions",difficulty:"medium",question:"Test conditions for an e-commerce checkout should include:",options:["A. Only positive flow conditions","B. Both positive (successful purchase) and negative (payment failure, expired card) conditions","C. Only negative conditions","D. Performance conditions only"],answer:1,explanation:"Complete test conditions include both positive (happy path) and negative (error cases) scenarios."},
{id:837,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"medium",question:"Testers should report minor defects because:",options:["A. To increase defect count metrics","B. Minor defects may indicate larger issues; stakeholders should decide priority","C. All defects must be fixed","D. To justify testing effort"],answer:1,explanation:"Minor defects may be symptoms of deeper issues; priority decisions belong to stakeholders, not testers."},
{id:838,chapter:"Test Tools",topic:"Tool Categories",difficulty:"medium",question:"Spinnaker and ArgoCD are examples of:",options:["A. Test case design tools","B. Continuous delivery and deployment orchestration tools","C. Static analysis tools","D. Performance testing tools"],answer:1,explanation:"Spinnaker and ArgoCD automate deployment pipeline orchestration for continuous delivery."},
{id:839,chapter:"Fundamentals of Testing",topic:"Testing Objectives",difficulty:"hard",question:"Fitness for purpose testing verifies:",options:["A. Technical correctness of code","B. The software fulfills its intended purpose from the user's perspective","C. Performance benchmarks","D. All requirements are implemented"],answer:1,explanation:"Fitness for purpose confirms the software achieves its goal in the user's real context."},
{id:840,chapter:"Testing Throughout the SDLC",topic:"Testing in SDLC",difficulty:"hard",question:"In SAFe, testing at the Program Increment level MOST closely corresponds to:",options:["A. Unit testing","B. System integration testing across Agile Release Train teams","C. Acceptance testing only","D. Component testing"],answer:1,explanation:"PI-level testing in SAFe verifies integration across multiple ART teams."},
{id:841,chapter:"Static Testing",topic:"Review Types",difficulty:"hard",question:"Requirements inspections benefit MOST from:",options:["A. Walkthroughs only","B. Checklists of common requirements defects (ambiguity, incompleteness)","C. Code-focused reviews","D. Performance-focused reviews"],answer:1,explanation:"Requirements inspection checklists targeting common defect types ensure systematic review coverage."},
{id:842,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"extreme",question:"An API with 3 optional boolean fields has how many valid input combinations?",options:["A. 3","B. 6","C. 8","D. 9"],answer:2,explanation:"3 optional binary fields: 2^3 = 8 combinations (none, one of each, two combinations, all three)."},
{id:843,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"extreme",question:"Defect discovery rate increasing in the final week before release while fix rate is constant — the MOST appropriate action is:",options:["A. Accept and release on schedule","B. Escalate to stakeholders - late rising defect rates are a significant quality risk","C. Increase testing pace","D. Reduce number of tests to finish faster"],answer:1,explanation:"Late-rising defect rates signal quality risk — stakeholders need this for informed release decisions."},
{id:844,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"hard",question:"80% test automation coverage MOST accurately represents:",options:["A. 80% of defects will be found","B. 80% of defined test scenarios can be executed automatically","C. Software is 80% bug-free","D. 80% of requirements verified by automation"],answer:1,explanation:"Automation coverage measures the proportion of the test suite that is automated — not defect detection capability."},
{id:845,chapter:"Fundamentals of Testing",topic:"Test Activities",difficulty:"hard",question:"A test procedure (script) is characterized by:",options:["A. Abstract high-level guidance","B. Step-by-step execution instructions with expected results at each step","C. Only use in exploratory testing","D. Expected results only, no steps"],answer:1,explanation:"A test procedure provides complete step-by-step instructions including expected results at each step."},
{id:846,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"hard",question:"Compliance testing differs from functional testing in that:",options:["A. Compliance only tests legal requirements","B. Compliance verifies against external standards; functional testing verifies specifications","C. Functional testing is more rigorous","D. They test the same things differently"],answer:1,explanation:"Compliance testing verifies against external standards (GDPR, PCI-DSS); functional testing verifies feature specs."},
{id:847,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"hard",question:"Why is reviewing the test plan an important static testing activity?",options:["A. To check grammatical errors","B. To find gaps, ambiguities, or risks before testing begins when changes are cheapest","C. To count planned test cases","D. To approve budget"],answer:1,explanation:"Test plan reviews find planning gaps and risks before testing starts — the cheapest time to make corrections."},
{id:848,chapter:"Test Analysis and Design",topic:"Experience-based Techniques",difficulty:"hard",question:"Using the OWASP Top 10 to guide security testing is BEST described as:",options:["A. Formal inspection","B. Checklist-based testing using a security vulnerability taxonomy","C. Static analysis","D. Unplanned exploratory testing"],answer:1,explanation:"Testing against OWASP Top 10 is structured checklist-based testing with a security focus."},
{id:849,chapter:"Managing the Test Activities",topic:"Configuration Management",difficulty:"hard",question:"Test environment configuration management MAINLY involves:",options:["A. Managing physical workstation layouts","B. Tracking, controlling, and documenting environment configuration for reproducibility","C. Scheduling environment time slots","D. Monitoring test execution performance"],answer:1,explanation:"Environment CM tracks state enabling consistent, reproducible testing and defect investigation."},
{id:850,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"hard",question:"Contract-first API development means:",options:["A. Legal agreements before development","B. Defining the API specification before implementation, enabling parallel development and testing","C. Testing APIs based on past contracts","D. A waterfall approach to API design"],answer:1,explanation:"Contract-first defines the API spec upfront, enabling consumer and provider to develop and test in parallel."},
{id:851,chapter:"Fundamentals of Testing",topic:"Testing Principles",difficulty:"hard",question:"Defects cluster together should lead a test team to:",options:["A. Allocate equal effort across all modules","B. Focus more testing on modules with known defect history and high complexity","C. Test only the modules with most code","D. Reduce testing of previously defective modules"],answer:1,explanation:"Defect clustering means historically prone and complex modules deserve more testing attention."},
{id:852,chapter:"Testing Throughout the SDLC",topic:"Test Levels",difficulty:"extreme",question:"mTLS authentication between microservices is MOST effectively tested at:",options:["A. Unit testing","B. Component integration testing","C. System testing","D. User acceptance testing"],answer:1,explanation:"mTLS between services is an integration concern — component integration testing is most relevant."},
{id:853,chapter:"Static Testing",topic:"Feedback and Review Process",difficulty:"medium",question:"SUCCESS factors for reviews according to ISTQB include:",options:["A. All reviews must be formal inspections","B. Management support and adequate time allocation","C. Only senior testers should participate","D. Reviews completed in one session regardless of size"],answer:1,explanation:"Management support and adequate time are key ISTQB-defined success factors for effective reviews."},
{id:854,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"extreme",question:"For 1-switch (all transition pairs) coverage with 6 valid transitions, how many test sequences are needed?",options:["A. 4","B. 6","C. Up to 36","D. All valid consecutive pairs"],answer:3,explanation:"1-switch coverage tests all consecutive transition pairs — for 6 transitions, all valid consecutive pairs must be covered."},
{id:855,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"extreme",question:"In a Kanban project, test planning should be:",options:["A. Full plan before any card starts","B. Continuous — adapting the approach for each card as it enters the test column","C. Quarterly upfront planning","D. Avoided since Kanban is informal"],answer:1,explanation:"Kanban test planning is continuous and per-item — the approach adapts as each item flows through testing."},
{id:856,chapter:"Test Tools",topic:"CI/CD",difficulty:"extreme",question:"Test impact analysis reducing CI from 2h to 15min carries what MAIN risk?",options:["A. Tests run too fast","B. Missing regressions in areas not identified as affected by changes","C. Pipeline becomes too complex","D. Developers push too much code"],answer:1,explanation:"Impact analysis may miss regressions in areas with non-obvious dependencies — coverage gaps are the key risk."},
{id:857,chapter:"Fundamentals of Testing",topic:"Essential Skills",difficulty:"extreme",question:"A tester finds a production defect and reports it without telling their manager first. Was this appropriate?",options:["A. No - managers must always be informed first","B. Yes, if following the organization's defect reporting process — timely reporting is essential","C. No - production defects are only for operations team","D. Yes - testers should always bypass management"],answer:1,explanation:"Timely reporting per the process is appropriate — critical production defects should not be delayed."},
{id:858,chapter:"Testing Throughout the SDLC",topic:"Maintenance Testing",difficulty:"hard",question:"Which release triggers all three maintenance types (corrective, adaptive, perfective)?",options:["A. A single production defect report","B. A release containing a bug fix, OS upgrade adaptation, AND performance optimization","C. A user manual update","D. A developer training session"],answer:1,explanation:"A combined release with fix (corrective) + OS adaptation (adaptive) + performance improvement (perfective) triggers all three."},
{id:859,chapter:"Static Testing",topic:"Review Types",difficulty:"extreme",question:"Formal inspection metrics MOST useful for improving development processes are:",options:["A. Reviewer attendance rate","B. Defect density per work product type and defect injection phase","C. Meeting duration","D. Number of reviewers per inspection"],answer:1,explanation:"Defect density by artifact type and injection phase reveals which processes introduce most defects."},
{id:860,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"extreme",question:"MC/DC was developed specifically for:",options:["A. Web application testing","B. Safety-critical software where independent condition effects must be demonstrated","C. All unit testing","D. Performance testing of complex algorithms"],answer:1,explanation:"MC/DC was created for safety-critical avionics (DO-178C Level A) requiring demonstration of independent condition effects."},
{id:861,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"hard",question:"The MOST effective way to prevent recurring defects is:",options:["A. Find more defects per cycle","B. Root cause analysis followed by process improvements","C. Add more testers","D. Automate all testing"],answer:1,explanation:"Root cause analysis identifies why defects were introduced, enabling process changes to prevent recurrence."},
{id:862,chapter:"Test Tools",topic:"Tool Categories",difficulty:"extreme",question:"Chaos monkey with monitoring represents:",options:["A. Acceptance testing","B. Shift-right resilience testing using chaos engineering principles","C. Unit testing","D. Static testing"],answer:1,explanation:"Chaos engineering with monitoring is a shift-right practice testing system resilience under real conditions."},
{id:863,chapter:"Fundamentals of Testing",topic:"Test Roles",difficulty:"hard",question:"An independent tester provides value because:",options:["A. They cost less than developers","B. They bring different perspectives and may find defects developers miss due to familiarity","C. They write better test cases","D. They access production systems directly"],answer:1,explanation:"Independent testers bring fresh perspectives and challenge assumptions — overcoming developer familiarity bias."},
{id:864,chapter:"Testing Throughout the SDLC",topic:"Testing in SDLC",difficulty:"hard",question:"Organizational test strategy should be updated when:",options:["A. Every sprint completes","B. Major changes occur: new technology, new SDLC, regulatory changes","C. A test manager joins","D. Each new project starts"],answer:1,explanation:"Organizational test strategies update when major changes occur — new tech, methodology, or regulations."},
{id:865,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"medium",question:"A limitation of static analysis tools is:",options:["A. They cannot integrate with CI/CD","B. They cannot determine if business logic is correct — only structural issues","C. They require software to be deployed","D. They only work for Java"],answer:1,explanation:"Static analysis finds structural/security issues but cannot verify business logic correctness."},
{id:866,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"hard",question:"Decision table for customer tier (Bronze/Silver/Gold) x purchase amount (under/over 100) has how many rules?",options:["A. 3","B. 4","C. 6","D. 9"],answer:2,explanation:"3 tiers x 2 purchase amounts = 6 rules."},
{id:867,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"hard",question:"Escaped defect rate measures:",options:["A. Defects found during testing","B. Defects found in production that were not caught during testing","C. Defects closed per day","D. Defects deferred to next release"],answer:1,explanation:"Escaped defect rate = defects that passed through testing into production — a key effectiveness metric."},
{id:868,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"medium",question:"Test tagging in automation frameworks enables:",options:["A. Adding metadata to defect reports","B. Marking tests with labels to enable selective execution","C. Tagging test environments","D. Labeling test cases in management tools"],answer:1,explanation:"Tags like @smoke, @regression enable selective test execution — run only the tests you need."},
{id:869,chapter:"Fundamentals of Testing",topic:"Why Testing is Necessary",difficulty:"extreme",question:"Software quality models (ISO 25010) define characteristics testing verifies. Which is NOT typically tested?",options:["A. Functional suitability","B. Performance efficiency","C. Developer coding style","D. Security"],answer:2,explanation:"Coding style is a static analysis/review concern — testing focuses on functional and non-functional quality characteristics."},
{id:870,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"extreme",question:"A performance issue found in production but not in testing. ROOT CAUSE is MOST likely:",options:["A. Test environment had production-equivalent load","B. Test environment did not simulate realistic production load or data volumes","C. Developers did not fix the issue","D. The testing tool was wrong"],answer:1,explanation:"Non-representative test environments miss production-scale performance issues."},
{id:871,chapter:"Static Testing",topic:"Review Types",difficulty:"hard",question:"Minimum people needed for an informal review:",options:["A. 1 (self-review is possible)","B. 2 (author + one reviewer)","C. 3 (author + moderator + scribe)","D. 5 (full review team)"],answer:0,explanation:"An informal review can even be a self-review, though external reviewers add more value."},
{id:872,chapter:"Test Analysis and Design",topic:"Collaboration Approaches",difficulty:"hard",question:"Acceptance criteria written before development in Agile serve as:",options:["A. Performance benchmarks","B. A contract between team and product owner defining what done means for a story","C. Automation test scripts","D. Database design requirements"],answer:1,explanation:"Pre-written acceptance criteria define story completion — they are the agreed definition of done."},
{id:873,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"hard",question:"The MAIN purpose of a test closure report is:",options:["A. To close all open defects","B. To document what was tested, results, deviations, and lessons learned","C. To terminate underperforming testers","D. To archive test data"],answer:1,explanation:"Test closure reports summarize the testing effort, results, and lessons learned for future reference."},
{id:874,chapter:"Test Tools",topic:"CI/CD",difficulty:"hard",question:"A CI pipeline failing 15% of the time without code changes indicates:",options:["A. Poor development team","B. Infrastructure or environmental flakiness needing remediation","C. Tests are too comprehensive","D. Declining code quality"],answer:1,explanation:"Build failures without code changes indicate CI infrastructure or environment instability."},
{id:875,chapter:"Fundamentals of Testing",topic:"Test Activities",difficulty:"medium",question:"CORRECT order of ISTQB test activities is:",options:["A. Design -> Plan -> Analyze -> Implement -> Execute -> Complete","B. Plan -> Analyze -> Design -> Implement -> Execute -> Complete","C. Execute -> Plan -> Design -> Analyze -> Complete -> Implement","D. Plan -> Design -> Analyze -> Execute -> Implement -> Complete"],answer:1,explanation:"ISTQB test process order: Planning -> Analysis -> Design -> Implementation -> Execution -> Completion."},
{id:876,chapter:"Testing Throughout the SDLC",topic:"Test Levels",difficulty:"medium",question:"System-level smoke testing typically involves:",options:["A. Full testing of all system features","B. Quick sanity check of critical functions before full testing begins","C. Performance testing critical features","D. Security testing most exposed features"],answer:1,explanation:"Smoke testing quickly validates critical functionality works before committing to full regression."},
{id:877,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"easy",question:"A common defect found by reviewing requirements is:",options:["A. Memory leaks","B. Infinite loops","C. Ambiguous specifications","D. Performance bottlenecks"],answer:2,explanation:"Requirements reviews most commonly find ambiguities, contradictions, and missing specifications."},
{id:878,chapter:"Test Analysis and Design",topic:"Test Conditions",difficulty:"medium",question:"Test condition 'Verify system handles concurrent user logins' is MOST likely testing:",options:["A. Functional correctness","B. Non-functional behavior (concurrency/performance)","C. Static behavior","D. Acceptance criteria"],answer:1,explanation:"Concurrent login handling is a non-functional (performance/concurrency) testing concern."},
{id:879,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"hard",question:"A defect should be reported as a known issue rather than fixed before release when:",options:["A. Never - all defects must be fixed","B. Risk is formally accepted by stakeholders and a workaround exists","C. The tester considers it unimportant","D. The developer says it is not worth fixing"],answer:1,explanation:"Known issues are formally risk-accepted defects where stakeholders determine release is acceptable."},
{id:880,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"hard",question:"Visual testing tools like Percy or Applitools provide:",options:["A. Testing for color blindness","B. Automated visual regression — detecting visual changes by comparing screenshots","C. UI design principle validation","D. Manual visual inspection support"],answer:1,explanation:"Visual regression tools detect unintended UI changes by comparing screenshots against baselines."},
{id:881,chapter:"Fundamentals of Testing",topic:"Testing Objectives",difficulty:"hard",question:"Testing a new API before integration MOST represents testing for:",options:["A. Validation","B. Defect detection and component verification","C. Compliance","D. Acceptance"],answer:1,explanation:"Pre-integration API testing aims to find defects and verify the component meets its specification."},
{id:882,chapter:"Testing Throughout the SDLC",topic:"Testing in SDLC",difficulty:"hard",question:"XP test-first refers to:",options:["A. Writing acceptance tests before user stories","B. Writing unit tests before production code (TDD)","C. Customers writing tests first","D. Running tests before starting development"],answer:1,explanation:"XP test-first is TDD — write a failing test, then write minimum code to pass it."},
{id:883,chapter:"Static Testing",topic:"Feedback and Review Process",difficulty:"hard",question:"An effective review process indicator is:",options:["A. Zero defects found (clean reviews)","B. High defect detection efficiency per review hour","C. All reviews in one meeting","D. No author input needed"],answer:1,explanation:"Effective reviews find many defects per unit of review time — high DDE is the key indicator."},
{id:884,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"hard",question:"A hotel booking form with check-in (today+), check-out (after check-in), and adults (1-6) has at least how many invalid partitions total?",options:["A. 3","B. 5","C. 6+","D. 2"],answer:2,explanation:"Each field has multiple invalid partitions: past check-in, check-out before/on check-in, 0 adults, 7+ adults = 6+ partitions."},
{id:885,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"extreme",question:"After a production failure from a known medium-risk defect, the test manager should:",options:["A. Accept blame and apologize","B. Document the incident, update risk models, improve future risk assessment","C. Argue the risk was communicated","D. Fix all remaining known defects immediately"],answer:1,explanation:"Post-incident analysis improves future risk calibration — use the failure as a learning opportunity."},
{id:886,chapter:"Test Tools",topic:"Tool Categories",difficulty:"hard",question:"Load profile simulation in performance testing means:",options:["A. Loading user profile data","B. Simulating the expected distribution of user behaviors under realistic load","C. Testing user profile features","D. Loading test data profiles"],answer:1,explanation:"Load profiles define realistic user behavior mix and transaction patterns for accurate performance simulation."},
{id:887,chapter:"Fundamentals of Testing",topic:"Testware",difficulty:"hard",question:"A test completion report differs from a progress report in that:",options:["A. They are the same document","B. Completion report closes a phase with summary; progress report provides status during testing","C. Completion is for management; progress is for testers","D. Completion is automated; progress is manual"],answer:1,explanation:"Completion reports close a phase with summary and lessons; progress reports track ongoing status."},
{id:888,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"hard",question:"Portability testing verifies an application:",options:["A. Can be physically moved","B. Can be installed and operated in different environments and platforms","C. Meets mobile requirements","D. Can be transferred between teams"],answer:1,explanation:"Portability testing verifies the software can run in different target environments."},
{id:889,chapter:"Static Testing",topic:"Review Types",difficulty:"hard",question:"Why is self-review by an author insufficient?",options:["A. It is always sufficient","B. Familiarity bias prevents the author from seeing their own errors and assumptions","C. Only managers can review","D. Reviews require at least 5 people"],answer:1,explanation:"Authors are too familiar with their work to review it objectively — independent perspective is essential."},
{id:890,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"extreme",question:"For condition (A and B) or C with MC/DC, minimum tests needed are:",options:["A. 2","B. 3","C. 4","D. 8"],answer:2,explanation:"MC/DC for 3 conditions: N+1 = 4 tests demonstrating each condition independently affects the outcome."},
{id:891,chapter:"Managing the Test Activities",topic:"Configuration Management",difficulty:"hard",question:"In continuous deployment, test data CM is MOST challenging because:",options:["A. Too much test data","B. Constant deployments require test data to stay synchronized with a constantly changing system","C. CM tools are expensive","D. CM tools do not support test data"],answer:1,explanation:"Continuous deployment creates a moving target — test data must evolve with every deployment."},
{id:892,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"extreme",question:"Developers adding telemetry before merging (observability-driven development) supports testing by:",options:["A. Replacing automated testing","B. Making failure diagnosis and system behavior understanding easier during testing and production","C. Increasing code complexity","D. Slowing development"],answer:1,explanation:"Built-in telemetry accelerates diagnosis during testing and in production."},
{id:893,chapter:"Fundamentals of Testing",topic:"Testing Principles",difficulty:"extreme",question:"Project manager skips testing to save time. Which principles does this violate?",options:["A. Only pesticide paradox","B. Early testing saves time + testing shows presence of defects + absence-of-errors fallacy","C. Only exhaustive testing is impossible","D. Only defects cluster together"],answer:1,explanation:"Skipping testing violates: early testing saves money, you cannot detect defects without testing, and user reports do not ensure fitness for purpose."},
{id:894,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"extreme",question:"For 10M users at peak load on a payment system, which test is MOST appropriate?",options:["A. Unit testing of payment functions","B. Load testing simulating peak transaction volumes","C. Exploratory testing of payment flows","D. Contract testing of payment APIs"],answer:1,explanation:"Load testing simulates peak transaction volumes to verify the payment system handles the expected user base."},
{id:895,chapter:"Static Testing",topic:"Feedback and Review Process",difficulty:"extreme",question:"Why does early static testing have higher ROI than dynamic testing for the same defect?",options:["A. Static testing is cheaper to run","B. Early defects have not propagated to code — fixing them costs exponentially less","C. Dynamic testing finds more defects","D. Static testing requires no tools"],answer:1,explanation:"Early defects haven't cascaded through code — fixing in requirements costs orders of magnitude less than in production."},
{id:896,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"extreme",question:"For a file upload field (max 10MB, PDF/DOCX only), comprehensive EP+BVA coverage requires:",options:["A. 10MB only","B. Boundary values (9.99MB, 10MB, 10.01MB) plus valid and invalid format partitions","C. 1MB, 5MB, 10MB only","D. Maximum size testing only"],answer:1,explanation:"Full coverage requires BVA on size boundaries AND EP for each valid/invalid file format."},
{id:897,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"extreme",question:"For a system with 500 user stories, the MOST appropriate scope definition approach is:",options:["A. List all 500 stories individually in the plan","B. Define scope at feature/epic level with per-sprint refinement","C. Include only top 50 stories","D. Defer scope definition until all stories are done"],answer:1,explanation:"Large backlogs require feature/epic-level scope with iterative per-sprint refinement — agile test planning."},
{id:898,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"extreme",question:"A tester claims 100% automated pass rate means software is release-ready. Test manager should:",options:["A. Agree - 100% pass rate is the standard","B. Challenge it: 100% pass does not prove quality — coverage, assertion quality, and missed scenarios matter","C. Immediately approve release","D. Add more tests until something fails"],answer:1,explanation:"Pass rates alone do not indicate quality — coverage gaps and weak assertions produce 100% pass on defective software."},
{id:899,chapter:"Fundamentals of Testing",topic:"Test Activities",difficulty:"extreme",question:"A major incident in a module with 95% coverage. Most likely root cause:",options:["A. 95% coverage is insufficient — need 100%","B. Defect was in the 5% uncovered code, or tests covering it had weak assertions","C. Coverage is an unreliable metric","D. Environmental issue"],answer:1,explanation:"Either the defect was in uncovered code, or tests executed the defective code without properly asserting correctness."},
{id:900,chapter:"Testing Throughout the SDLC",topic:"Testing in SDLC",difficulty:"extreme",question:"Transitioning from waterfall to SAFe — the MOST significant testing change is:",options:["A. Writing less documentation","B. Moving from phase-gate testing to continuous testing integrated into each PI and sprint","C. Reducing tester headcount","D. Eliminating performance testing"],answer:1,explanation:"SAFe requires testing integrated into every PI and sprint — a fundamental shift from waterfall phase-gate testing."},
{id:901,chapter:"Fundamentals of Testing",topic:"Why Testing is Necessary",difficulty:"medium",question:"The V&V (Verification and Validation) model requires:",options:["A. Only verification since validation is done by users","B. Both verification (are we building it right?) and validation (are we building the right thing?)","C. Only validation since requirements drive the system","D. Sequential verification then validation at the end"],answer:1,explanation:"V&V requires both: verification checks conformance to specifications; validation checks fitness for actual user needs."},
{id:902,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"medium",question:"Internationalization (i18n) testing verifies:",options:["A. That the software translates text correctly","B. That the software can be adapted for different languages and regions without code changes","C. Internet connectivity of the application","D. That the software works internationally"],answer:1,explanation:"i18n testing verifies the software is designed for adaptation to different locales without requiring code changes."},
{id:903,chapter:"Static Testing",topic:"Feedback and Review Process",difficulty:"medium",question:"The author's role AFTER a review meeting is to:",options:["A. Defend the original work product","B. Address the identified issues and make required changes","C. Schedule the next review meeting","D. Update the review metrics"],answer:1,explanation:"After the review, the author is responsible for addressing and fixing the identified issues."},
{id:904,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"Which of the following is an INVALID equivalence partition for a field accepting only positive integers?",options:["A. The integer 500","B. The integer 1","C. The value -5","D. The integer 10000"],answer:2,explanation:"-5 is a negative integer — it belongs to the invalid partition for a positive-integers-only field."},
{id:905,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"medium",question:"Which testing approach is MOST appropriate when requirements are unknown and change frequently?",options:["A. Scripted testing with a fixed test plan","B. Adaptive testing with exploratory sessions and flexible prioritization","C. Formal inspections of all requirements","D. Full regression testing on every change"],answer:1,explanation:"When requirements are unstable, adaptive testing with exploratory sessions provides the most flexibility."},
{id:906,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"medium",question:"Which of the following is MOST true about test automation in regression testing?",options:["A. Manual regression is more reliable than automated","B. Automated regression provides faster, more consistent execution for stable test scenarios","C. Automation always achieves better coverage than manual","D. Regression testing cannot be automated"],answer:1,explanation:"Automated regression is faster and more consistent for stable scenarios — a key benefit over manual regression."},
{id:907,chapter:"Fundamentals of Testing",topic:"Testing Principles",difficulty:"medium",question:"The principle 'testing shows presence of defects, not their absence' is important because:",options:["A. It limits the tester's responsibility","B. It sets realistic stakeholder expectations — passing tests reduce risk but don't guarantee defect-free software","C. It justifies reducing test effort","D. It means testing is not necessary"],answer:1,explanation:"Setting realistic expectations: passing tests reduce risk and increase confidence, but cannot guarantee zero defects."},
{id:908,chapter:"Testing Throughout the SDLC",topic:"Test Levels",difficulty:"medium",question:"Integration testing at the system level (System Integration Testing) verifies:",options:["A. Individual functions within a module","B. That the complete system integrates correctly with external systems and interfaces","C. That each class in the codebase works correctly","D. User acceptance criteria"],answer:1,explanation:"System Integration Testing verifies the complete system interfaces correctly with external systems."},
{id:909,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"easy",question:"Which of the following BEST describes 'peer review'?",options:["A. A review performed by external auditors","B. A review of a work product by colleagues at a similar level","C. A formal inspection with defined roles","D. A self-review by the author"],answer:1,explanation:"Peer reviews involve colleagues at similar levels reviewing each other's work — an informal review type."},
{id:910,chapter:"Test Analysis and Design",topic:"Experience-based Techniques",difficulty:"medium",question:"A tester with 10 years in financial software testing is MORE likely to find defects than a junior tester because:",options:["A. They are older","B. Their domain knowledge guides them to high-risk, error-prone areas","C. They test faster","D. They automate everything"],answer:1,explanation:"Domain experience guides experienced testers to areas most likely to have defects based on past patterns."},
{id:911,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"medium",question:"Which of the following BEST describes 'defect leakage'?",options:["A. Defects found during testing","B. Defects that escape from one test phase to be found in a later phase or production","C. Confidential defect information being shared","D. Defects that are removed without being fixed"],answer:1,explanation:"Defect leakage measures defects not caught in testing but found later — a quality efficiency metric."},
{id:912,chapter:"Test Tools",topic:"CI/CD",difficulty:"medium",question:"A 'deployment frequency' metric in DevOps measures:",options:["A. How often tests are run","B. How often code changes are released to production","C. How many developers are deploying code","D. How many environments are available"],answer:1,explanation:"Deployment frequency (DORA metric) measures how often the team deploys to production — a key DevOps metric."},
{id:913,chapter:"Fundamentals of Testing",topic:"Test Activities",difficulty:"easy",question:"Which of the following is a testware item produced during test DESIGN?",options:["A. Test plan","B. Test cases and test procedures","C. Test execution log","D. Test completion report"],answer:1,explanation:"Test cases and procedures are designed and produced during the test design activity."},
{id:914,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"easy",question:"Usability testing evaluates:",options:["A. Whether the software meets requirements","B. How easy and pleasant the software is to use","C. Whether the software performs adequately","D. Whether the software is secure"],answer:1,explanation:"Usability testing evaluates how easy, efficient, and satisfying the software is to use."},
{id:915,chapter:"Static Testing",topic:"Review Types",difficulty:"easy",question:"In a WALKTHROUGH, who presents the work product?",options:["A. The moderator","B. The author","C. A senior reviewer","D. An external auditor"],answer:1,explanation:"In a walkthrough, the author presents their work product to the reviewers."},
{id:916,chapter:"Test Analysis and Design",topic:"Test Conditions",difficulty:"easy",question:"Which of the following BEST describes 'test coverage'?",options:["A. The number of tests in the suite","B. The degree to which test coverage items have been exercised by tests","C. The budget spent on testing","D. The time available for testing"],answer:1,explanation:"Test coverage measures how many defined coverage items (requirements, branches, states) have been tested."},
{id:917,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"easy",question:"The PRIMARY purpose of test progress reporting is:",options:["A. To document defects found","B. To communicate test status, progress, and risks to stakeholders","C. To generate test cases","D. To approve software release"],answer:1,explanation:"Test progress reports keep stakeholders informed of testing status, risks, and activities."},
{id:918,chapter:"Test Tools",topic:"Tool Categories",difficulty:"easy",question:"A unit testing framework is PRIMARILY used to:",options:["A. Test user interfaces","B. Write and run tests for individual code components","C. Manage test cases","D. Generate performance reports"],answer:1,explanation:"Unit testing frameworks support writing and running tests at the individual component/function level."},
{id:919,chapter:"Fundamentals of Testing",topic:"Why Testing is Necessary",difficulty:"medium",question:"Why is early detection of defects important from a cost perspective?",options:["A. Testing tools are more expensive later in the project","B. The cost to fix defects generally increases significantly the later they are found","C. Testers charge more in later phases","D. There are always more defects in later phases"],answer:1,explanation:"Defect fix cost escalates exponentially from requirements (cheapest) through to production (most expensive)."},
{id:920,chapter:"Testing Throughout the SDLC",topic:"Maintenance Testing",difficulty:"medium",question:"Impact analysis before regression testing helps by:",options:["A. Eliminating the need for regression","B. Identifying what is affected by changes, guiding which regression tests to prioritize","C. Finding new defects","D. Replacing the test plan"],answer:1,explanation:"Impact analysis identifies change scope, enabling targeted, efficient regression testing rather than full re-testing."},
{id:921,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"medium",question:"Which of the following is a benefit of automated static analysis in DevOps?",options:["A. Automatic defect fixing","B. Fast, automated code quality feedback on every commit without manual review time","C. Replacing all code reviews","D. Eliminating false positives"],answer:1,explanation:"Automated static analysis in DevOps provides immediate code quality feedback on every commit."},
{id:922,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"For an email field, which input belongs to the VALID equivalence partition?",options:["A. An email without @","B. An email with multiple @ symbols","C. user@example.com","D. An empty string"],answer:2,explanation:"user@example.com is a valid email format — part of the valid equivalence partition."},
{id:923,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"medium",question:"A risk with HIGH impact and LOW probability should receive:",options:["A. No testing","B. Some testing proportional to impact","C. Same testing as high probability/low impact","D. Only exploratory testing"],answer:1,explanation:"High-impact risks need coverage even at low probability — catastrophic outcomes justify testing investment."},
{id:924,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"medium",question:"Test automation is MOST beneficial for:",options:["A. One-time manual testing activities","B. Repetitive tests executed frequently in regression cycles","C. Exploratory testing sessions","D. Single user acceptance tests"],answer:1,explanation:"Automation ROI grows with repetition frequency — regression tests run repeatedly benefit most from automation."},
{id:925,chapter:"Fundamentals of Testing",topic:"Testware",difficulty:"medium",question:"Which of the following is a characteristic of GOOD test data?",options:["A. Uses only real production data","B. Covers both valid inputs and boundary/invalid cases relevant to the test conditions","C. Is minimal to reduce storage costs","D. Is always randomly generated"],answer:1,explanation:"Good test data covers valid, boundary, and invalid cases — providing comprehensive coverage of test conditions."},
{id:926,chapter:"Testing Throughout the SDLC",topic:"Test Levels",difficulty:"medium",question:"Which test level has the NARROWEST scope?",options:["A. System testing","B. Acceptance testing","C. Unit testing","D. Integration testing"],answer:2,explanation:"Unit (component) testing has the narrowest scope — testing individual components in isolation."},
{id:927,chapter:"Static Testing",topic:"Feedback and Review Process",difficulty:"medium",question:"Why should reviewers prepare individually BEFORE the review meeting?",options:["A. To finish the review faster","B. To identify issues independently without group bias influencing their findings","C. To reduce the meeting time","D. Because the moderator requires it"],answer:1,explanation:"Independent preparation ensures unbiased findings — group dynamics can suppress individual observations."},
{id:928,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"medium",question:"A 'branch' in white-box testing refers to:",options:["A. A module of the software","B. A possible outcome (true/false) of a decision point in the code","C. A version of the code in source control","D. A test execution path"],answer:1,explanation:"A branch is either the true or false outcome of a decision statement (if/else, switch)."},
{id:929,chapter:"Managing the Test Activities",topic:"Configuration Management",difficulty:"medium",question:"Why should test execution results be stored with the software version they tested?",options:["A. For audit compliance only","B. To trace which tests ran against which build, enabling accurate defect investigation and regression analysis","C. To reduce storage requirements","D. To track developer productivity"],answer:1,explanation:"Linking results to specific software versions enables accurate defect tracking and regression analysis."},
{id:930,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"medium",question:"A 'test runner' in automation frameworks:",options:["A. A person who executes tests","B. A component that executes tests and reports results","C. A tool that records user actions","D. A CI server that manages builds"],answer:1,explanation:"A test runner is the component that executes test cases and generates pass/fail reports."},
{id:931,chapter:"Fundamentals of Testing",topic:"Testing Principles",difficulty:"hard",question:"A tester argues that since they found zero defects in a release, the software must be defect-free. Which principle refutes this?",options:["A. Defects cluster together","B. Testing shows presence of defects, not their absence","C. Pesticide paradox","D. Exhaustive testing is impossible"],answer:1,explanation:"Zero defects found does not mean zero defects exist — testing can only prove presence, not absence."},
{id:932,chapter:"Testing Throughout the SDLC",topic:"Testing in SDLC",difficulty:"hard",question:"A 'definition of done' at the sprint level typically includes:",options:["A. Only unit tests passing","B. Code complete, unit tested, code reviewed, integration tested, acceptance criteria met","C. Product owner approval only","D. Performance tests only"],answer:1,explanation:"A robust DoD includes code completion, all test levels passing, reviews, and acceptance criteria being met."},
{id:933,chapter:"Static Testing",topic:"Review Types",difficulty:"hard",question:"What is the MAIN advantage of inspection over walkthrough?",options:["A. Inspections are faster","B. Inspections are more rigorous with metrics, defined roles, and entry/exit criteria","C. Walkthroughs require more preparation","D. Inspections are less formal"],answer:1,explanation:"Inspections are more rigorous — with defined roles, mandatory preparation, metrics, and formal exit criteria."},
{id:934,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"hard",question:"A shopping system applies loyalty discounts. Conditions: is_member (Y/N) and purchase_over_100 (Y/N). Action: 10% off if member, 5% off if over 100, 15% off if both. The decision table has:",options:["A. 2 rules","B. 4 rules","C. 6 rules","D. 8 rules"],answer:1,explanation:"2 binary conditions = 2^2 = 4 rules: NN, NY, YN, YY."},
{id:935,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"hard",question:"In a test plan, the 'test approach' section should describe:",options:["A. Who is on the test team","B. The techniques, tools, levels, and methods to be used for testing this project","C. The testing schedule","D. The defect severity classifications"],answer:1,explanation:"The test approach describes how testing will be conducted: techniques, tools, levels, and methods."},
{id:936,chapter:"Test Tools",topic:"CI/CD",difficulty:"hard",question:"Why is test parallelization important in CI/CD?",options:["A. It reduces the number of tests needed","B. It reduces total pipeline execution time, providing faster feedback without sacrificing coverage","C. It ensures tests run in the correct order","D. It eliminates flaky tests"],answer:1,explanation:"Parallelization reduces wall-clock time for CI feedback without reducing test coverage."},
{id:937,chapter:"Fundamentals of Testing",topic:"Essential Skills",difficulty:"hard",question:"A tester who constantly advocates for quality improvements and challenges the status quo is demonstrating:",options:["A. Insubordination","B. Quality mindset — a key professional attribute for testers","C. Scope creep","D. Over-engineering"],answer:1,explanation:"A quality mindset drives continuous improvement and is a key professional attribute for effective testers."},
{id:938,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"hard",question:"Interoperability testing verifies:",options:["A. System performance under load","B. The system exchanges data and operates correctly with other systems","C. Internal code structure correctness","D. User satisfaction levels"],answer:1,explanation:"Interoperability testing verifies correct data exchange and interaction with other systems."},
{id:939,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"hard",question:"A DAST tool scans a running web application. What is a LIMITATION of this approach?",options:["A. It requires source code","B. It may miss vulnerabilities not exposed through the application's external interface","C. It runs too slowly","D. It only works for mobile applications"],answer:1,explanation:"DAST only sees what's exposed externally — vulnerabilities in internal components may not be detected."},
{id:940,chapter:"Test Analysis and Design",topic:"Test Conditions",difficulty:"hard",question:"A test condition for a financial system: 'Verify interest calculation is correct for all loan types.' This is a:",options:["A. Test case","B. High-level test condition requiring multiple test cases to fully verify","C. Test procedure","D. Acceptance criterion"],answer:1,explanation:"A high-level test condition like this requires multiple test cases (each loan type, boundary values) to fully cover it."},
{id:941,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"hard",question:"'Defect clustering' in practice means a test manager should:",options:["A. Spread test effort equally across all modules","B. Focus more testing resources on historically defect-prone modules","C. Ignore low-defect modules entirely","D. Automate all testing in defect-prone areas"],answer:1,explanation:"Defect clustering guides resource allocation — historically defect-prone modules deserve more testing."},
{id:942,chapter:"Test Tools",topic:"Tool Categories",difficulty:"hard",question:"Service virtualization vs. mocking — the key difference is:",options:["A. They are identical","B. Service virtualization simulates complex, stateful external services; mocking typically simulates simple, stateless dependencies","C. Mocking simulates all service behaviors; virtualization only simulates APIs","D. Service virtualization is for databases only"],answer:1,explanation:"Service virtualization handles complex, stateful services (mainframes, complex APIs); mocking handles simpler dependencies."},
{id:943,chapter:"Fundamentals of Testing",topic:"Testing Objectives",difficulty:"extreme",question:"A test team achieves 100% requirements coverage. This guarantees:",options:["A. All defects are found","B. Nothing — coverage means tests exist for each requirement, not that the tests are thorough or correct","C. The software is ready for release","D. No more testing is needed"],answer:1,explanation:"Coverage only confirms tests exist for each item — it does not guarantee the tests are thorough or correct."},
{id:944,chapter:"Testing Throughout the SDLC",topic:"Test Levels",difficulty:"extreme",question:"In a cloud-native system, contract testing between microservices prevents:",options:["A. Performance degradation","B. Breaking changes where a provider change breaks a consumer without either team knowing","C. Security vulnerabilities","D. Database errors"],answer:1,explanation:"Contract testing prevents silent breaking changes — when provider changes break consumers without coordinated awareness."},
{id:945,chapter:"Static Testing",topic:"Review Types",difficulty:"extreme",question:"A team implements automated pull request reviews using AI. This BEST supplements:",options:["A. Formal inspection (replaces it)","B. Informal code review (complements it with automated checks)","C. User acceptance testing","D. Dynamic testing"],answer:1,explanation:"AI-assisted PR reviews augment informal code reviews — automated checks complement human judgment."},
{id:946,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"extreme",question:"A system accepts 4-digit PIN codes. How many valid equivalence partitions and boundary values (2-value BVA) exist?",options:["A. 1 valid partition, 2 boundary values","B. 1 valid partition (0000-9999), invalid (non-numeric, <4 digits, >4 digits), BVA: 0000, 9999","C. 4 valid partitions, 8 boundary values","D. 2 valid partitions, 4 boundary values"],answer:1,explanation:"PINs: valid (0000-9999), invalid non-numeric, too short, too long; BVA: 0000 (lower), 9999 (upper)."},
{id:947,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"extreme",question:"A test plan for a Continuously Deployed product should address:",options:["A. Phase-by-phase testing stages","B. Continuous testing strategy, quality gates, production monitoring, and rollback criteria","C. Only automated testing","D. Testing only before major releases"],answer:1,explanation:"Continuous deployment requires: continuous testing, quality gates at each stage, production monitoring, and rollback procedures."},
{id:948,chapter:"Test Tools",topic:"CI/CD",difficulty:"extreme",question:"A team implements 'progressive delivery' with feature flags. In testing, feature flags enable:",options:["A. Eliminating test environments","B. Testing new features in production for a limited user group while keeping the feature off for others","C. Replacing automated tests","D. Automating test data creation"],answer:1,explanation:"Feature flags enable dark launches — new code in production, only visible to selected users for testing."},
{id:949,chapter:"Fundamentals of Testing",topic:"Why Testing is Necessary",difficulty:"extreme",question:"A 60 million dollar spacecraft is lost because a unit conversion error (metric/imperial) was not detected in testing. This MOST powerfully illustrates:",options:["A. Pesticide paradox","B. The catastrophic consequences of inadequate testing — defects can cause massive harm","C. Defects cluster together","D. Exhaustive testing is impossible"],answer:1,explanation:"The Mars Climate Orbiter failure illustrates the real-world consequences of undetected software defects."},
{id:950,chapter:"Testing Throughout the SDLC",topic:"Testing in SDLC",difficulty:"extreme",question:"In a DevSecOps pipeline, the MOST comprehensive security posture uses:",options:["A. Only SAST","B. SAST + DAST + SCA (software composition analysis) + IAST + security-focused code review","C. Only penetration testing","D. Only DAST"],answer:1,explanation:"Comprehensive DevSecOps security uses multiple complementary tools: SAST (code), DAST (runtime), SCA (dependencies), IAST (instrumented)."},
{id:951,chapter:"Static Testing",topic:"Review Types",difficulty:"extreme",question:"A team conducting a review discovers 90% of defects are in 10% of the requirements. This BEST applies which principle to future reviews?",options:["A. Pesticide paradox — change the review approach","B. Defect clustering — focus future reviews more intensively on similar types of requirements","C. Early testing — review earlier","D. Context-dependent testing"],answer:1,explanation:"Defect clustering informs review focus — requirements types with historically high defect density deserve extra scrutiny."},
{id:952,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"extreme",question:"A function has a loop from 1 to N and an exit condition. For complete loop boundary testing, test values include:",options:["A. N only","B. 0, 1, 2, N-1, N","C. 1 and N only","D. Random values within range"],answer:1,explanation:"Loop boundary testing: 0 iterations (skip), 1 (once), 2 (twice), N-1 (near max), N (max) for complete boundary coverage."},
{id:953,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"extreme",question:"A distributed global test team requires which additional planning considerations?",options:["A. No special considerations","B. Time zone coordination, communication protocols, cultural differences, and tool standardization","C. Only automated testing","D. Each region tests independently with no coordination"],answer:1,explanation:"Global teams need: time zone coordination, shared communication protocols, cultural awareness, and unified tooling."},
{id:954,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"extreme",question:"What is 'shift-left security testing' in practice?",options:["A. Moving penetration testing earlier in the sprint","B. Integrating SAST, dependency scanning, and security code reviews into the development workflow before deployment","C. Having security testers join development sprints","D. Only testing security features early"],answer:1,explanation:"Shift-left security integrates SAST, SCA, and security reviews into the development workflow — finding issues before deployment."},
{id:955,chapter:"Fundamentals of Testing",topic:"Testing Principles",difficulty:"medium",question:"Which principle would you cite to justify NOT testing every field in a 100-field form with all possible values?",options:["A. Defects cluster together","B. Exhaustive testing is impossible","C. Testing is context-dependent","D. Pesticide paradox"],answer:1,explanation:"Exhaustive testing is impossible — the combination of 100 fields with all possible values is astronomically large."},
{id:956,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"medium",question:"Load testing, stress testing, and volume testing are all types of:",options:["A. Functional testing","B. Performance testing","C. Security testing","D. Acceptance testing"],answer:1,explanation:"Load, stress, and volume tests are all performance testing subtypes — testing different aspects of system performance."},
{id:957,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"medium",question:"Code that will never be executed because a return statement precedes it is called:",options:["A. Commented code","B. Dead code","C. Error-handling code","D. Unreachable code"],answer:1,explanation:"Dead code / unreachable code is code that can never be executed — typically detectable through static analysis."},
{id:958,chapter:"Test Analysis and Design",topic:"Experience-based Techniques",difficulty:"medium",question:"A test charter for exploratory testing should include:",options:["A. Exact test steps to follow","B. The mission, scope, and any focus areas or risks to investigate","C. A complete list of expected results","D. Code coverage targets"],answer:1,explanation:"A charter defines the exploration mission and focus areas — providing direction without over-scripting."},
{id:959,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"medium",question:"Which defect status indicates no defect was found after investigation?",options:["A. Closed","B. Fixed","C. Not a Bug / Invalid / Rejected","D. Deferred"],answer:2,explanation:"'Not a Bug' / Invalid / Rejected statuses indicate the reported issue is not a defect after investigation."},
{id:960,chapter:"Test Tools",topic:"Tool Categories",difficulty:"medium",question:"Which of the following is an example of an IAST (Interactive Application Security Testing) tool?",options:["A. SonarQube","B. Contrast Security","C. OWASP ZAP","D. Checkmarx"],answer:1,explanation:"Contrast Security is an IAST tool — it instruments the running application to detect vulnerabilities from within."},
{id:961,chapter:"Fundamentals of Testing",topic:"Test Roles",difficulty:"medium",question:"In Agile, a 'quality coach' role MOST likely performs:",options:["A. Writing all test cases for the team","B. Mentoring the team on testing practices and fostering a quality mindset","C. Managing the defect backlog","D. Approving all user stories"],answer:1,explanation:"A quality coach mentors the team on testing practices and helps build a quality culture."},
{id:962,chapter:"Testing Throughout the SDLC",topic:"Test Levels",difficulty:"easy",question:"Which test level is MOST closely associated with testing user stories in Agile?",options:["A. Unit testing","B. Integration testing","C. Acceptance testing","D. System testing"],answer:2,explanation:"User stories are verified through acceptance testing against their acceptance criteria."},
{id:963,chapter:"Static Testing",topic:"Review Types",difficulty:"easy",question:"The MOST formal type of review is:",options:["A. Walkthrough","B. Informal review","C. Technical review","D. Inspection"],answer:3,explanation:"Inspection is the most formal review type — with defined roles, mandatory preparation, metrics, and formal exit criteria."},
{id:964,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"easy",question:"In state transition testing, what connects two states?",options:["A. A guard condition","B. A transition triggered by an event","C. A test case","D. An equivalence partition"],answer:1,explanation:"A transition is the movement from one state to another, triggered by an event or stimulus."},
{id:965,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"easy",question:"Which of the following is a key component of a test plan?",options:["A. Source code modules","B. Test scope and objectives","C. Development architecture","D. Marketing materials"],answer:1,explanation:"Test scope and objectives are core test plan components defining what and why we are testing."},
{id:966,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"easy",question:"Which tool category helps manage large volumes of test cases?",options:["A. Load testing tools","B. Test management tools","C. Static analysis tools","D. Unit testing frameworks"],answer:1,explanation:"Test management tools (Jira, TestRail, Azure Test Plans) manage test cases, execution, and reporting."},
{id:967,chapter:"Fundamentals of Testing",topic:"Why Testing is Necessary",difficulty:"easy",question:"Which of the following is a PRIMARY reason organizations invest in software testing?",options:["A. To give testers employment","B. To reduce the risk of software failures causing harm or loss","C. To slow down development","D. To meet ISO 9001 requirements exclusively"],answer:1,explanation:"Organizations test to reduce the risk of production failures that can cause financial loss, legal issues, or harm."},
{id:968,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"easy",question:"A test verifies the system produces correct results for given inputs. This is:",options:["A. Non-functional testing","B. Functional testing","C. White-box testing","D. Static testing"],answer:1,explanation:"Functional testing verifies the system produces correct outputs for defined inputs — testing what it does."},
{id:969,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"easy",question:"Which of the following is tested using STATIC methods?",options:["A. System response time","B. A requirements document for ambiguities","C. Database query performance","D. User interface navigation"],answer:1,explanation:"Static testing reviews documents like requirements for ambiguities, completeness, and correctness."},
{id:970,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"easy",question:"The purpose of decision table testing is to:",options:["A. Test performance under load","B. Systematically test combinations of conditions and their resulting actions","C. Test individual input boundaries","D. Test code paths through the system"],answer:1,explanation:"Decision tables systematically cover all combinations of conditions and their corresponding system actions."},
{id:971,chapter:"Managing the Test Activities",topic:"Defect Management",difficulty:"easy",question:"A bug report should ALWAYS include:",options:["A. The tester's personal opinion of the code quality","B. Steps to reproduce, expected result, and actual result","C. Suggestions for how to fix the code","D. The developer's name"],answer:1,explanation:"Minimum required bug report content: reproducible steps, expected result, and actual (observed) result."},
{id:972,chapter:"Test Tools",topic:"Benefits and Risks of Tools",difficulty:"easy",question:"Test automation CANNOT replace which type of testing?",options:["A. Regression testing","B. Load testing","C. Human-based exploratory testing","D. API testing"],answer:2,explanation:"Exploratory testing requires human creativity, intuition, and learning — automation cannot replicate these qualities."},
{id:973,chapter:"Fundamentals of Testing",topic:"Testing Principles",difficulty:"easy",question:"How many testing principles are in the ISTQB Foundation Level v4.0 syllabus?",options:["A. 5","B. 6","C. 7","D. 8"],answer:2,explanation:"ISTQB Foundation Level defines 7 testing principles."},
{id:974,chapter:"Testing Throughout the SDLC",topic:"Test Levels",difficulty:"easy",question:"Acceptance testing is PRIMARILY performed by:",options:["A. Developers","B. Test managers","C. Users or customer representatives","D. Automated tools"],answer:2,explanation:"Acceptance testing is performed by users or customer representatives to validate business needs."},
{id:975,chapter:"Static Testing",topic:"Feedback and Review Process",difficulty:"easy",question:"What is the PRIMARY output of a review meeting?",options:["A. Fixed work products","B. A list of identified issues, defects, and action items","C. Approved work products","D. Updated test plans"],answer:1,explanation:"Review meetings produce a list of identified issues and action items for the author to address."},
{id:976,chapter:"Test Analysis and Design",topic:"White-box Techniques",difficulty:"easy",question:"Statement coverage measures what percentage of:",options:["A. Requirements tested","B. Executable statements executed by tests","C. Branches covered","D. Test cases that passed"],answer:1,explanation:"Statement coverage = percentage of executable code statements that were executed during testing."},
{id:977,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"easy",question:"A test manager reports that 80% of planned tests have been executed. This is an example of:",options:["A. Defect density metric","B. Test execution progress metric","C. Code coverage metric","D. Risk assessment metric"],answer:1,explanation:"Test execution progress (% of planned tests executed) is a basic test monitoring metric."},
{id:978,chapter:"Test Tools",topic:"CI/CD",difficulty:"easy",question:"What is the primary goal of a CI system?",options:["A. To deploy software to production automatically","B. To automatically build and test code changes to detect integration issues early","C. To manage software releases","D. To monitor production systems"],answer:1,explanation:"CI automatically builds and tests code changes, detecting integration issues as early as possible."},
{id:979,chapter:"Fundamentals of Testing",topic:"Test Activities",difficulty:"easy",question:"Which activity involves identifying defects in work products without executing code?",options:["A. Dynamic testing","B. Test execution","C. Static testing","D. Regression testing"],answer:2,explanation:"Static testing finds defects by examining work products without executing the software."},
{id:980,chapter:"Testing Throughout the SDLC",topic:"Testing in SDLC",difficulty:"easy",question:"TDD stands for:",options:["A. Test Driven Development","B. Test Data Design","C. Technical Design Document","D. Test Deployment Delivery"],answer:0,explanation:"TDD = Test-Driven Development — writing tests before production code."},
{id:981,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"easy",question:"Which of the following is a static testing activity?",options:["A. Running automated unit tests","B. Reviewing a test plan document","C. Executing system tests","D. Performance load testing"],answer:1,explanation:"Reviewing a test plan (or any document) is a static testing activity — no code execution involved."},
{id:982,chapter:"Test Analysis and Design",topic:"Experience-based Techniques",difficulty:"easy",question:"Which technique is based on the tester's experience and knowledge?",options:["A. Boundary value analysis","B. Equivalence partitioning","C. Error guessing","D. Decision table testing"],answer:2,explanation:"Error guessing relies on the tester's experience to predict where defects are likely to occur."},
{id:983,chapter:"Managing the Test Activities",topic:"Test Planning",difficulty:"easy",question:"Who is responsible for creating the test plan?",options:["A. Developer","B. Test Manager","C. Product Owner","D. Business Analyst"],answer:1,explanation:"The Test Manager is primarily responsible for creating and maintaining the test plan."},
{id:984,chapter:"Test Tools",topic:"Tool Categories",difficulty:"easy",question:"A tool that records a developer's actions when debugging and replays them is a type of:",options:["A. Performance testing tool","B. Test management tool","C. Debugging support tool","D. Static analysis tool"],answer:2,explanation:"Debugging tools record and replay developer actions to help diagnose and fix defects."},
{id:985,chapter:"Fundamentals of Testing",topic:"Test Roles",difficulty:"easy",question:"Which of the following is a TESTER's PRIMARY responsibility?",options:["A. Writing production code","B. Designing and executing tests to find defects","C. Managing the project schedule","D. Reviewing requirements only"],answer:1,explanation:"A tester's primary responsibility is designing and executing tests to find defects and verify quality."},
{id:986,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"medium",question:"Regression testing is MOST important after which event?",options:["A. Initial system deployment","B. Any change to the system — bug fixes, new features, or configuration changes","C. User acceptance testing completion","D. Security testing failure"],answer:1,explanation:"Regression testing is triggered by ANY change — to ensure changes haven't broken existing functionality."},
{id:987,chapter:"Static Testing",topic:"Review Types",difficulty:"medium",question:"In a TECHNICAL REVIEW, the focus is on:",options:["A. Process adherence and metrics","B. Evaluating technical content for correctness and suitability","C. Training new team members","D. Author's presentation skills"],answer:1,explanation:"Technical reviews evaluate technical content correctness — suitability of design, architecture, or code."},
{id:988,chapter:"Test Analysis and Design",topic:"Test Conditions",difficulty:"medium",question:"Test conditions derived from requirements should be:",options:["A. One per requirement regardless of complexity","B. As many as needed to fully verify the requirement from multiple angles","C. Only for high-priority requirements","D. Only for functional requirements"],answer:1,explanation:"Multiple test conditions may be needed per requirement to ensure comprehensive verification."},
{id:989,chapter:"Managing the Test Activities",topic:"Risk-based Testing",difficulty:"medium",question:"Risk assessment considers which two factors?",options:["A. Test team size and budget","B. Likelihood of failure and impact of failure","C. Number of requirements and code complexity","D. Test environment cost and schedule"],answer:1,explanation:"Risk = Likelihood (probability) x Impact — both factors determine the risk level and testing priority."},
{id:990,chapter:"Test Tools",topic:"Tool Support for Testing",difficulty:"medium",question:"What is the purpose of a 'test data factory' in automation?",options:["A. Physical hardware for test data storage","B. A component that creates test data programmatically for use in automated tests","C. A database containing all test data","D. A tool for anonymizing production data"],answer:1,explanation:"A test data factory programmatically generates the required test data for automated test cases."},
{id:991,chapter:"Fundamentals of Testing",topic:"Testing Objectives",difficulty:"medium",question:"'Preventing defects' as a testing objective is achieved MOST through:",options:["A. Finding more defects during system testing","B. Early reviews, TDD, and feedback loops that prevent defects from being introduced","C. Running more automated tests","D. Increasing testing frequency"],answer:1,explanation:"Defect prevention occurs through early feedback mechanisms — reviews, TDD, and process improvements."},
{id:992,chapter:"Testing Throughout the SDLC",topic:"Test Types",difficulty:"medium",question:"A test checking that a system correctly handles database transactions when multiple users submit simultaneously is MOST closely:",options:["A. Functional testing","B. Concurrency/performance testing","C. Static testing","D. Acceptance testing"],answer:1,explanation:"Multi-user concurrent transactions test concurrency behavior — a non-functional (performance) concern."},
{id:993,chapter:"Static Testing",topic:"Static Testing Basics",difficulty:"medium",question:"Which of the following is detected by BOTH static analysis tools AND code reviews?",options:["A. Business logic errors","B. Coding standard violations","C. Performance bottlenecks","D. User experience issues"],answer:1,explanation:"Both automated static analysis and manual code reviews can detect coding standard violations."},
{id:994,chapter:"Test Analysis and Design",topic:"Black-box Techniques",difficulty:"medium",question:"For a range field accepting 1-100, using equivalence partitioning creates partitions:",options:["A. One valid partition only","B. Valid (1-100) and two invalid partitions (below 1, above 100)","C. Three invalid partitions only","D. One partition for every 10 values"],answer:1,explanation:"EP creates: valid (1-100), invalid low (<1), and invalid high (>100) — three partitions total."},
{id:995,chapter:"Managing the Test Activities",topic:"Test Monitoring",difficulty:"medium",question:"Which metric tracks testing efficiency rather than just quantity?",options:["A. Number of test cases executed","B. Defects found per test hour","C. Total number of tests written","D. Test execution rate"],answer:1,explanation:"Defects found per test hour measures testing efficiency — value delivered per unit of testing effort."},
{id:996,chapter:"Test Tools",topic:"CI/CD",difficulty:"medium",question:"In DevOps, 'observability' is MOST relevant to which testing approach?",options:["A. Unit testing","B. Static analysis","C. Shift-right testing and production monitoring","D. Acceptance testing"],answer:2,explanation:"Observability (logs, metrics, traces) enables shift-right testing and production issue detection."},
{id:997,chapter:"Fundamentals of Testing",topic:"Why Testing is Necessary",difficulty:"hard",question:"The consequences of software failures can include:",options:["A. Only financial losses","B. Financial loss, reputational damage, injury, death, and environmental harm","C. Only user dissatisfaction","D. Only project schedule delays"],answer:1,explanation:"Software failures have consequences ranging from financial loss to safety-critical outcomes including death."},
{id:998,chapter:"Testing Throughout the SDLC",topic:"Testing in SDLC",difficulty:"hard",question:"In DevOps, the concept of 'you build it, you run it' implies for testing:",options:["A. Developers are solely responsible for testing","B. Teams are responsible for quality end-to-end including production behavior","C. Testing is eliminated since developers own production","D. Operations teams replace QA teams"],answer:1,explanation:"DevOps end-to-end responsibility means teams care about quality from development through production operation."},
{id:999,chapter:"Static Testing",topic:"Review Types",difficulty:"hard",question:"When a team discovers that 60% of all project defects were found through reviews, this BEST demonstrates:",options:["A. Dynamic testing is unnecessary","B. The high value of static testing in finding defects early and cheaply","C. The team does not need testers","D. Reviews replace all other quality activities"],answer:1,explanation:"High defect detection through reviews demonstrates the exceptional ROI of static testing for early defect finding."},
{id:1000,chapter:"Test Analysis and Design",topic:"Test Conditions",difficulty:"extreme",question:"A test manager has delivered a project with 95% requirements coverage, 85% branch coverage, 5 known deferred medium-risk defects, and zero critical open defects. Stakeholders ask if the software is ready for release. The test manager's MOST appropriate response is:",options:["A. Yes — 95% coverage guarantees quality","B. Provide a transparent quality report: coverage achieved, risk profile of deferred defects, residual risks, and let stakeholders make the informed go/no-go decision","C. No — 100% coverage is required","D. Yes — zero critical defects means release is guaranteed safe"],answer:1,explanation:"The test manager's role is to provide transparent quality information; the release decision belongs to stakeholders who weigh business risk against quality evidence."}
];

